INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('absurd', '[əbˈsɜːrd]', 'http://dict.youdao.com/dictvoice?audio=absurd', '{adj.}++愚蠢的，荒谬的；滑稽可笑的；荒诞派的**{n.}++荒诞，荒诞的事物 （the absurd）**{n.}++a situation in which life seems irrational and meaningless																										        				&quot;The absurd is the essential concept and the first truth&quot;															   	同义词：								                                  				    the absurd**{adj.}++inconsistent with reason or logic or common sense																										        				&quot;the absurd predicament of seeming to argue that virtue is highly desirable but intensely unpleasant&quot;**{adj.}++荒谬的；可笑的**', '');
