INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('bearing', '[ˈberɪŋ]', 'http://dict.youdao.com/dictvoice?audio=bearing', '{n.}++举止，仪态；与……有关，对……有影响；（对坏事的）宽容，容忍；轴承，支轴；方位，方向角；（用罗盘）定向，测位；（盾形纹章面上的）图案**{v.}++写有，刻有；手持，携带；承担（bear 的现在分词形式）**{n.}++relevant relation or interconnection																										        				&quot;those issues have no bearing on our situation&quot;**{n.}++[机]轴承；关系；[矿业][测][天]方位；举止**{v.}++忍受（bear的ing形式）**', '');
