INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('blast', '[blæst]', 'http://dict.youdao.com/dictvoice?audio=blast', '{n.}++爆炸，爆破；冲击波；爆炸声，爆破声；强劲的（气或水）流，疾风；吹奏声，轰鸣；严厉的批评；狂欢，有趣的事；（球队或选手的）猛烈进攻；枪击；（公司、组织等发出的）群发电子邮件**{v.}++炸毁，爆破；轰开，炸开（通路）；向……射击，枪击；发出刺耳的高音；严厉批评，痛斥；由爆炸引起；用力踢，猛击；喷射（水流、气流等）；使枯萎；轻易击败；损坏，摧毁；开，炸开（通路）**{int.}++该死，讨厌**{n.}++a very long fly ball**{n.}++[力]爆炸；冲击波；一阵**{vi.}++猛攻**{vt.}++[力]爆炸；损害；使枯萎**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('blaze', '[bleɪz]', 'http://dict.youdao.com/dictvoice?audio=blaze', '{v.}++熊熊燃烧；闪耀，发亮光；怒视，（怒火）燃烧；醒目地刊登在报纸等上，大肆宣扬；（枪炮）连续射击（或开火）； 夺取，摘取；大力击（球）；在树皮上刻路标；带头，开拓；快速移动**{n.}++大火，烈火；火焰；（光或色彩等的）展现，灿烂；（强烈感情的）迸发；（刻在树上用于指示道路的）标记，记号；（尤指马面部的一条）白斑**{n.}++a strong flame that burns brightly																										        				&quot;the blaze spread rapidly&quot;															   	同义词：								                                  				    blazing**{vt.}++在树皮上刻路标；公开宣布**{n.}++火焰，烈火；光辉；情感爆发**{vi.}++燃烧；照耀，发光；激发**', '');
