INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('blind', '[blaɪnd]', 'http://dict.youdao.com/dictvoice?audio=blind', '{adj.}++失明的，盲的；未察觉的，视而不见的；未加思考的，莫名的（形容感情强烈）；（拐角）看不见的，隐蔽的；无窗的，无门的；（行动）未掌握一定信息的；丝毫的，一丁点儿的；盲飞的；（植物）无芽的，无顶生花的**{v.}++使变瞎，使失明；使眼花，使目眩；蒙蔽，使无辨别力**{n.}++窗帘，（尤指）卷帘；（狩猎时的）埋伏处，伏击处；借口，幌子**{adv.}++看不清地；失去理智地；盲目地，无准备地**{n.}++people who have severe visual impairments, considered as a group																										        				&quot;he spent hours reading to the blind&quot;**{adj.}++[生物]盲目的；瞎的**{adv.}++盲目地；看不见地**{n.}++掩饰，借口；[建]百叶窗**', '');
