INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('blush', '[blʌʃ]', 'http://dict.youdao.com/dictvoice?audio=blush', '{v.}++（因感到难堪或羞愧而）脸红；惭愧，尴尬；使成红色**{n.}++（因感到难堪或羞愧的）脸红；胭红，淡红色； 胭脂；玫瑰红酒；胭脂**{n.}++a rosy color (especially in the cheeks) taken as a sign of good health																					   	同义词：								                                  				    bloom				    				    				      				    				      				    				                                      				    flush				    				    				      				    				      				    				                                      				    rosiness**{vi.}++脸红；感到惭愧**{n.}++脸红；红色；羞愧**', '');
