INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('comprehend', '[ˌkɑːmprɪˈhend]', 'http://dict.youdao.com/dictvoice?audio=comprehend', '{v.}++理解，领悟；包括，包含**{v.}++get the meaning of something																										        				&quot;Do you comprehend the meaning of this letter?&quot;															   	同义词：								                                  				    grok				    				    				      				    				      				    				                                      				    get the picture				    				    				      				    				      				    				                                      				    savvy				    				    				      				    				      				    				                                      				    dig				    				    				      				    				      				    				                                      				    grasp				    				    				      				    				      				    				                                      				    compass				    				    				      				    				      				    				                                      				    apprehend**{vt.}++理解；包含；由…组成**', '');
