INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('compulsory', '[kəmˈpʌlsəri]', 'http://dict.youdao.com/dictvoice?audio=compulsory', '{adj.}++必须做的，义务的，强制的**{n.}++（花样滑冰、竞技体操等的）规定动作**{adj.}++required by rule																										        				&quot;in most schools physical education is compulsory&quot;															   	同义词：								                                  				    mandatory				    				    				      				    				      				    				                                      				    required**{adj.}++义务的；必修的；被强制的**{n.}++（花样滑冰、竞技体操等的）规定动作**', '');
