INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('concentrate', '[ˈkɑːns(ə)ntreɪt]', 'http://dict.youdao.com/dictvoice?audio=concentrate', '{v.}++集中注意力，聚精会神；使集中，聚集；浓缩**{n.}++浓缩物，浓缩液**{n.}++the desired mineral that is left after impurities have been removed from mined ore																					   	同义词：								                                  				    dressed ore**{vi.}++集中；[物]浓缩；全神贯注；聚集**{vt.}++集中；[物]浓缩**{n.}++[物]浓缩，精选；浓缩液**', '');
