INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('confidence', '[ˈkɑːnfɪdəns]', 'http://dict.youdao.com/dictvoice?audio=confidence', '{n.}++自信，信心；信任，信赖；把握，肯定；保密，机密；秘密，知心话**{n.}++freedom from doubt; belief in yourself and your abilities																										        				&quot;after that failure he lost his confidence&quot;															   	同义词：								                                  				    assurance				    				    				      				    				      				    				                                      				    self-assurance				    				    				      				    				      				    				                                      				    self-confidence				    				    				      				    				      				    				                                      				    authority				    				    				      				    				      				    				                                      				    sureness**{n.}++信心；信任；秘密**', '');
