INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('conform', '[kənˈfɔːrm]', 'http://dict.youdao.com/dictvoice?audio=conform', '{v.}++遵守，符合；顺从，随潮流；一致，相吻合**{v.}++be similar, be in line with**{vi.}++符合；遵照；适应环境**{vt.}++使遵守；使一致；使顺从**{adj.}++一致的；顺从的**', '');
