INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('disgrace', '[dɪsˈɡreɪs]', 'http://dict.youdao.com/dictvoice?audio=disgrace', '{n.}++耻辱，不光彩； 令人感到羞耻的人（或事），不名誉的事；失宠**{v.}++使丢脸，使蒙受耻辱；使名誉扫地，使失势**{n.}++a state of dishonor																					   	同义词：								                                  				    shame				    				    				      				    				      				    				                                      				    ignominy**{v.}++bring shame or dishonor upon																					   	同义词：								                                  				    dishonor				    				    				      				    				      				    				                                      				    dishonour				    				    				      				    				      				    				                                      				    attaint				    				    				      				    				      				    				                                      				    shame**{n.}++耻辱；丢脸的人或事；失宠**', '');
