INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('distinct', '[dɪˈstɪŋkt]', 'http://dict.youdao.com/dictvoice?audio=distinct', '{adj.}++不同的，有区别的；清楚的，明显的；确切的**{adj.}++easy to perceive; especially clearly outlined																										        													        													        													        													        				&quot;a distinct flavor&quot;; &quot;a distinct odor of turpentine&quot;; &quot;a distinct outline&quot;; &quot;the ship appeared as a distinct silhouette&quot;; &quot;distinct fingerprints&quot;**{clearly or sharply defined to the mind																										        													        				&quot;Claudius was the first to invade Britain with distinct.}++..intentions of conquest&quot;; &quot;trenchant distinctions between right and wrong&quot;															   	同义词：								                                  				    clear-cut				    				    				      				    				      				    				                                      				    trenchant**{adj.}++明显的；独特的；清楚的；有区别的**', '');
