INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('dock', '[dɑːk]', 'http://dict.youdao.com/dictvoice?audio=dock', '{n.}++码头，船埠，船坞；港区；（供上下船或系船用的）突堤，栈桥；供船只、卡车、火车等装卸货物用的）月台；（尤指私家）泊位； 酸模（一种植物）；动物尾巴（除毛发外的）骨肉部分；被告席；被告席**{v.}++（使船）靠码头，进港；（航天器）在太空对接；将电子设备（如电脑、数码相机）相接；扣工资，扣分；剪短（动物的尾巴）**{n.}++an enclosure in a court of law where the defendant sits during the trial**{n.}++[水运]码头；[船]船坞；被告席；尾巴的骨肉部分**{vt.}++使靠码头；剪短**', '');
