INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('drain', '[dreɪn]', 'http://dict.youdao.com/dictvoice?audio=drain', '{v.}++（使）排出，滤干；喝光，喝干；使劳累，使疲惫；（使）逐渐消失；使降低，消耗；（通常指因惊吓或疾病而脸色）变苍白；漂亮地完成（投篮、射门等）；将（球）轻击入穴**{n.}++下水道，排水管；流失，消耗；（将体内液体排走的）导管，引流管；（场效应晶体管的）漏极；使人疲倦的事物，负担**{n.}++emptying something accomplished by allowing liquid to run out of it																					   	同义词：								                                  				    drainage**{vi.}++排水；流干**{vt.}++喝光，耗尽；使流出；排掉水**{n.}++排水；下水道，[建]排水管；消耗**', '');
