INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('establish', '[ɪˈstæblɪʃ]', 'http://dict.youdao.com/dictvoice?audio=establish', '{v.}++建立，设立；证实，确定；发现，找出；使被接受，使得到承认；使（故事的角色）真实；（桥牌）（通过出大牌）使（某）花色所剩的牌都能赢**{v.}++set up or found																					   	同义词：								                                  				    set up				    				    				      				    				      				    				                                      				    found				    				    				      				    				      				    				                                      				    launch**{vt.}++建立；创办；安置**', '');
