INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('eternal', '[ɪˈtɜːrn(ə)l]', 'http://dict.youdao.com/dictvoice?audio=eternal', '{adj.}++永恒的，永存的；似乎无休无止的，没完没了的**{adj.}++continuing forever or indefinitely																										        				&quot;eternal truths&quot;															   	同义词：								                                  				    ageless				    				    				      				    				      				    				                                      				    aeonian				    				    				      				    				      				    				                                      				    eonian				    				    				      				    				      				    				                                      				    everlasting				    				    				      				    				      				    				                                      				    perpetual				    				    				      				    				      				    				                                      				    unending				    				    				      				    				      				    				                                      				    unceasing**{adj.}++永恒的；不朽的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('evaporate', '[ɪˈvæpəreɪt]', 'http://dict.youdao.com/dictvoice?audio=evaporate', '{v.}++（使）蒸发，挥发；消失，消散**{v.}++lose or cause to lose liquid by vaporization leaving a more concentrated residue																										        				&quot;evaporate milk&quot;															   	同义词：								                                  				    vaporize				    				    				      				    				      				    				                                      				    vaporise**{vt.}++使……蒸发；使……脱水；使……消失**{vi.}++蒸发，挥发；消失，失踪**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('even', '[ˈiːv(ə)n]', 'http://dict.youdao.com/dictvoice?audio=even', '{adj.}++平坦的，水平的；平静的，平和的；平齐的，挨着的；无变化的，平稳的；势均力敌的，不相上下的；双数的，偶数的；平等的，公平的；不变的，恒定的；（某事发生的概率）对半的，各半的；扯平的，互不相欠的；匀称的，同样大小的；正好的，不多不少的**{adv.}++甚至，即使；更加，愈加；其实，实际上**{v.}++使相等，使平均；变平坦；使变平，使平整**{n.}++傍晚，晚上**{n.}++the latter part of the day (the period of decreasing daylight from late afternoon until nightfall)																										        				&quot;he enjoyed the evening light across the lake&quot;															   	同义词：								                                  				    evening				    				    				      				    				      				    				                                      				    eve				    				    				      				    				      				    				                                      				    eventide**{v.}++make level or straight																					   	同义词：								                                  				    flush				    				    				      				    				      				    				                                      				    level				    				    				      				    				      				    				                                      				    even out**{adj.}++[数]偶数的；平坦的；相等的**{adv.}++甚至；即使；还；实际上**{vt.}++使平坦；使相等**{vi.}++变平；变得可比较；成为相等**', '');
