INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('everlasting', '[ˌevərˈlæstɪŋ]', 'http://dict.youdao.com/dictvoice?audio=everlasting', '{adj.}++永恒的；接连不断的**{n.}++any of various plants of various genera of the family Compositae having flowers that can be dried without loss of form or color																					   	同义词：								                                  				    everlasting flower**{adj.}++continuing forever or indefinitely																										        				&quot;life everlasting&quot;															   	同义词：								                                  				    ageless				    				    				      				    				      				    				                                      				    aeonian				    				    				      				    				      				    				                                      				    eonian				    				    				      				    				      				    				                                      				    eternal				    				    				      				    				      				    				                                      				    perpetual				    				    				      				    				      				    				                                      				    unending				    				    				      				    				      				    				                                      				    unceasing**{adj.}++永恒的；接连不断的**', '');
