INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('evolution', '[ˌevəˈluːʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=evolution', '{n.}++进化（论）；演变，发展；（气体的）释放，（热量的）散发；队形变换，位置变换；开方**{n.}++a process in which something passes by degrees to a different stage (especially a more advanced or mature stage)																										        				&quot;the evolution of Greek civilization&quot;															   	同义词：								                                  				    development**{n.}++演变；[进化]进化论；进展**', '');
