INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('except', '[ɪkˈsept]', 'http://dict.youdao.com/dictvoice?audio=except', '{prep.}++除……外，不包括**{conj.}++除了，只是；要不是**{v.}++不包括，把……排除在外**{v.}++take exception to																					   	同义词：								                                  				    demur**{vi.}++反对**{prep.}++除…之外**{conj.}++除了；要不是**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('exceptional', '[ɪkˈsepʃən(ə)l]', 'http://dict.youdao.com/dictvoice?audio=exceptional', '{adj.}++卓越的，杰出的；不寻常的，罕见的；（心理或身体上）有缺陷的**{n.}++（公司账目上的）异常项目**{adj.}++far beyond what is usual in magnitude or degree																										        				&quot;an exceptional memory&quot;															   	同义词：								                                  				    exceeding				    				    				      				    				      				    				                                      				    olympian				    				    				      				    				      				    				                                      				    prodigious				    				    				      				    				      				    				                                      				    surpassing**{adj.}++异常的，例外的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('excess', '[ɪkˈses]', 'http://dict.youdao.com/dictvoice?audio=excess', '{n.}++超过，过量；越轨行为，暴行；无节制，无度；（保险中的）免赔额**{adj.}++过多的，超额的；额外的，附加的**{n.}++a quantity much larger than is needed																					   	同义词：								                                  				    surplus				    				    				      				    				      				    				                                      				    surplusage				    				    				      				    				      				    				                                      				    nimiety**{n.}++超过，超额；过度，过量；无节制**{adj.}++额外的，过量的；附加的**', '');
