INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('exclusive', '[ɪkˈskluːsɪv]', 'http://dict.youdao.com/dictvoice?audio=exclusive', '{adj.}++独有的，专用的；高档的，昂贵的；不含……的；排外的；排斥的；全部的；唯一关心的；（新闻或报道）独家的；（条款）除外责任的；高级的，昂贵的**{n.}++独家新闻，独家报道**{n.}++a news report that is reported first by one news organization																					   	同义词：								                                  				    scoop**{adj.}++not divided or shared with others																										        				&quot;they have exclusive use of the machine&quot;															   	同义词：								                                  				    sole(a)**{adj.}++独有的；排外的；专一的**{n.}++独家新闻；独家经营的项目；排外者**', '');
