INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('excuse', '[ɪkˈskjuːs]', 'http://dict.youdao.com/dictvoice?audio=excuse', '{n.}++借口，托词；正当理由；宽恕，赦免；拙劣样品，蹩脚货；（医生或父母为学生写的）病假条，请假条**{v.}++原谅，宽恕；辩解，开脱；准许……离开；同意免除**{n.}++a defense of some offensive behavior or some failure to keep a promise etc.																										        				&quot;he kept finding excuses to stay&quot;															   	同义词：								                                  				    alibi				    				    				      				    				      				    				                                      				    exculpation				    				    				      				    				      				    				                                      				    self-justification**{n.}++借口；理由**{vt.}++原谅；为…申辩；给…免去**{vi.}++作为借口；请求宽恕；表示宽恕**', '');
