INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('flux', '[flʌks]', 'http://dict.youdao.com/dictvoice?audio=flux', '{n.}++不断变化，波动；（血等体液的）流出，溢出；（物理）通量，能流；辐射（或粒子）通量；电通量，磁通量；焊剂，（助）熔剂；造渣**{v.}++用焊（或熔）剂处理；使熔融**{n.}++the rate of flow of energy or particles across a given surface**{n.}++[流][机]流量；变迁；不稳定；流出**{vt.}++使熔融；用焊剂处理**{vi.}++熔化；流出**', '');
