INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('fright', '[fraɪt]', 'http://dict.youdao.com/dictvoice?audio=fright', '{n.}++惊骇，恐怖，惊吓；恐怖的经历；不整洁的人，奇怪、丑陋的东西**{v.}++使惊恐**{n.}++an emotion experienced in anticipation of some specific pain or danger (usually accompanied by a desire to flee or fight)																					   	同义词：								                                  				    fear				    				    				      				    				      				    				                                      				    fearfulness**{v.}++cause fear in																										        													        				&quot;The stranger who hangs around the building frightens me&quot;; &quot;Ghosts could never affright her&quot;															   	同义词：								                                  				    frighten				    				    				      				    				      				    				                                      				    scare				    				    				      				    				      				    				                                      				    affright**{n.}++惊吓；惊骇**{vt.}++使惊恐**', '');
