INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('hard', '[hɑːrd]', 'http://dict.youdao.com/dictvoice?audio=hard', '{adj.}++硬的，坚固的；困难的；困苦的，艰苦的；费力的，努力的；坚强的，勇敢的；猛烈的，用力的；冷酷的，严厉的；寒冷的，凛冽的；可证实的，确凿的；刺眼的，（感觉上）难受的；（水）硬的；烈性的，强烈的；（酒）苦涩的；仔细的，认真的；严肃的；强壮的；（政治上）极端的；发硬音的**{adv.}++努力地，费力地；用力地，猛烈地；仔细地，认真地；沉重地，大量地；变硬；在最大程度上**{n.}++海滩路**{adj.}++not easy; requiring great physical or mental effort to accomplish or comprehend or endure																										        				&quot;why is it so hard for you to keep a secret?&quot;															   	同义词：								                                  				    difficult**{adj.}++努力的；硬的；困难的；辛苦的；[医]确实的；严厉的；猛烈的；冷酷无情的**{adv.}++努力地；困难地；辛苦地；接近地；猛烈地；牢固地**', '');
