INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('hatch', '[hætʃ]', 'http://dict.youdao.com/dictvoice?audio=hatch', '{v.}++孵化，孵出；密谋，策划**{n.}++（船甲板或飞机底部装货物的）舱口；（尤指厨房和餐厅之间供传递食物的）两室之间的小窗口；（飞机或宇宙飞船的）舱门；（地面或天花板的）开口**{n.}++the production of young from an egg																					   	同义词：								                                  				    hatching**{n.}++孵化；[船][航]舱口**{vt.}++[动]孵；策划**{vi.}++孵化**', '');
