INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('haul', '[hɔːl]', 'http://dict.youdao.com/dictvoice?audio=haul', '{v.}++（用力）拖，拉；强迫（某人）去某处；费力前进，艰难地走；迫使（某人）出庭受审；（用运载工具）运送，运输；（费力地）升级；（尤指帆船）突然改变航道**{n.}++拖，拉；大批赃物，大量非法物品；赛季（或赛事）得分总数；旅行的距离；一网的捕鱼量；托运的距离**{n.}++the act of drawing or hauling something																										        				&quot;the haul up the hill went very slowly&quot;															   	同义词：								                                  				    draw				    				    				      				    				      				    				                                      				    haulage**{n.}++拖，拉；用力拖拉；努力得到的结果；捕获物；一网捕获的鱼量；拖运距离**{vt.}++[交]拖运；拖拉**{vi.}++拖，拉；改变主意；改变方向**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('haunt', '[hɔːnt]', 'http://dict.youdao.com/dictvoice?audio=haunt', '{v.}++（鬼魂）出没；萦绕在……心头；（长期）困扰；常去（某地）**{n.}++常去的地方；栖息地**{n.}++a frequently visited place																					   	同义词：								                                  				    hangout				    				    				      				    				      				    				                                      				    resort				    				    				      				    				      				    				                                      				    repair				    				    				      				    				      				    				                                      				    stamping ground**{v.}++follow stealthily or recur constantly and spontaneously to																										        				&quot;the ghost of her mother haunted her&quot;															   	同义词：								                                  				    stalk**{n.}++栖息地；常去的地方**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('hazard', '[ˈhæzərd]', 'http://dict.youdao.com/dictvoice?audio=hazard', '{n.}++危险，危害；（不可避免的）风险；（高尔夫球道）障碍物（如池塘或沙地）；机会，机遇；双骰子游戏；（网球）可得分区域；（台球）使球触他球后落入袋中的一击**{v.}++冒失地提出，冒险猜测；使遭危险，使处于危险**{n.}++a source of danger; a possibility of incurring loss or misfortune																										        				&quot;drinking alcohol is a health hazard&quot;															   	同义词：								                                  				    jeopardy				    				    				      				    				      				    				                                      				    peril				    				    				      				    				      				    				                                      				    risk				    				    				      				    				      				    				                                      				    endangerment**{vt.}++赌运气；冒…的危险，使遭受危险**{n.}++[安全]危险，冒险；冒险的事**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('head', '[hed]', 'http://dict.youdao.com/dictvoice?audio=head', '{n.}++头；头脑，智力；顶部；排头；领导人，负责人；校长，院长；人数，（动物的）头数；（植物的）叶球，头状花序；一头长，一头高；钉头，锤头；啤酒沫；（河流）源头；脓头；硬币正面（有人头像）；磁头；（短语的）中心词，主导词；水压，蒸汽压力；紧要关头；桌子的上首座位，床头；头痛；蓄水高度，水头**{v.}++朝（某方向）行进；领导，主管；居……之首；加标题；用头顶（球）；形成……的头或顶部；砍（植物或树木的）枝；（莴苣，卷心菜）结球，长成球状；发源**{adj.}++领头的，负责的；头的；在顶端的；从前方来的**{adv.}++（硬币）有头像的一面朝上（heads）**{n.}++the upper part of the human body or the front part of the body in animals; contains the face and brains																										        				&quot;he stuck his head out the window&quot;															   	同义词：								                                  				    caput**{n.}++[解剖]头；头痛；上端；最前的部分；理解力**{vt.}++前进；用头顶；作为…的首领；站在…的前头；给…加标题**{vi.}++出发；成头状物；船驶往**{adj.}++头的；主要的；在顶端的**', '');
