INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('hit', '[hɪt]', 'http://dict.youdao.com/dictvoice?audio=hit', '{v.}++打，击；撞击，碰撞；击中，命中；击（球）；产生不良影响，危害；攻击，袭击；达到（一个特定的水平，阶段，数字）；碰到，遇到（困难、问题等）；使（某人）突然意识到；使（突然）闻到，使看到；按，摁；给（人）一剂毒品（或烈酒）；（产品）面市并产生影响；给（21点纸牌游戏玩家）发另一张纸牌**{n.}++打击；命中，击中；很受欢迎的人（或事物），成功；（对网站的）访问，点击；毒品的一剂；暴力犯罪，凶杀；很受欢迎的人（或事物）**{n.}++(baseball) a successful stroke in an athletic contest (especially in baseball)																										        				&quot;he came all the way around on Williams hit&quot;**{vt.}++打击；袭击；碰撞；偶然发现；伤…的感情**{vi.}++打；打击；碰撞；偶然碰上**{n.}++打；打击；（演出等）成功；讽刺**', '');
