INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('hollow', '[ˈhɑːloʊ]', 'http://dict.youdao.com/dictvoice?audio=hollow', '{adj.}++空的，空心的；凹的，凹陷的；虚伪的，不真诚的；无用的，无价值的；（声音）沉闷回荡的；空腹的；沉闷回荡的**{v.}++使凹陷，使下陷；挖洞（成某物）；形成空洞**{n.}++凹陷处，坑洼处；坑，洞；山谷**{n.}++a cavity or space in something																										        				&quot;hunger had caused the hollows in their cheeks&quot;**{adj.}++空的；中空的，空腹的；凹的；虚伪的**{n.}++洞；山谷；窟窿**{vi.}++形成空洞**{adv.}++彻底地；无用地**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('homely', '[ˈhoʊmli]', 'http://dict.youdao.com/dictvoice?audio=homely', '{adj.}++普通的，朴实无华的；相貌平平的；像家一样舒适的；（女子）热情亲切的，家庭主妇型的**{adj.}++lacking in physical beauty or proportion																										        													        				&quot;a homely child&quot;; &quot;several of the buildings were downright homely&quot;															   	同义词：								                                  				    plain**{adj.}++家庭的；平凡的；不好看的**', '');
