INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('hook', '[hʊk]', 'http://dict.youdao.com/dictvoice?audio=hook', '{n.}++钩，挂钩；勾拳；曲线球；吸引人的东西；使（投手）下场；（尤指用于收割、剪羊毛）弧形切割工具；弯曲的笔画；弧形岬（或沙嘴）**{v.}++钩住，挂住；（用手臂等身体部位）箍住；钓鱼；打曲线球；弯成钩状；吸引；偷窃；卖淫；把……连接到（某设备）**{n.}++a catch for locking a door**{n.}++挂钩，[机]吊钩**{vt.}++钩住；[口腔]引上钩**', '');
