INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('house', '[haʊs]', 'http://dict.youdao.com/dictvoice?audio=house', '{n.}++房子，住宅；一家人，同住一幢房子的人们；（有特定用途的）大楼，大厦；公司，商业机构；观众席，观众；演出场次；餐馆，餐厅；豪斯音乐；王室，皇族（House）；（某些英国学校学生为进行比赛而分的）组；动物的笼舍；议院，议会；（占星）黄道十二宫之一，黄道宫**{v.}++让……居住，给……提供住房；给……提供场地，收藏存放；包裹，覆盖；住**{adj.}++家养的，常在室内的；公司的，机构的；（乐队，组合）（在俱乐部或别的场所）常驻的，定期表演的**{n.}++a dwelling that serves as living quarters for one or more families																										        													        				&quot;he has a house on Cape Cod&quot;; &quot;she felt she had to get out of the house&quot;**{n.}++[建]住宅；家庭；机构；议会；某种用途的建筑物**{vt.}++覆盖；给…房子住；把…储藏在房内**', '');
