INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('hug', '[hʌɡ]', 'http://dict.youdao.com/dictvoice?audio=hug', '{v.}++拥抱；抱住，抱在胸前；紧靠，紧挨；（衣服）缠紧，缚紧；暗自庆幸，沾沾自喜；抱有，持有（信念等）**{n.}++拥抱，紧抱；（摔跤中的）抓握**{n.}++a tight or amorous embrace																										        				&quot;come here and give me a big hug&quot;															   	同义词：								                                  				    clinch				    				    				      				    				      				    				                                      				    squeeze**{v.}++squeeze (someone) tightly in your arms, usually with fondness																										        				&quot;He hugged her close to him&quot;															   	同义词：								                                  				    embrace				    				    				      				    				      				    				                                      				    bosom				    				    				      				    				      				    				                                      				    squeeze**{vt.}++拥抱；紧抱；抱有，坚持**{vi.}++拥抱；紧抱在一起；挤在一起**{n.}++拥抱；紧抱；固执**', '');
