INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('inclination', '[ˌɪnklɪˈneɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=inclination', '{n.}++倾向，意愿；趋向，趋势；斜坡，斜度；轻微向下的动作；轨道交角**{n.}++an attitude of mind especially one that favors one alternative over others																										        				&quot;he had an inclination to give up too easily&quot;															   	同义词：								                                  				    disposition				    				    				      				    				      				    				                                      				    tendency**{n.}++倾向，爱好；斜坡**', '');
