INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('inclusive', '[ɪnˈkluːsɪv]', 'http://dict.youdao.com/dictvoice?audio=inclusive', '{adj.}++包容广阔的；包括一切费用在内的；包括的，包含的；无性别歧视的；对外开放的**{adj.}++including much or everything; and especially including stated limits																										        													        													        													        				&quot;an inclusive art form&quot;; &quot;an inclusive fee&quot;; &quot;his concept of history is modern and inclusive&quot;; &quot;from Monday to Friday inclusive&quot;**{adj.}++包括的，包含的**', '');
