INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('incorporate', '[ɪnˈkɔːrpəreɪt]', 'http://dict.youdao.com/dictvoice?audio=incorporate', '{v.}++包含，合并；组成公司；掺和，混合（成分）；使具体化，体现**{adj.}++合成一体的，合并的；具体化的；组成公司（或社团）的**{v.}++make into a whole or make part of a whole																										        				&quot;She incorporated his suggestions into her proposal&quot;															   	同义词：								                                  				    integrate**{vt.}++包含，吸收；体现；把……合并**{vi.}++合并；混合；组成公司**{adj.}++合并的；一体化的；组成公司的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('incredible', '[ɪnˈkredəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=incredible', '{adj.}++不可思议的，难以置信的；惊人的，极大的，极多的；了不起的，极好的**{adj.}++beyond belief or understanding																										        													        				&quot;at incredible speed&quot;; &quot;the books plot is simply incredible&quot;															   	同义词：								                                  				    unbelievable**{adj.}++难以置信的，惊人的**', '');
