INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('indicative', '[ɪnˈdɪkətɪv]', 'http://dict.youdao.com/dictvoice?audio=indicative', '{adj.}++指示的，表明的，象征的；陈述（语气）的**{n.}++陈述语气的动词形式，陈述语气**{n.}++a mood (grammatically unmarked) that represents the act or state as an objective fact																					   	同义词：								                                  				    indicative mood				    				    				      				    				      				    				                                      				    declarative mood				    				    				      				    				      				    				                                      				    declarative				    				    				      				    				      				    				                                      				    common mood				    				    				      				    				      				    				                                      				    fact mood**{adj.}++relating to the mood of verbs that is used simple declarative statements																										        				&quot;indicative mood&quot;															   	同义词：								                                  				    declarative**{adj.}++象征的；指示的；表示…的**', '');
