INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('line', '[laɪn]', 'http://dict.youdao.com/dictvoice?audio=line', '{n.}++线，线条；（运动场地的）场界，场地线；皱纹，褶子；分界线，边界线；（思想或行为等的）界限；轮廓，外形；排，行，列；队列，队伍；一系列（类似事物），家族；各级人员；字行，诗行；（戏剧或电影的）台词，对白；罚抄写（对学童的处罚）（lines）；妙语，谎话；线，绳，索；电话线（路）；热线（电话），电话服务；（铁道或公交）线路；铁轨，轨道；管线；（行进的）方向，路线；路径，渠道；（尤指公开表明的）态度，看法；方法，方式；行业，行当；种类，类型；运输公司，航运公司；防线，前线，战线；生产线，流水线；一串音符；（准备吸用的）散放成细线的毒品；赤道（the Line）；（印刷，计算机）线条的；字母底部水平线（the line）；（正规）战斗部队（the line）**{v.}++沿……形成行（或列、排）；给……安衬里，铺，垫；（在某物的内部）形成一层；击出（平直球）；用线条标出，布满线条（lined）**{n.}++a formation of people or things one beside another																										        													        													        				&quot;the line of soldiers advanced with their bayonets fixed&quot;; &quot;they were arrayed in line of battle&quot;; &quot;the cast stood in line for the curtain call&quot;**{n.}++路线，航线；排；绳**{vi.}++排队；站成一排**', '');
