INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('manifest', '[ˈmænɪfest]', 'http://dict.youdao.com/dictvoice?audio=manifest', '{v.}++显示，表明；（鬼魂或神灵）显灵，出现；（病症）显现；把……列入货单；显化（指通过可视化和积极思考来帮助梦想成真）**{adj.}++明显的，显而易见的**{n.}++旅客名单，载货清单；货运列车编组清单**{n.}++a customs document listing the contents put on a ship or plane**{v.}++provide evidence for; stand as proof of; show by ones behavior, attitude, or external attributes																										        				&quot;The buildings in Rome manifest a high level of architectural sophistication&quot;															   	同义词：								                                  				    attest				    				    				      				    				      				    				                                      				    certify				    				    				      				    				      				    				                                      				    demonstrate				    				    				      				    				      				    				                                      				    evidence**{vt.}++证明，表明；显示**{vi.}++显示，出现**{n.}++[贸易]载货单，货单；旅客名单**{adj.}++显然的，明显的；明白的**', '');
