INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('marginal', '[ˈmɑːrdʒɪn(ə)l]', 'http://dict.youdao.com/dictvoice?audio=marginal', '{adj.}++小的，微不足道的；（活动、花费、税项等）边际的；非主流的，边缘的；以相差无几的票数获胜（或失败）的；写在页边空白的；贫瘠的**{n.}++岸边水生植物；边缘席位**{adj.}++at or constituting a border or edge																										        				&quot;the marginal strip of beach&quot;															   	同义词：								                                  				    fringy**{adj.}++[数]边缘的；临界的；末端的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('market', '[ˈmɑːrkɪt]', 'http://dict.youdao.com/dictvoice?audio=market', '{n.}++集市，市场；交易，交易量；行销地区，购买人群；市场机制；股市；市面，市况**{v.}++推销，促销；出售；做买卖**{adj.}++市场的，由市场决定的**{n.}++the world of commercial activity where goods and services are bought and sold																										        													        				&quot;without competition there would be no market&quot;; &quot;they were driven from the marketplace&quot;															   	同义词：								                                  				    marketplace**{n.}++市场；行情；股票市场；市面；[贸易]集市；销路；商店**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('Mars', '[mɑːrz]', 'http://dict.youdao.com/dictvoice?audio=Mars', '{n.}++战神；[天] 火星**{n.}++a small reddish planet that is the 4th from the sun and is periodically visible to the naked eye; minerals rich in iron cover its surface and are responsible for its characteristic color																					   	同义词：								                                  				    Red Planet**{n.}++战神；[天]火星**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('marsh', '[mɑːrʃ]', 'http://dict.youdao.com/dictvoice?audio=marsh', '{n.}++沼泽，湿地**{n.}++low-lying wet land with grassy vegetation; usually is a transition zone between land and water																										        				&quot;thousands of acres of marshland&quot;															   	同义词：								                                  				    marshland				    				    				      				    				      				    				                                      				    fen				    				    				      				    				      				    				                                      				    fenland**{n.}++沼泽；[地理]湿地**{adj.}++[地理]沼泽的；生长在沼泽地的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('marshal', '[ˈmɑːrʃ(ə)l]', 'http://dict.youdao.com/dictvoice?audio=marshal', '{n.}++（英国）陆军元帅，空军元帅；司仪，典礼官；（尤指体育赛事的）总指挥；（美国法院的）执行官；一些美国城市的）警察局长，消防局长；（英国）巡回法官随员**{v.}++结集，安排；控制，组织；整理（思路、想法等）；（车辆）编组；引导（飞机在机场地面移动）；合并（盾徽）；成形，有序**{n.}++a law officer having duties similar to those of a sheriff in carrying out the judgments of a court of law																					   	同义词：								                                  				    marshall**{n.}++[军]元帅；司仪**{vt.}++整理；引领；编列**{vi.}++排列**', '');
