INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('marvel', '[ˈmɑːrv(ə)l]', 'http://dict.youdao.com/dictvoice?audio=marvel', '{n.}++令人惊异的人（或事），奇迹**{v.}++感到惊奇，大为赞叹**{n.}++something that causes feelings of wonder																					   	同义词：								                                  				    wonder**{v.}++be amazed at																										        				&quot;We marvelled at the childs linguistic abilities&quot;															   	同义词：								                                  				    wonder**{n.}++奇迹**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('masculine', '[ˈmæskjəlɪn]', 'http://dict.youdao.com/dictvoice?audio=masculine', '{adj.}++男性的，男子的；阳刚的，男子气概的；（某些语言中）阳性的**{n.}++阳性词，阳性词形；男性，雄性**{n.}++a gender that refers chiefly (but not exclusively) to males or to objects classified as male**{adj.}++of grammatical gender**{adj.}++[人类]男性的；阳性的；男子气概的**{n.}++[人类]男性；阳性，阳性词**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('massacre', '[ˈmæsəkər]', 'http://dict.youdao.com/dictvoice?audio=massacre', '{n.}++屠杀，残杀；（运动或比赛中的）惨败**{v.}++（大规模地）屠杀，杀戮；（比赛或竞争等中）使惨败，彻底击败；笨拙地演奏（演唱）**{vt.}++残杀；彻底击败**{n.}++大屠杀；惨败**', '');
