INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mature', '[məˈtʃʊr]', 'http://dict.youdao.com/dictvoice?audio=mature', '{adj.}++成熟的，理智的；成年的，发育完全的；发酵成熟的，酿成的；中老年的；技艺精湛的，技巧娴熟的；审慎考虑的，深思熟虑的；到期（应该支付）的；（某些食品或饮料）可立即食用的；（经济，行业，市场）成熟的，发展余地不大的**{v.}++（使）成熟，（使）长成；变理智，（举止）变成熟；酿成，制成；到期**{v.}++develop and reach maturity; undergo maturation																										        				&quot;He matured fast&quot;															   	同义词：								                                  				    maturate				    				    				      				    				      				    				                                      				    grow**{adj.}++[农学][地质]成熟的；充分考虑的；到期的；成年人的**{vi.}++[农学][地质]成熟；到期**', '');
