INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mechanics', '[məˈkænɪks]', 'http://dict.youdao.com/dictvoice?audio=mechanics', '{n.}++机械学，力学；机制，运作方式；机械部件，运转部件；结构，构成**{n.}++the branch of physics concerned with the motion of bodies in a frame of reference**{n.}++[力]力学（用作单数）；结构；技术；[机]机械学（用作单数）**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mechanism', '[ˈmekənɪzəm]', 'http://dict.youdao.com/dictvoice?audio=mechanism', '{n.}++机械装置，机件；途径，方法；（生物体内的）机制，构造；机械论；（产生自然现象等的）物理过程**{n.}++the atomic process that occurs during a chemical reaction																										        				&quot;he determined unique mechanisms for the photochemical reactions&quot;															   	同义词：								                                  				    chemical mechanism**{n.}++机制；原理，途径；进程；机械装置；技巧**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('meditate', '[ˈmedɪteɪt]', 'http://dict.youdao.com/dictvoice?audio=meditate', '{v.}++（宗教中）默想，冥想；思考，沉思（meditate on/upon）；暗自策划，谋划**{v.}++reflect deeply on a subject																					   	同义词：								                                  				    chew over				    				    				      				    				      				    				                                      				    think over				    				    				      				    				      				    				                                      				    ponder				    				    				      				    				      				    				                                      				    excogitate				    				    				      				    				      				    				                                      				    contemplate				    				    				      				    				      				    				                                      				    muse				    				    				      				    				      				    				                                      				    reflect				    				    				      				    				      				    				                                      				    mull				    				    				      				    				      				    				                                      				    mull over				    				    				      				    				      				    				                                      				    ruminate				    				    				      				    				      				    				                                      				    speculate**{vt.}++考虑；计划；企图**{vi.}++冥想；沉思**', '');
