INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('menace', '[ˈmenəs]', 'http://dict.youdao.com/dictvoice?audio=menace', '{n.}++威胁，危险的人或物；烦人的人（或事物），引起麻烦的人（或事物）；危险气氛，威胁；（以）威胁（或恐吓）的手段（索要钱财）**{v.}++威胁，威吓**{n.}++something that is a source of danger																					   	同义词：								                                  				    threat**{n.}++威胁；恐吓**{vi.}++恐吓；进行威胁**{vt.}++威胁；恐吓**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mend', '[mend]', 'http://dict.youdao.com/dictvoice?audio=mend', '{v.}++缝补，修补；修理；愈合，痊愈；弥合（分歧），解决（争端）；（给火）添燃料**{n.}++好转，复苏；修理过的地方，补丁**{n.}++sewing that repairs a worn or torn hole (especially in a garment)																										        				&quot;her stockings had several mends&quot;															   	同义词：								                                  				    patch				    				    				      				    				      				    				                                      				    darn**{vt.}++修理，修补；改善；修改**{vi.}++改善，好转**{n.}++好转，改进；修补处**', '');
