INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('merciful', '[ˈmɜːrsɪf(ə)l]', 'http://dict.youdao.com/dictvoice?audio=merciful', '{adj.}++宽大的，仁慈的；带来幸运的，给人解脱的**{adj.}++showing or giving mercy																										        													        				&quot;sought merciful treatment for the captives&quot;; &quot;a merciful god&quot;**{adj.}++仁慈的；慈悲的；宽容的**', '');
