INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('merit', '[ˈmerɪt]', 'http://dict.youdao.com/dictvoice?audio=merit', '{n.}++优秀品质，价值；优点，长处；（成绩等级）良好；事实真相，是非曲直；善行，善事**{v.}++值得，应受；应受赏（或罚）**{n.}++any admirable quality or attribute																										        				&quot;work of great merit&quot;															   	同义词：								                                  				    virtue**{the quality of being deserving (e.}++g., deserving assistance)																					   	同义词：								                                  				    deservingness				    				    				      				    				      				    				                                      				    meritoriousness**{n.}++优点，价值；功绩；功过**{vt.}++值得**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mesh', '[meʃ]', 'http://dict.youdao.com/dictvoice?audio=mesh', '{n.}++网，网状物；错综复杂的局面，陷阱，圈套；网眼，网孔；网状结构，互相交织的结构；（计算机）网格，格网；（计算机）网状网络（尤指 n 维点阵）**{v.}++啮合；吻合，匹配，适合；（使）交缠在一起；将……转化成网格，将……生成网格；以网捕捉**{n.}++the number of opening per inch of a screen; measures size of particles																										        													        				&quot;a 100 mesh screen&quot;; &quot;100 mesh powdered cellulose&quot;**{n.}++网眼；网丝；圈套**{vt.}++[机]啮合；以网捕捉**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mess', '[mes]', 'http://dict.youdao.com/dictvoice?audio=mess', '{n.}++肮脏，杂乱；不整洁或邋遢的人（或物）；掉落的东西，溅出的东西；（动物的）粪便；困境，混乱局面；处于困境的人；（军队的）食堂，交谊厅； 大量；（尤指引不起食欲的）半干半稀的一份食物**{v.}++弄脏，弄乱；玩弄；随地便溺；在军人食堂就餐**{n.}++a state of confusion and disorderliness																										        				&quot;the house was a mess&quot;															   	同义词：								                                  				    messiness				    				    				      				    				      				    				                                      				    muss				    				    				      				    				      				    				                                      				    mussiness**{n.}++混乱；食堂，伙食团；困境；脏乱的东西**{vt.}++弄乱，弄脏；毁坏；使就餐**{vi.}++把事情弄糟；制造脏乱；玩弄**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('message', '[ˈmesɪdʒ]', 'http://dict.youdao.com/dictvoice?audio=message', '{n.}++口信，消息；（书籍、演讲等的）要旨，主题思想；（从大脑发给身体某部位或身体某部位向大脑发送的）信息；购物；电视广告；差使；启示，教训；（先知的）预言**{v.}++（尤指以电子形式）传送（信息）；通报**{n.}++a communication (usually brief) that is written or spoken or signaled																										        				&quot;he sent a three-word message&quot;**{n.}++消息；差使；启示；预言；广告词**{vi.}++报信，报告；[通信]报文**{vt.}++通知**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('metallic', '[məˈtælɪk]', 'http://dict.youdao.com/dictvoice?audio=metallic', '{adj.}++含金属的，金属制的；（金属碰撞发出的）叮当声的；（色彩）似金属的，像金属般闪烁的；金属味的；尖利刺耳的，难听的**{n.}++金属制品，含金属物；金属色泽**{n.}++a fabric made of a yarn that is partly or entirely of metal**{adj.}++金属的，含金属的**', '');
