INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('microprocessor', '[ˌmaɪkroʊˈprɑːsesər]', 'http://dict.youdao.com/dictvoice?audio=microprocessor', '{n.}++[计] 微处理器**{n.}++integrated circuit semiconductor chip that performs the bulk of the processing and controls the parts of a system																										        													        				&quot;a microprocessor functions as the central processing unit of a microcomputer&quot;; &quot;a disk drive contains a microprocessor to handle the internal functions of the drive&quot;**{n.}++[计]微处理器**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('microscopic', '[ˌmaɪkrəˈskɑːpɪk]', 'http://dict.youdao.com/dictvoice?audio=microscopic', '{adj.}++极小的，微小的；显微镜的，用显微镜的；非常仔细的，一丝不苟的；微观的**{adj.}++of or relating to or used in microscopy																										        													        				&quot;microscopic analysis&quot;; &quot;microscopical examination&quot;															   	同义词：								                                  				    microscopical**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('microwave', '[ˈmaɪkrəweɪv]', 'http://dict.youdao.com/dictvoice?audio=microwave', '{n.}++微波炉；微波**{v.}++用微波炉烹调（或加热）**{n.}++a short electromagnetic wave (longer than infrared but shorter than radio waves); used for radar and microwave ovens and for transmitting telephone, facsimile, video and data**{n.}++[物]微波**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mighty', '[ˈmaɪti]', 'http://dict.youdao.com/dictvoice?audio=mighty', '{adj.}++强大的，巨大的；（动作）用力的，需用力的**{adv.}++很，非常，十分**{adj.}++having or showing great strength or force or intensity																										        													        				&quot;struck a mighty blow&quot;; &quot;the mighty logger Paul Bunyan&quot;**{adv.}++(Southern regional intensive) very																										        													        				&quot;the baby is mighty cute&quot;; &quot;hes mighty tired&quot;															   	同义词：								                                  				    powerful				    				    				      				    				      				    				                                      				    right**{adj.}++有力的；强有力的；有势力的**{adv.}++很；极；非常**{n.}++有势力的人**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('migrate', '[ˈmaɪɡreɪt]', 'http://dict.youdao.com/dictvoice?audio=migrate', '{v.}++（候鸟或动物）迁徙；（尤指为找工作）移居，迁移；转移（从一个部位移到另一部位）；把（程序，硬件）从一系统转移到另一系统；改用操作系统**{v.}++move from one country or region to another and settle there																										        													        				&quot;Many Germans migrated to South America in the mid-19th century&quot;; &quot;This tribe transmigrated many times over the centuries&quot;															   	同义词：								                                  				    transmigrate**{vi.}++移动；随季节而移居；移往**{vt.}++使移居；使移植**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mild', '[maɪld]', 'http://dict.youdao.com/dictvoice?audio=mild', '{adj.}++（伤病）不严重的，轻微的；（感觉或表情）不强烈的，微弱的；（惩罚或批评）不严厉的；轻的，不过度的；（味道）清淡的，不刺激的；（药物、化妆品等）柔和的，无副作用的；（肥皂、洗涤液）温和的，不伤皮肤的；（天气）和煦的，温暖的；（人或其行为）和善的，随和的**{n.}++淡味黑啤**{adj.}++moderate in type or degree or effect or force; far from extreme																										        													        													        													        													        				&quot;a mild winter storm&quot;; &quot;a mild fever&quot;; &quot;fortunately the pain was mild&quot;; &quot;a mild rebuke&quot;; &quot;mild criticism&quot;**{adj.}++温和的；轻微的；淡味的；文雅的；不含有害物质的的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('milky', '[ˈmɪlki]', 'http://dict.youdao.com/dictvoice?audio=milky', '{adj.}++像奶的，如奶般的；奶制的，含奶多的；混浊不清的**{adj.}++resembling milk in color or cloudiness; not clear																										        				&quot;milky glass&quot;															   	同义词：								                                  				    milklike				    				    				      				    				      				    				                                      				    whitish**{adj.}++乳白色的；牛奶的；乳状的；柔和的；混浊不清的**', '');
