INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mingle', '[ˈmɪŋɡ(ə)l]', 'http://dict.youdao.com/dictvoice?audio=mingle', '{v.}++（在聚会中）应酬，交际；（使）混合**{v.}++to bring or combine together or with something else																										        				&quot;resourcefully he mingled music and dance&quot;															   	同义词：								                                  				    mix				    				    				      				    				      				    				                                      				    commix				    				    				      				    				      				    				                                      				    unify				    				    				      				    				      				    				                                      				    amalgamate**{vi.}++混合；交往**{vt.}++使混合；使相混**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('miniature', '[ˈmɪnətʃər]', 'http://dict.youdao.com/dictvoice?audio=miniature', '{adj.}++微型的，小型的**{n.}++缩微模型，微型复制品；微型画，小画像；小瓶装酒；小种植物（或动物）；（华美装饰手稿上的）画饰，花字**{n.}++painting or drawing included in a book (especially in illuminated medieval manuscripts)																					   	同义词：								                                  				    illumination**{adj.}++微型的，小规模的**{n.}++缩图；微型画；微型图画绘画术**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('minimize', '[ˈmɪnɪmaɪz]', 'http://dict.youdao.com/dictvoice?audio=minimize', '{v.}++使减少到最低限度；贬低，使显得不重要；（尤指在计算机屏幕上）使最小化**{v.}++make small or insignificant																										        				&quot;Lets minimize the risk&quot;															   	同义词：								                                  				    minimise**', '');
