INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mirror', '[ˈmɪrər]', 'http://dict.youdao.com/dictvoice?audio=mirror', '{n.}++镜子；写照，真实反映；（计算机）镜像网点；榜样**{vt.}++反射，映照；反映；与……十分相似；（计算机）做……的镜像；（计算机）在（两个或数个硬盘）中做备份**{n.}++polished surface that forms images by reflecting light**{n.}++[轻]镜子；真实的写照；榜样**{vt.}++[光]反射；反映**', '');
