INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('misery', '[ˈmɪzəri]', 'http://dict.youdao.com/dictvoice?audio=misery', '{n.}++痛苦，苦难；穷困，悲惨境遇；老发牢骚的人**{n.}++a state of ill-being due to affliction or misfortune																										        				&quot;the misery and wretchedness of those slums is intolerable&quot;															   	同义词：								                                  				    wretchedness				    				    				      				    				      				    				                                      				    miserableness**{n.}++痛苦，悲惨；不幸；苦恼；穷困**', '');
