INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mist', '[mɪst]', 'http://dict.youdao.com/dictvoice?audio=mist', '{n.}++薄雾，水汽；雾状物；使视线模糊的东西；迷雾，难以透彻了解的事物**{v.}++使……蒙上雾气；（使）充满泪水；给……喷水；下毛毛细雨**{n.}++a thin fog with condensation near the ground**{v.}++become covered with mist																										        				&quot;The windshield misted over&quot;															   	同义词：								                                  				    mist over**{n.}++[气象]薄雾；视线模糊不清；模糊不清之物**{vi.}++下雾；变模糊**{vt.}++使模糊；使蒙上薄雾**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mistress', '[ˈmɪstrəs]', 'http://dict.youdao.com/dictvoice?audio=mistress', '{n.}++女教师；（奴仆的）女主人；（宠物的）女主人；绝对控制……的女人，主宰……的女人；（精通某项活动的）女能手，女行家；女士（用作女子姓氏或姓名前的称呼）；女院长 (Mistress)；情妇**{n.}++an adulterous woman; a woman who has an ongoing extramarital sexual relationship with a man																					   	同义词：								                                  				    kept woman				    				    				      				    				      				    				                                      				    fancy woman**{n.}++情妇；女主人；主妇；女教师；女能人**', '');
