INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mixer', '[ˈmɪksər]', 'http://dict.youdao.com/dictvoice?audio=mixer', '{n.}++搅拌机；调酒用的饮料；（善于）交际的人；交谊会；声音（图像）混合器，声音（图像）混合操作员；（可与罐装湿食混拌的）宠物干性食物；（录音，电影摄影）混频器**{n.}++a party of people assembled to promote sociability and communal activity																					   	同义词：								                                  				    sociable				    				    				      				    				      				    				                                      				    social**{n.}++[电影][广播][电子][地物][通信]混合器；[机]搅拌器；混频器**', '');
