INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mock', '[mɑːk]', 'http://dict.youdao.com/dictvoice?audio=mock', '{v.}++嘲笑，（模仿）嘲弄；使显得徒劳，使显得可笑；（照原尺寸）模仿，仿制 （mock sth. up）**{adj.}++假装的，假的；仿真的；（考试、作战等）模拟的，演习的**{n.}++模拟考试（mocks）；嘲笑对象，笑柄；嘲笑；模仿，仿造（品）**{adv.}++虚假地，不诚实地**{n.}++the act of mocking or ridiculing																										        				&quot;they made a mock of him&quot;**{v.}++treat with contempt																										        				&quot;The new constitution mocks all democratic principles&quot;															   	同义词：								                                  				    bemock**{vt.}++嘲弄；模仿；使…失望；使…无效**{vi.}++嘲弄，嘲笑**{n.}++嘲弄；仿制品；嘲笑对象**{adj.}++模拟的；假装的；伪造的**{adv.}++虚伪地**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('moderately', '[ˈmɑːdərətli]', 'http://dict.youdao.com/dictvoice?audio=moderately', '{adv.}++有合理限度地，适中地；一般地，勉强地**{adv.}++to a moderately sufficient extent or degree																					   	同义词：								                                  				    reasonably				    				    				      				    				      				    				                                      				    within reason				    				    				      				    				      				    				                                      				    somewhat				    				    				      				    				      				    				                                      				    fairly				    				    				      				    				      				    				                                      				    middling				    				    				      				    				      				    				                                      				    passably**{adv.}++适度地；中庸地；有节制地**', '');
