INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('moor', '[mʊr]', 'http://dict.youdao.com/dictvoice?audio=moor', '{n.}++摩尔人（8世纪到15世纪之间统治西班牙南部的穆斯林）(Moor）；沼泽，高沼；猎场，狩猎区；（尤指长有欧石兰的）荒芜高原，荒野**{v.}++使（船）停泊，系泊**{n.}++one of the Muslim people of north Africa; of mixed Arab and Berber descent; converted to Islam in the 8th century; conqueror of Spain in the 8th century**{vt.}++系住；使停泊**{n.}++[地理]沼泽；荒野**', '');
