INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('mount', '[maʊnt]', 'http://dict.youdao.com/dictvoice?audio=mount', '{v.}++组织，开展；爬上，登上；骑上；增多，增加，上升；增强，加剧；镶嵌，裱贴，安置；上演，展出；爬上（雌性动物的背）进行交配；设置（岗哨），担任（警卫）；把（观察对象）固定于显微镜的载玻片**{n.}++山，山峰；坐骑，马；登，骑；（相片）框，（艺术品）装帧，衬托纸；底座，底架；（贴邮票用的）透明胶纸；（显微镜观察的）封片；掌丘**{n.}++a lightweight horse kept for riding only																					   	同义词：								                                  				    saddle horse				    				    				      				    				      				    				                                      				    riding horse**{vt.}++增加；爬上；使骑上马**{vi.}++爬；上升**{n.}++山峰；底座；乘骑用马**', '');
