INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('move', '[muːv]', 'http://dict.youdao.com/dictvoice?audio=move', '{v.}++（使）改变位置，（使）移动；搬家，搬迁；（使）变换，调动；（使）改变观点（或做法）；前进，进展；采取行动；使感动，打动；促使，驱使；更改（时间或日期）；改变话题；走棋，移动棋子；（在会议或法庭上）提议；快速行进；（商品）被销售，销售（商品）；进行社交活动，交往；离去；使（肠）排空**{n.}++措施，行动；移动，活动；转变，改变；一步棋，走棋；搬家，迁移**{n.}++the act of deciding to do something																										        													        				&quot;he didnt make a move to help&quot;; &quot;his first move was to hire a lawyer&quot;**{n.}++移动；步骤；迁居**{vi.}++移动；搬家，迁移；离开**{vt.}++移动；感动**', '');
