INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('municipal', '[mjuːˈnɪsɪp(ə)l]', 'http://dict.youdao.com/dictvoice?audio=municipal', '{adj.}++城市的，市政的；自治城市的，地方自治的；内政的**{adj.}++relating or belonging to or characteristic of a municipality																										        													        													        													        				&quot;municipal government&quot;; &quot;municipal bonds&quot;; &quot;a municipal park&quot;; &quot;municipal transportation&quot;**{of or relating to the government of a municipality																										        				&quot;international law.}++..only authorizes a belligerent to punish a spy under its municipal law&quot;**{adj.}++[建][经]市政的，市的；地方自治的**', '');
