INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('negative', '[ˈneɡətɪv]', 'http://dict.youdao.com/dictvoice?audio=negative', '{adj.}++有害的，负面的；悲观的，消极的；否定的，拒绝的；否定式的；（结果）阴性的；负极的，阴极的；负的，小于零的；亏损的；负像的，底片的；（天文）负的；（立法）自动生效的；Rh阴性的**{n.}++底片，负片；否定词，否定句；坏处，害处；阴性结果；（逻）（对命题的）否定；负电；负数**{v.}++拒绝，否定；推翻，证伪；消除，抵消**{n.}++a reply of denial																										        				&quot;he answered in the negative&quot;**{adj.}++[数]负的；消极的；[语]否定的；阴性的**{n.}++[语]否定；负数；[摄]底片**{vt.}++[语]否定；拒绝**', '');
