INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('nest', '[nest]', 'http://dict.youdao.com/dictvoice?audio=nest', '{n.}++窝，巢，穴；舒适的居所，安乐窝；（套叠的）一套物件，一组物件；藏匿处，秘密窝点**{v.}++（鸟类）筑巢，做窝；（一套物件）逐个套叠；嵌套（信息）；找鸟巢**{n.}++a structure in which animals lay eggs or give birth to their young**{n.}++巢，窝；安乐窝；温床**{vi.}++筑巢；找鸟巢**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('net', '[net]', 'http://dict.youdao.com/dictvoice?audio=net', '{n.}++网，网状物；因特网；球网，球门网；广播网，通讯网；安全网；捕鱼总量；净赚，纯利；（板球）练球场；（板球）一次练球；网眼织物；陷阱；候选人的选择面**{adj.}++净得的；净重的；最后的，最终的**{v.}++净赚，净得；设法获得，巧妙地做；（用网）捕捉；（篮球或足球）得分，进（球）；用网覆盖；（计算时）扣除……（以得出净额）**{adv.}++净赚地**{n.}++a computer network consisting of a worldwide network of computer networks that use the TCP/IP network protocols to facilitate data transmission and exchange																					   	同义词：								                                  				    internet				    				    				      				    				      				    				                                      				    cyberspace**{n.}++网；网络；净利；实价**{vt.}++得到；净赚；用网捕**{adj.}++纯粹的；净余的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('network', '[ˈnetwɜːrk]', 'http://dict.youdao.com/dictvoice?audio=network', '{n.}++网络，网状系统；人际关系网，联络网；计算机网络，互联网；广播网，电视网**{v.}++使（计算机）联网；（尤指工作中）建立关系网，建立人脉；对（电视或广播节目）进行联播**{n.}++an interconnected system of things or people																										        													        				&quot;he owned a network of shops&quot;; &quot;retirement meant dropping out of a whole network of people who had been part of my life&quot;															   	同义词：								                                  				    web**{n.}++[计][通信]网络；广播网；网状物**', '');
