INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('nice', '[naɪs]', 'http://dict.youdao.com/dictvoice?audio=nice', '{adj.}++美好的，令人愉快的；好心的，友好的；（天气）温暖的，宜人的；（观点、区别等）细致的，微妙的；（用于打招呼）很高兴见到你；干得好的，出色的；坏的，令人不愉快的；正派的，有教养的；挑剔的，谨慎的**{n.}++尼斯（法国城市，Nice）**{n.}++a city in southeastern France on the Mediterranean; the leading resort on the French Riviera**{adj.}++pleasant or pleasing or agreeable in nature or appearance																										        													        													        													        													        													        													        				&quot;what a nice fellow you are and we all thought you so nasty&quot;; &quot;nice manners&quot;; &quot;a nice dress&quot;; &quot;a nice face&quot;; &quot;a nice day&quot;; &quot;had a nice time at the party&quot;; &quot;the corn and tomatoes are nice today&quot;**{adj.}++精密的；美好的；细微的；和蔼的**', '');
