INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('nickname', '[ˈnɪkneɪm]', 'http://dict.youdao.com/dictvoice?audio=nickname', '{n.}++绰号，外号**{v.}++给……起绰号；叫错名字**{n.}++a familiar name for a person (often a shortened version of a persons given name)																										        													        				&quot;Joes mother would not use his nickname and always called him Joseph&quot;; &quot;Henrys nickname was Slim&quot;															   	同义词：								                                  				    moniker				    				    				      				    				      				    				                                      				    cognomen				    				    				      				    				      				    				                                      				    sobriquet				    				    				      				    				      				    				                                      				    soubriquet				    				    				      				    				      				    				                                      				    byname**{a descriptive name for a place or thing																										        				&quot;the nickname for the U.}++S. Constitution is `Old Ironsides&quot;**{n.}++绰号；昵称**', '');
