INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('norm', '[nɔːrm]', 'http://dict.youdao.com/dictvoice?audio=norm', '{n.}++社会准则，行为规范；标准，平均水平；常态，平常事物；模方；诺姆（指整日呆在家中看电视的懒人，尤指看体育节目）**{n.}++a standard or model or pattern regarded as typical																										        				&quot;the current middle-class norm of two children per family&quot;**{n.}++规范，基准；[经管]定额，分配之工作量**', '');
