INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('nose', '[noʊz]', 'http://dict.youdao.com/dictvoice?audio=nose', '{n.}++鼻子；（飞机、火箭等的）头部，机首；嗅觉；觉察力；（酒的）特有的气味；警方线人；探听，探问**{v.}++（车辆、船只等）缓慢地前行；（动物用鼻子）拱，嗅；勉强领先（或获胜）；窥探，搜寻**{n.}++the organ of smell and entrance to the respiratory tract; the prominent part of the face of man or other mammals																										        				&quot;he has a cold in the nose&quot;															   	同义词：								                                  				    olfactory organ**{n.}++鼻子；嗅觉；突出的部分；探问**{vt.}++嗅；用鼻子触**{vi.}++小心探索着前进；探问**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('notable', '[ˈnoʊtəb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=notable', '{adj.}++显要的，值得注意的；非常成功的，令人尊敬的**{n.}++显要人物，名流**{n.}++a celebrity who is an inspiration to others																					   	同义词：								                                  				    luminary				    				    				      				    				      				    				                                      				    leading light				    				    				      				    				      				    				                                      				    guiding light				    				    				      				    				      				    				                                      				    notability**{adj.}++worthy of notice																					   	同义词：								                                  				    noteworthy**{adj.}++值得注意的，显著的；著名的**{n.}++名人，显要人物**', '');
