INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('oblige', '[əˈblaɪdʒ]', 'http://dict.youdao.com/dictvoice?audio=oblige', '{v.}++迫使，责成；施恩惠于，帮……的忙；使（某人）遵守誓约（或承诺、约定）**{v.}++force or compel somebody to do something																					   	同义词：								                                  				    compel				    				    				      				    				      				    				                                      				    obligate**{vt.}++迫使；强制；赐，施恩惠；责成**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('obscure', '[əbˈskjʊr]', 'http://dict.youdao.com/dictvoice?audio=obscure', '{adj.}++难以说清楚的，模糊的；鲜为人知的，默默无闻的；未被查实的，不确定的；费解的，晦涩的**{v.}++遮掩，遮蔽；使费解**{n.}++某种模糊的或不清楚的东西**{v.}++make less visible or unclear																										        				&quot;The stars are obscured by the clouds&quot;															   	同义词：								                                  				    befog				    				    				      				    				      				    				                                      				    becloud				    				    				      				    				      				    				                                      				    obnubilate				    				    				      				    				      				    				                                      				    haze over				    				    				      				    				      				    				                                      				    fog				    				    				      				    				      				    				                                      				    cloud				    				    				      				    				      				    				                                      				    mist**{adj.}++模糊的；晦涩的；[光]昏暗的**{vt.}++遮掩；使变暗；使难理解**', '');
