INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('orient', '[ˈɔːrient]', 'http://dict.youdao.com/dictvoice?audio=orient', '{v.}++朝向，面对，使适合；定向放置（某物）；确定方位，认识方向（orient oneself）；引导；使熟悉，帮助适应**{n.}++东方，东亚诸国（the Orient）；（优质珍珠的）光泽；优质珍珠**{adj.}++东方的，东方国家的；（尤指宝石）光彩夺目的；（太阳等）冉冉上升的，（白昼的光亮等）渐渐变强的**{n.}++the countries of Asia																					   	同义词：								                                  				    East**{vt.}++使适应；确定方向；使朝东**{n.}++东方；东方诸国**{adj.}++东方的**{vi.}++向东**', '');
