INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('otherwise', '[ˈʌðərwaɪz]', 'http://dict.youdao.com/dictvoice?audio=otherwise', '{adv.}++否则，不然；除此以外，在其他方面；不同地，另外地；以其他方式，用别的方法**{adj.}++不是那样的，另外情况下的**{adj.}++other than as supposed or expected																										        				&quot;the outcome was otherwise&quot;**{adv.}++in other respects or ways																										        													        													        				&quot;he is otherwise normal&quot;; &quot;the funds are not otherwise available&quot;; &quot;an otherwise hopeless situation&quot;**{adv.}++否则；另外；在其他方面**{adj.}++另外的；其他方面的**', '');
