INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('outside', '[ˌaʊtˈsaɪd]', 'http://dict.youdao.com/dictvoice?audio=outside', '{n.}++外表，外部（the outside）；（建筑物、车辆等的）周围，外围（the outside）；（人行道的）外侧；（弯曲路面或轨道的）外道，边缘；一令纸的上下两张（outsides）；局外（人士），外界（人士）**{prep.}++在……的外面，在户外；超出……的范围（或界限）；（团体或组织）以外的；除了，除……之外（outside of）**{adv.}++在外面；在户外，在四周；在外侧，表面上**{adj.}++外边的，表面的；（曲棍球、足球等）边锋的；（建筑物）外围的，四周的；不属于本团体（或机构、国家等）的，不相关的；（可能性）极微小的，不大可能的；（车道）靠近路中间的，快车道的**{n.}++the region that is outside of something																					   	同义词：								                                  				    exterior**{adj.}++外面的，[计]外部的；外来的**{n.}++[计]外部；外观**{adv.}++在外面，向外面；在室外**{prep.}++在…范围之外**', '');
