INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('over', '[ˈoʊvər]', 'http://dict.youdao.com/dictvoice?audio=over', '{adv.}++向下，倒下；翻过，翻转；越过；超过，以上；完全覆盖；在上方；剩下，余下；再，又；改变，掉换；结束，完；去，到（某处）；很，太；仔细地；度过一段时间**{prep.}++盖在……上面；悬在……上面；从一边到另一边；翻越；在……的对面；从……落下；遍及；超过，多于；控制，支配；在……期间；渡过（难关等）；由于，关于；利用，通过；声音大于；胜过，优于；尽管；漏掉，略过；除以**{n.}++（板球）一轮投球**{adj.}++结束的；剩下的**{v.}++越过**{adj.}++having come or been brought to a conclusion																										        				&quot;the affair is over, ended, finished&quot;															   	同义词：								                                  				    complete				    				    				      				    				      				    				                                      				    concluded				    				    				      				    				      				    				                                      				    ended				    				    				      				    				      				    				                                      				    all over				    				    				      				    				      				    				                                      				    terminated**{adv.}++at or to a point across intervening space etc.																										        													        				&quot;come over and see us some time&quot;; &quot;over there&quot;**{adv.}++结束；越过；从头到尾**{prep.}++越过；在…之上；遍于…之上**{adj.}++结束的；上面的**{vt.}++越过**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('overall', '[ˌoʊvərˈɔːl]', 'http://dict.youdao.com/dictvoice?audio=overall', '{adj.}++总的，全面的；所有的，包括一切的**{adv.}++全部，总共； 总的说来，大体上**{n.}++（工作时穿的）罩衣；（上下连身的）工作服，防护服（overalls）；背带工装裤（overalls）；骑马裤，紧身制服裤（overalls）**{n.}++(usually plural) work clothing consisting of denim trousers (usually with a bib and shoulder straps)**{adj.}++全部的；全体的；一切在内的**{adv.}++全部地；总的说来**{n.}++工装裤；罩衫**', '');
