INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('overwhelm', '[ˌoʊvərˈwelm]', 'http://dict.youdao.com/dictvoice?audio=overwhelm', '{v.}++（感情上）使受不了，使不知所措；使大吃一惊；压垮，使应接不暇；打败，击垮； （水）漫过，淹没；压倒，制服**{v.}++overcome, as with emotions or perceptual stimuli																					   	同义词：								                                  				    overpower				    				    				      				    				      				    				                                      				    sweep over				    				    				      				    				      				    				                                      				    whelm				    				    				      				    				      				    				                                      				    overcome				    				    				      				    				      				    				                                      				    overtake**{vt.}++压倒；淹没；受打击**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('overwhelming', '[ˌoʊvərˈwelmɪŋ]', 'http://dict.youdao.com/dictvoice?audio=overwhelming', '{adj.}++难以抗拒的，令人不知所措的；巨大的，压倒性的**{v.}++（感情上）使受不了，使不知所措；压垮，使应接不暇；打败，击垮（overwhelm 的现在分词形式）**{adj.}++so strong as to be irresistible																										        													        				&quot;the temptation to despair may become overwhelming&quot;; &quot;an overwhelming majority&quot;															   	同义词：								                                  				    overpowering**{adj.}++压倒性的；势不可挡的**{v.}++压倒；淹没（overwhelm的ing形式）；制服**', '');
