INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('pace', '[peɪs]', 'http://dict.youdao.com/dictvoice?audio=pace', '{n.}++步速，（移动的）速度；（发生、进展、发展的）速度，节奏；一步，一步之距；（马行走或奔跑的）步法；步态；快节奏；快跑的能力；（板球）（影响球速的）两个三柱门之间的场地状况**{v.}++（因担忧、紧张或不耐烦而）踱步，踱步于；（在赛跑中）为……定速度；为……领跑；为（书、电影等中的故事）设定节奏；调整自己的工作（或活动）节奏；步测；（马）走侧对步（主见于专门饲养或训练的马）**{prep.}++（用于人名前，委婉提出不同意见）请……原谅**{n.}++the rate of moving (especially walking or running)																					   	同义词：								                                  				    gait**{a unit of length equal to 3 feet; defined as 91.}++44 centimeters; originally taken to be the average length of a stride																					   	同义词：								                                  				    yard**{n.}++一步；步速；步法**', '');
