INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('peak', '[piːk]', 'http://dict.youdao.com/dictvoice?audio=peak', '{n.}++巅峰，顶点；山顶；有尖峰的山；尖端，尖顶；帽檐，帽舌；极值，峰值；（艏或艉的）尖舱；斜桁外端，（帆的）后上角**{v.}++达到高峰，达到最大值；消瘦，衰弱，精神萎靡**{adj.}++巅峰状态的，最高的；高峰时期的**{n.}++the most extreme possible amount or value																										        				&quot;voltage peak&quot;															   	同义词：								                                  				    extremum**{n.}++山峰；最高点；顶点；[服装]帽舌**{vt.}++使达到最高点；使竖起**{vi.}++消瘦；到达最高点；变憔悴**{adj.}++最高的；最大值的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('peck', '[pek]', 'http://dict.youdao.com/dictvoice?audio=peck', '{v.}++啄，啄食；匆匆轻吻；缓慢而费力地用打字机打；（马）向前跌倒**{n.}++匆匆的轻吻；（鸟的）啄；配克（谷物、水果等的干量单位，等于8夸脱）；啄痕**{n.}++(often followed by `of) a large number or amount or extent																					   	同义词：								                                  				    batch				    				    				      				    				      				    				                                      				    deal				    				    				      				    				      				    				                                      				    flock				    				    				      				    				      				    				                                      				    good deal				    				    				      				    				      				    				                                      				    great deal				    				    				      				    				      				    				                                      				    hatful				    				    				      				    				      				    				                                      				    heap				    				    				      				    				      				    				                                      				    lot				    				    				      				    				      				    				                                      				    mass				    				    				      				    				      				    				                                      				    mess				    				    				      				    				      				    				                                      				    mickle				    				    				      				    				      				    				                                      				    mint				    				    				      				    				      				    				                                      				    muckle				    				    				      				    				      				    				                                      				    pile				    				    				      				    				      				    				                                      				    plenty				    				    				      				    				      				    				                                      				    pot				    				    	