INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('pedal', '[ˈped(ə)l]', 'http://dict.youdao.com/dictvoice?audio=pedal', '{n.}++（自行车、汽车或机器的）脚踏板；(钢琴、风琴等的)踏板；（乐）PEDAL NOTE的简称**{v.}++骑自行车前进；踩（自行车等的）踏板；（尤指以某种特别方式）踩动钢琴踏板**{adj.}++踏板的，脚踏的；脚的，关于脚的**{n.}++a sustained bass note																					   	同义词：								                                  				    pedal point**{vi.}++踩踏板；骑车**{n.}++踏板；脚蹬子**{vt.}++骑（自行车）；踩……的踏板**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('pedestrian', '[pəˈdestriən]', 'http://dict.youdao.com/dictvoice?audio=pedestrian', '{n.}++步行者，行人**{adj.}++平淡无奇的，乏味的；行人的，行人使用的；徒步的**{n.}++a person who travels by foot																					   	同义词：								                                  				    walker				    				    				      				    				      				    				                                      				    footer**{adj.}++lacking wit or imagination																										        				&quot;a pedestrian movie plot&quot;															   	同义词：								                                  				    prosaic				    				    				      				    				      				    				                                      				    prosy				    				    				      				    				      				    				                                      				    earthbound**{adj.}++徒步的；缺乏想像力的**{n.}++行人；步行者**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('pedlar', '[ˈpedlər]', 'http://dict.youdao.com/dictvoice?audio=pedlar', '{n.}++[贸易]小贩；传播者（等于 peddler）**{n.}++someone who travels about selling his wares (as on the streets or at carnivals)																					   	同义词：								                                  				    peddler				    				    				      				    				      				    				                                      				    packman				    				    				      				    				      				    				                                      				    hawker				    				    				      				    				      				    				                                      				    pitchman**{n.}++[贸易]小贩；传播者（等于peddler）**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('peel', '[piːl]', 'http://dict.youdao.com/dictvoice?audio=peel', '{v.}++除去，剥去（水果、蔬菜等的）皮；去掉，剥掉，揭掉；剥落，脱落，脱皮；（水果，蔬菜）有可被除掉的皮；（槌球）把（另一球员的球）传过拱门**{n.}++（水果、蔬菜的）皮，外皮；去角质；（16世纪时建在英格兰和苏格兰交界各郡的）堡塔，堡寨**{n.}++the tissue forming the hard outer layer (of e.g. a fruit)																					   	同义词：								                                  				    skin				    				    				      				    				      				    				                                      				    rind**{v.}++剥，剥落；削**{n.}++[植]皮**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('peer', '[pɪr]', 'http://dict.youdao.com/dictvoice?audio=peer', '{n.}++同龄人，同等地位的人，相匹敌的人；（英国）贵族**{v.}++凝视，费力地看；隐现；看见；匹敌**{n.}++a person who is of equal standing with another in a group																					   	同义词：								                                  				    equal				    				    				      				    				      				    				                                      				    match				    				    				      				    				      				    				                                      				    compeer**{vi.}++凝视，盯着看；窥视**{n.}++贵族；同等的人**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('penalty', '[ˈpenəlti]', 'http://dict.youdao.com/dictvoice?audio=penalty', '{n.}++（因违反法律、规定或合同而受到的）处罚，刑罚；（行为、环境带来的）不利后果，苦难；（体育运动中对犯规者的）判罚，处罚；（足球、橄榄球及类似运动中的）罚球；（桥牌）（叫牌者未完成定约时的）罚分**{n.}++the act of punishing																					   	同义词：								                                  				    punishment				    				    				      				    				      				    				                                      				    penalization				    				    				      				    				      				    				                                      				    penalisation**{n.}++[经]罚款，罚金；[法]处罚**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('penetration', '[ˌpenəˈtreɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=penetration', '{n.}++穿透，渗透，进入；（产品对市场的）渗透度，占有率；（某种信仰在某一社会的）渗透；（为刺探情报对某团体、企业等的）渗入；洞察力；（阴茎的）插入**{n.}++an attack that penetrates into enemy territory																					   	同义词：								                                  				    incursion**{n.}++渗透；突破；侵入；洞察力**', '');
