INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('perception', '[pərˈsepʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=perception', '{n.}++看法，认识；感觉，感知；洞察力；（租金、农作物等的）收取，占有**{n.}++the representation of what is perceived; basic component in the formation of a concept																					   	同义词：								                                  				    percept				    				    				      				    				      				    				                                      				    perceptual experience**{n.}++知觉；[生理]感觉；看法；洞察力；获取**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('perch', '[pɜːrtʃ]', 'http://dict.youdao.com/dictvoice?audio=perch', '{v.}++（鸟）栖息，停留；（尤指人在高处或很窄的地方）稍坐，暂歇；（建筑物）坐落于……的上方（或边缘）；把……平稳置于，使坐落于**{n.}++（鸟的）栖木，栖枝；高处，高位；河鲈，鲈鱼；杆（尤指用来测量土地长度的单位）**{n.}++support consisting of a branch or rod that serves as a resting place (especially for a bird)**{a linear measure of 16.}++5 feet																					   	同义词：								                                  				    rod				    				    				      				    				      				    				                                      				    pole**{n.}++高位；栖木；杆**{vt.}++栖息；就位；位于；使坐落于**{vi.}++栖息；就位；位于**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('perfect', '[ˈpɜːrfɪkt]', 'http://dict.youdao.com/dictvoice?audio=perfect', '{adj.}++无瑕的，完好的；完全正确的，极其准确的；完美的，理想的；最佳的，绝配的；十足的，完全的；通常的，大体的；（语法）完成时的，完成式的；（数字）完全的；（花）有雌雄蕊的；（昆虫）性成熟的；（真菌）有性孢子形成阶段的，有性的；完成时的，完成式的**{v.}++完善，使完美；双面印完（一页纸）；使（礼物、头衔等）合法转移**{n.}++（语法）完成时，完成体**{n.}++a tense of verbs used in describing action that has been completed (sometimes regarded as perfective aspect)																					   	同义词：								                                  				    perfective				    				    				      				    				      				    				                                      				    perfective tense				    				    				      				    				      				    				                                      				    perfect tense**{v.}++make perfect or complete																										        				&quot;perfect your French in Paris!&quot;															   	同义词：								                                  				    hone**{adj.}++being complete of its kind and without defect or blemish																										        													        													        													        													        													        				&quot;a perfect circle&quot;; &quot;a perfect reproduction&quot;; &quot;perfect happiness&quot;; &quot;perfect manners&quot;; &quot;a perfect specimen&quot;; &quot;a perfect day&quot;**{adj.}++完美的；最好的；精通的**{vt.}++使完美；使熟练**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('perfection', '[pərˈfekʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=perfection', '{n.}++完美；完善；完美的人（或物）**{n.}++the state of being without a flaw or defect																					   	同义词：								                                  				    flawlessness				    				    				      				    				      				    				                                      				    ne plus ultra**{n.}++完善；完美**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('peril', '[ˈperəl]', 'http://dict.youdao.com/dictvoice?audio=peril', '{n.}++巨大的危险，危难；（某活动或行为的）危险，问题**{v.}++使有危险，使临险境，危及**{n.}++a source of danger; a possibility of incurring loss or misfortune																					   	同义词：								                                  				    hazard				    				    				      				    				      				    				                                      				    jeopardy				    				    				      				    				      				    				                                      				    risk				    				    				      				    				      				    				                                      				    endangerment**{n.}++[安全]危险；冒险**{vt.}++危及；置…于险境**', '');
