INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('periodical', '[ˌpɪriˈɑːdɪk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=periodical', '{n.}++（尤指学术）期刊**{adj.}++间发性的，定期的，周期的；（杂志，报纸）定期出版的**{n.}++a publication that appears at fixed intervals**{adj.}++happening or recurring at regular intervals																					   	同义词：								                                  				    periodic**{adj.}++[数]周期的；定期的**{n.}++期刊；杂志**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('peripheral', '[pəˈrɪfərəl]', 'http://dict.youdao.com/dictvoice?audio=peripheral', '{adj.}++次要的，附带的；外围的，周边的；（计算机设备）外围的；（剖）体表的；周围神经系统的，末梢的**{n.}++（计算机的）外部设备**{n.}++(computer science) electronic equipment connected by cable to the CPU of a computer																										        				&quot;disk drives and printers are important peripherals&quot;															   	同义词：								                                  				    computer peripheral				    				    				      				    				      				    				                                      				    peripheral device**{adj.}++on or near an edge or constituting an outer boundary; the outer area																										        													        				&quot;Russias peripheral provinces&quot;; &quot;peripheral suburbs&quot;**{adj.}++[昆][计]外围的；次要的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('perish', '[ˈperɪʃ]', 'http://dict.youdao.com/dictvoice?audio=perish', '{v.}++（人或动物）惨死，猝死；湮灭，毁灭；（木头、橡胶、食物等）腐烂，腐败； 经受酷寒**{v.}++pass from physical life and lose all bodily attributes and functions necessary to sustain life																										        				&quot;They children perished in the fire&quot;															   	同义词：								                                  				    die				    				    				      				    				      				    				                                      				    decease				    				    				      				    				      				    				                                      				    go				    				    				      				    				      				    				                                      				    exit				    				    				      				    				      				    				                                      				    pass away				    				    				      				    				      				    				                                      				    expire				    				    				      				    				      				    				                                      				    pass				    				    				      				    				      				    				                                      				    kick the bucket				    				    				      				    				      				    				                                      				    cash in one&#39;s chips				    				    				      				    				      				    				                                      				    buy the farm				    				    				      				    				      				    				                                      				    conk				    				    				      				    				      				    				                                      				    give-up the ghost				    				    				      				    				      				    				                                      				    drop dead				    				    				      				    				      				    				                                      				    pop off				    				    				      				    				      				    				                                      