INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('perpendicular', '[ˌpɜːrpənˈdɪkjələr]', 'http://dict.youdao.com/dictvoice?audio=perpendicular', '{adj.}++垂直的，直立的，成直角的；（14、15世纪英格兰教堂）垂直式装饰风格的；（带斜面的物体）陡峭的，陡立的**{n.}++垂线，垂直线，垂直姿态**{n.}++a straight line at right angles to another line**{adj.}++[数]垂直的，正交的；直立的；陡峭的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('perpetual', '[pərˈpetʃuəl]', 'http://dict.youdao.com/dictvoice?audio=perpetual', '{adj.}++长期的，永恒的；连续不断的，重复不停的；（职位、工作或战利品）终身的；（投资）永不还本的；（植物）四季开花的，四季结果的**{adj.}++continuing forever or indefinitely																										        				&quot;hells perpetual fires&quot;															   	同义词：								                                  				    ageless				    				    				      				    				      				    				                                      				    aeonian				    				    				      				    				      				    				                                      				    eonian				    				    				      				    				      				    				                                      				    eternal				    				    				      				    				      				    				                                      				    everlasting				    				    				      				    				      				    				                                      				    unending				    				    				      				    				      				    				                                      				    unceasing**{adj.}++永久的；不断的；四季开花的；无期限的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('perplex', '[pərˈpleks]', 'http://dict.youdao.com/dictvoice?audio=perplex', '{v.}++使困惑，使茫然；使复杂化**{v.}++be a mystery or bewildering to																					   	同义词：								                                  				    vex				    				    				      				    				      				    				                                      				    stick				    				    				      				    				      				    				                                      				    get				    				    				      				    				      				    				                                      				    puzzle				    				    				      				    				      				    				                                      				    mystify				    				    				      				    				      				    				                                      				    baffle				    				    				      				    				      				    				                                      				    beat				    				    				      				    				      				    				                                      				    pose				    				    				      				    				      				    				                                      				    bewilder				    				    				      				    				      				    				                                      				    flummox				    				    				      				    				      				    				                                      				    stupefy				    				    				      				    				      				    				                                      				    nonplus				    				    				      				    				      				    				                                      				    gravel				    				    				      				    				      				    				                                      				    amaze				    				    				      				    				      				    				                                      				    dumbfound**{vt.}++使困惑，使为难；使复杂化**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('persecute', '[ˈpɜːrsɪkjuːt]', 'http://dict.youdao.com/dictvoice?audio=persecute', '{v.}++（尤指因种族、宗教或政治信仰而）迫害，残害；骚扰，纠缠**{v.}++cause to suffer																										        				&quot;Jews were persecuted in the former Soviet Union&quot;															   	同义词：								                                  				    oppress**{vt.}++迫害；困扰；同…捣乱**', '');
