INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('pitch', '[pɪtʃ]', 'http://dict.youdao.com/dictvoice?audio=pitch', '{n.}++体育场地，球场；程度，强度；音准，音高；推销用语；投球；沥青，柏油；（船或飞机的）颠簸；倾斜度，高度；摊位，（街头艺人的）表演场所；（高尔夫）下旋高球；露营地；（技）螺距，节距**{v.}++扔，抛，掷；（棒球中）投（球）；击地，（使球）定点落地；重跌，坠落；（船或飞机）颠簸；把……定于某水平；使（产品）针对，面向；推销；为……定音高；向下倾斜；扎，搭建；（高尔夫）击下旋高球；用石头铺（路）；（酿酒用语）给（麦芽汁）加酵母；盖上沥青，涂上沥青**{n.}++the property of sound that varies with variation in the frequency of vibration**{vi.}++倾斜；投掷；搭帐篷；坠落**{vt.}++投；掷；定位于；用沥青涂；扎营；向前倾跌**{n.}++沥青；音高；程度；[松脂]树脂；倾斜；投掷**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('plague', '[pleɪɡ]', 'http://dict.youdao.com/dictvoice?audio=plague', '{n.}++瘟疫，传染病；鼠疫（尤指腺鼠疫）；（老鼠或昆虫等肆虐造成的）灾害，祸患； 普遍的祸害；烦恼事；愿上天降灾难于……（a plague on）**{v.}++困扰，折磨；烦扰，纠缠；使得灾祸**{n.}++a serious (sometimes fatal) infection of rodents caused by Yersinia pestis and accidentally transmitted to humans by the bite of a flea that has bitten an infected animal																					   	同义词：								                                  				    pestilence				    				    				      				    				      				    				                                      				    pest				    				    				      				    				      				    				                                      				    pestis**{n.}++[医]瘟疫；灾祸；麻烦；讨厌的人**{vt.}++折磨；使苦恼；使得灾祸**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('plain', '[pleɪn]', 'http://dict.youdao.com/dictvoice?audio=plain', '{adj.}++无装饰的，朴素的；单色的，无花纹的；单纯的，不掺杂的；显而易见的；（书面或口头用法）表达清楚的；直截了当的，坦率的；相貌平平的；普通的；直呼其名的；完全的；（编织）平针的**{adv.}++完全地，简直；明白地，不含糊地**{n.}++（大）平原；（编织的）平针；朴实无华的东西**{n.}++extensive tract of level open land																										        				&quot;they emerged from the woods onto a vast open plain&quot;															   	同义词：								                                  				    field				    				    				      				    				      				    				                                      				    champaign**{adj.}++平的；简单的；朴素的；清晰的**{n.}++[地理]平原；无格式；朴实无华的东西**{adv.}++清楚地；平易地**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('plastic', '[ˈplæstɪk]', 'http://dict.youdao.com/dictvoice?audio=plastic', '{n.}++塑料；信用卡；塑胶制造业（plastics）；塑料学（plastics）**{adj.}++塑料制的；人造的，不自然的；可塑的；（艺术用语）造型的，塑造的；（科技用语）范性的，塑性的；适应环境多样性的**{n.}++generic name for certain synthetic or semisynthetic materials that can be molded or extruded into objects or films or filaments or used for making e.g. coatings and adhesives**{adj.}++capable of being molded or modeled (especially of earth or clay or other soft material)																										        				&quot;plastic substances such as wax or clay&quot;															   	同义词：								                                  				    fictile				    				    				      				    				      				    				                                      				    moldable**{adj.}++[塑料][力]塑料的；（外科）造型的；可塑的**{n.}++[塑料]塑料制品；整形；[力]可塑体**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('plateau', '[plæˈtoʊ]', 'http://dict.youdao.com/dictvoice?audio=plateau', '{n.}++高原；（发展、增长后的）稳定期，停滞期；高原印第安人；托盘**{v.}++（在一段时间的发展之后）趋于平稳，进入停滞期**{n.}++a relatively flat highland																					   	同义词：								                                  				    tableland**{n.}++[地理]高原；稳定水平；托盘；平顶女帽**{vi.}++达到平衡；达到稳定时期**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('platform', '[ˈplætfɔːrm]', 'http://dict.youdao.com/dictvoice?audio=platform', '{n.}++平台；讲台，舞台；讲台上的人（the platform）；（火车站的）月台；（公共汽车上供乘客上下车的）踏脚台；发言机会，论坛；契机；（政党的）纲领；厚底鞋；计算机平台；（海上）钻井平台；（供人上下小船的）水上平台；（火箭或导弹的）卫星发射平台**{n.}++a raised horizontal surface																										        				&quot;the speaker mounted the platform&quot;**{n.}++[计][矿业]平台；月台，[铁路]站台；坛；[家具]讲台**', '');
