INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('pop', '[pɑːp]', 'http://dict.youdao.com/dictvoice?audio=pop', '{adj.}++流行音乐的；通俗的，大众的**{n.}++流行音乐；砰的响声； 汽水； 爸爸；鲜艳的一小块；（一系列事情中的）一次，一项；（棒球）小腾空球；打，敲击； 通俗古典乐，流行古典乐（pops）； 尝试，努力； 批评；老人家（用作称呼）（pops）；枪击**{v.}++（使）砰地爆开，砰地脱落；迅速去，短暂逗留；突然出现，短暂出现； 突然放置，迅速放入；（使）发出砰的响声，（使）啪的一声爆裂；（因飞机起飞、降落或上下陡坡等）耳压变化，耳胀；（因惊讶或兴奋而）瞪大眼睛； 过于频繁地服用（药片）；打（某人）；爆（玉米花）；击出小腾空球；射击，开枪；打开瓶子喝（啤酒）； 典当，抵押**{adv.}++砰的响声（go pop）**{abbr.}++邮局协议 （post office protocol）；人口 （population）**{n.}++an informal term for a father; probably derived from baby talk																					   	同义词：								                                  				    dad				    				    				      				    				      				    				                                      				    dada				    				    				      				    				      				    				                                      				    daddy				    				    				      				    				      				    				                                      				    pa				    				    				      				    				      				    				                                      				    papa				    				    				      				    				      				    				                                      				    pappa**{n.}++流行音乐；汽水；砰然声；枪击**{vi.}++突然出现；爆开；射击；瞪大；发出爆裂声**{vt.}++取出；开枪打；抛出；突然伸出；突然行动**{adj.}++流行的；通俗的；热门的**{adv.}++突然；砰地**', '');
