INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('positive', '[ˈpɑːzətɪv]', 'http://dict.youdao.com/dictvoice?audio=positive', '{adj.}++乐观的，有信心的；积极的，建设性的；良好的，有助益的；赞成的，支持的；确信的，肯定的；完全的，绝对的；证据确凿的，明确的；阳性的；正数的，大于零的；正电的，正极的；（摄影）正片的，正像的；（语法）（形容词，副词）原级的；（主哲）实证的，实在的；（占星）（风宫，火宫）积极的**{n.}++优势，优点；阳性结果；正片；正极，阳极；正数；（语法）原级形容词，原级副词**{n.}++a film showing a photographic image whose tones correspond to those of the original subject**{adj.}++characterized by or displaying affirmation or acceptance or certainty etc.																										        													        													        													        				&quot;a positive attitude&quot;; &quot;the reviews were all positive&quot;; &quot;a positive benefit&quot;; &quot;a positive demand&quot;**{adj.}++[电]积极的；[摄][物][数]正的，[化学][医]阳性的；确定的，肯定的；实际的，真实的；绝对的**', '');
