INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('prick', '[prɪk]', 'http://dict.youdao.com/dictvoice?audio=prick', '{v.}++扎，戳；使（身体某部位）刺痛；使……感到内疚（或尴尬）；驱使，驱策；（动物）竖起（耳朵）**{n.}++扎，穿刺；针刺感，刺痛（感）；蠢材，笨蛋，讨厌的家伙；一阵不快；阴茎；赶牛棒**{n.}++insulting terms of address for people who are stupid or irritating or ridiculous																					   	同义词：								                                  				    asshole				    				    				      				    				      				    				                                      				    bastard				    				    				      				    				      				    				                                      				    cocksucker				    				    				      				    				      				    				                                      				    dickhead				    				    				      				    				      				    				                                      				    shit				    				    				      				    				      				    				                                      				    mother fucker				    				    				      				    				      				    				                                      				    motherfucker				    				    				      				    				      				    				                                      				    whoreson				    				    				      				    				      				    				                                      				    son of a bitch				    				    				      				    				      				    				                                      				    SOB**{vt.}++刺，戳；刺伤，刺痛；竖起**{n.}++刺，扎；刺痛，刺伤；阴茎；锥**{vi.}++刺；竖起**{adj.}++竖起的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('primitive', '[ˈprɪmətɪv]', 'http://dict.youdao.com/dictvoice?audio=primitive', '{adj.}++原始的，远古的；（器物等）粗糙的，简陋的；（人、动物或植物发展）早期的；（行为，思想，情感）本能的，自然的；（艺术风格）朴实无华的；原来的，原有的；（语言学）根词的，非派生的；（数）（代数或几何表达式）本原的；（生）原生的**{n.}++原始人，未开化的土人；原始派艺术家（或其作品）；文艺复兴前的艺术家（或作品），模仿文艺复兴前艺术风格的现代画家；早期风格物品；词根，原（词）素；（数）基本式，初基；（计算机）图元，原语**{n.}++a person who belongs to an early stage of civilization																					   	同义词：								                                  				    primitive person**{adj.}++[数][生物][地质]原始的，远古的；简单的，粗糙的**{n.}++[数][生物][地质]原始人**', '');
