INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('probe', '[proʊb]', 'http://dict.youdao.com/dictvoice?audio=probe', '{v.}++调查，打探，探究；（用手指、细长工具等）探查，查看；搜寻，探索；侦察，侦探（敌情）**{n.}++探究，详尽调查；（医生和科学家用的）探针； 航天探测器，太空探测器（=space probe）；探测仪，传感器，取样器**{n.}++an inquiry into unfamiliar or questionable activities																										        				&quot;there was a congressional probe into the scandal&quot;															   	同义词：								                                  				    investigation**{n.}++[电子][医]探针；调查**{vi.}++调查；[航]探测**{vt.}++探查；用探针探测**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('proceeding', '[prəˈsiːdɪŋ]', 'http://dict.youdao.com/dictvoice?audio=proceeding', '{n.}++诉讼，诉讼程序；事件，（一连串）发生的事（the proceedings/the proceeding）；（会议等的）正式记录（proceedings）；（会议、仪式等）议程，活动过程（proceedings）**{v.}++开始行动，开展；继续做（或从事，进行）；（完成其他事后）继续做某事（proceed 的现在分词）**{n.}++(law) the institution of a sequence of steps by which legal judgments are invoked																					   	同义词：								                                  				    legal proceeding				    				    				      				    				      				    				                                      				    proceedings**{n.}++进行；程序；诉讼；事项**{v.}++开始；继续做；行进（proceed的ing形式）**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('producer', '[prəˈduːsər]', 'http://dict.youdao.com/dictvoice?audio=producer', '{n.}++生产者制造商，生产公司（国）；（人或物）造成者，生产者；（电影、广播戏剧、歌剧等的）制片主任，监制人；（音乐录音的）监制人；发生器**{n.}++someone who manufactures something																					   	同义词：								                                  				    manufacturer**{n.}++制作人，制片人；[劳经][生态]生产者；发生器**', '');
