INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('proper', '[ˈprɑːpər]', 'http://dict.youdao.com/dictvoice?audio=proper', '{adj.}++真正的，像样的；实际上的，严格意义上的；正确的，合适的；合理的，合乎体统的；非常有礼貌的，循规蹈矩的； 特有的，专有的；完全的，彻底的； 用于强调地道的；（圣诗、教义、祷词等）用于某特定场合的；（纹章）原色的；（数）真的，正常的**{adv.}++完全地，彻底地； 正确地，恰当地**{n.}++特定季节（或节日）的礼仪**{adj.}++marked by suitability or rightness or appropriateness																										        													        				&quot;proper medical treatment&quot;; &quot;proper manners&quot;**{adj.}++适当的；本身的；特有的；正派的**{adv.}++完全地**', '');
