INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('puff', '[pʌf]', 'http://dict.youdao.com/dictvoice?audio=puff', '{v.}++吸，抽（烟、烟斗等）；吹，喷出；（尤指跑步、攀登之后）气喘吁吁，喘息；喷着汽（或烟）移动；（尤指显得很愚蠢地）咆哮，怒吼；膨胀；吹捧**{n.}++吸烟；（烟、气等的）一缕；（空气或蒸汽突然喷射发出的）噗的一声；（蒸汽，烟雾的）一喷；吐气，喘气；（充足的）气息，气力；泡芙；吹捧文字；（尤指夸大产品价值的）广告；（裙子等的）泡泡裥；蓬松隆起的卷绕发型；鸭绒被；粉扑**{n.}++a short light gust of air																					   	同义词：								                                  				    puff of air				    				    				      				    				      				    				                                      				    whiff**{vt.}++喷出，张开；使膨胀；夸张；使骄傲自满**{vi.}++膨胀；张开；鼓吹；夸张**{n.}++粉扑；泡芙；蓬松；一阵喷烟；肿块；吹嘘，宣传广告**', '');
