INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('punch', '[pʌntʃ]', 'http://dict.youdao.com/dictvoice?audio=punch', '{n.}++一拳，一击；（出拳打击时所需要的）力量；感染力，活力；打孔器，穿孔机；孔洞；压印器，冲压机；潘趣酒（由果汁和酒制成的甜味饮品）；庞奇（奇形怪状、钩鼻、驼背的小丑，木偶戏《庞奇和朱迪》中的男主角）（Punch）；（矮壮的）萨福克驮马（Suffolk punch）；（矮壮的）萨福克驮马（Suffolk punch）**{v.}++用拳猛击（某人或某物）；按（按钮或键）；（用工具或机器）打孔，扎眼；（用刺棒）赶（牲口）；（用刺棒）赶（牲口）**{n.}++(boxing) a blow with the fist																					   	同义词：								                                  				    clout				    				    				      				    				      				    				                                      				    poke				    				    				      				    				      				    				                                      				    lick				    				    				      				    				      				    				                                      				    biff**{n.}++[机]冲压机；打洞器；[计]钻孔机**{vi.}++用拳猛击**', '');
