INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('qualification', '[ˌkwɑːlɪfɪˈkeɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=qualification', '{n.}++（通过考试或学习课程取得的）资格，学历；（胜任某一工作或职位所需的）资历，技能条件；获得资格，达到标准；先决条件，正式要求；限制，限定性条件；（语法）（尤指对名词等的）限定，修饰**{n.}++an attribute that must be met or complied with and that fits a person for something																										        													        				&quot;her qualifications for the job are excellent&quot;; &quot;one of the qualifications for admission is an academic degree&quot;															   	同义词：								                                  				    making**{n.}++资格；条件；限制；赋予资格**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('qualify', '[ˈkwɑːlɪfaɪ]', 'http://dict.youdao.com/dictvoice?audio=qualify', '{v.}++（使）有权去做；取得资格，达到标准；获得参赛资格；使合格，胜任；符合，可算作；具体说明，使语气缓和；修饰，限定**{v.}++prove capable or fit; meet requirements																					   	同义词：								                                  				    measure up**{vt.}++限制；使具有资格；证明…合格**{vi.}++取得资格，有资格**', '');
