INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('quench', '[kwentʃ]', 'http://dict.youdao.com/dictvoice?audio=quench', '{v.}++（喝水）止（渴）；满足（欲望）；扑灭，熄灭（火）；抑制，压制（感情）；（尤指用冷水或油）将……淬火，使冷却；控制（发光、震动或放电等效果）**{n.}++淬火**{v.}++satisfy (thirst)																										        				&quot;The cold water quenched his thirst&quot;															   	同义词：								                                  				    slake				    				    				      				    				      				    				                                      				    allay				    				    				      				    				      				    				                                      				    assuage**{vt.}++熄灭，[机]淬火；解渴；结束；冷浸**{vi.}++熄灭；平息**', '');
