INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('radial', '[ˈreɪdiəl]', 'http://dict.youdao.com/dictvoice?audio=radial', '{adj.}++辐射状的；（身体）中心区域的；桡骨的**{n.}++子午线轮胎；辐射道路；鳍辐骨；星形发动机**{n.}++pneumatic tire that has radial-ply casing																					   	同义词：								                                  				    radial tire				    				    				      				    				      				    				                                      				    radial-ply tire**{adj.}++relating to or near the radius																										        				&quot;the radial aspect of the forearm&quot;**{adj.}++半径的；放射状的；光线的；光线状的**{n.}++[物]射线，光线**', '');
