INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('radical', '[ˈrædɪk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=radical', '{adj.}++根本的，彻底的；激进的，极端的；全新的，不同凡响的；（增减）急剧的，大幅度的；（人，物）原本的，与生俱来的；顶呱呱的；（外科，医疗）根治的；（19世纪）自由党激进派的；（数）根式的，根号的；词根的；（植）根生的**{n.}++激进分子； 游离基，自由基；词根；（汉字）偏旁，部首；（数）根式；根号**{n.}++(chemistry) two or more atoms bound together as a single unit and forming part of a molecule																					   	同义词：								                                  				    group				    				    				      				    				      				    				                                      				    chemical group**{adj.}++激进的；根本的；彻底的**{n.}++基础；激进分子；[物化]原子团；[数]根数**', '');
