INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('raise', '[reɪz]', 'http://dict.youdao.com/dictvoice?audio=raise', '{v.}++提起，举起；（使）直立，站立；建造，树立（塑像等）；增加，提高；筹募，征集；提出，提起；引起，使出现；饲养，种植；抚养，养育；使自乘……次；比（对手）多下赌注；叫醒；使复活；终止，解除；与……取得联系；（海上人员）驶近能看见（陆地或其他船只）的地方；（免疫）刺激（抗血清、抗体等的）生成**{n.}++加薪；（扑克牌或勃莱格牌用语）赌注加码；（举重）（持杠铃时的）提，举**{n.}++the amount a salary is increased																										        				&quot;he got a 3% raise&quot;															   	同义词：								                                  				    rise				    				    				      				    				      				    				                                      				    wage hike				    				    				      				    				      				    				                                      				    hike				    				    				      				    				      				    				                                      				    wage increase				    				    				      				    				      				    				                                      				    salary increase**{vt.}++提高；筹集；养育；升起**{vi.}++上升**{n.}++高地；上升；加薪**', '');
