INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('rally', '[ˈræli]', 'http://dict.youdao.com/dictvoice?audio=rally', '{v.}++召集，集合；公开支持（或反对）；重新集合，重整（军队）；恢复，重新振作；动员（全体人员）发愤图强；（价格）回升，升值；参加汽车拉力赛；对……善意打趣，嘲笑**{n.}++集会，大会；赛车，汽车拉力赛；（网球等比赛中的）相持，拉锯；（球队技艺的）改进，提高；恢复健康，康复；（尤指股价）止跌回升**{n.}++a large gathering of people intended to arouse enthusiasm																					   	同义词：								                                  				    mass meeting**{vi.}++团结；重整；恢复；（网球等）连续对打**{vt.}++团结；集合；恢复健康、力量等**{n.}++集会；回复；公路赛车会**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('ramble', '[ˈræmb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=ramble', '{v.}++散步，闲逛；闲扯，随笔；（植物）蔓生，蔓延**{n.}++（在乡间的）漫游，闲逛；杂乱无章的长篇大论**{n.}++an aimless amble on a winding course																					   	同义词：								                                  				    meander**{v.}++continue talking or writing in a desultory manner																										        				&quot;This novel rambles on and jogs&quot;															   	同义词：								                                  				    ramble on				    				    				      				    				      				    				                                      				    jog**{n.}++漫步；漫游；随笔**{vi.}++漫步；漫游；闲逛；漫谈；蔓延**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('ranch', '[ræntʃ]', 'http://dict.youdao.com/dictvoice?audio=ranch', '{n.}++（尤指饲养牛、马、羊等的）大农场，大牧场；牧场式住宅（=ranch house）；酸奶油沙拉酱（=ranch dressing）**{v.}++经营牧场（或农场）；在农场饲养（牲畜）；把（土地）用作牧场（或农场）**{n.}++farm consisting of a large tract of land along with facilities needed to raise livestock (especially cattle)																					   	同义词：								                                  				    spread				    				    				      				    				      				    				                                      				    cattle ranch				    				    				      				    				      				    				                                      				    cattle farm**{v.}++manage or run a ranch																										        				&quot;Her husband is ranching in Arizona&quot;**{n.}++大农场；大牧场**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('random', '[ˈrændəm]', 'http://dict.youdao.com/dictvoice?audio=random', '{adj.}++任意的，随机的，胡乱的；（砖石建筑）石头大小不一的；奇怪的，不同寻常的**{n.}++随意，随机；不认识的人，陌生人**{adv.}++随机地，胡乱地**{adj.}++lacking any definite plan or order or purpose; governed by or depending on chance																										        													        													        				&quot;a random choice&quot;; &quot;bombs fell at random&quot;; &quot;random movements&quot;**{adj.}++[数]随机的；任意的；[建]胡乱的**{n.}++随意**{adv.}++胡乱地**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('range', '[reɪndʒ]', 'http://dict.youdao.com/dictvoice?audio=range', '{n.}++（变动或浮动的）范围，界限；视觉（或听觉）范围；射程，射击距离；一系列；成套产品，系列商品；山脉；牧场，牧区；靶场，射击场，炸弹试验场；（尤指旧时的）炉灶；一排建筑物；方向，走向；（飞机等交通工具的）续航距离**{v.}++（在一定的范围内）变化，变动；（按一定位置或顺序）排列，排序；徘徊，四处移动；（文章或讲话）涉及，包括 ；（枪、炮、射击后校准）测距，（用雷达或激光）测距；支持，反对；自然生长，分布；与……联合起来，加入……行列**{adj.}++（生活方式）有秩序的，安定的**{n.}++an area in which something acts or operates or has power or control:																										        				&quot;the range of a supersonic jet&quot;															   	同义词：								                                  				    scope				    				    				      				    				      				    				                                      				    reach				    				    				      				    				      				    				                                      				    orbit				    				    				      				    				      				    				                                      				    compass				    				    				      				    				      				    				                                      				    ambit**{n.}++范围；幅度；排；[地理]山脉**{vi.}++平行，列为一行；延伸；漫游；射程达到**{vt.}++漫游；放牧；使并列；归类于；来回走动**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('rap', '[ræp]', 'http://dict.youdao.com/dictvoice?audio=rap', '{n.}++说唱音乐；说唱歌曲；扣击，快速的敲击； 指控，罪名；（尤指人或事的不良）名声，声誉； 指责，苛评；（尤指冗长或即兴的）谈论，闲聊；一丁点儿，极少**{v.}++急拍，快敲；表演说唱音乐，说唱；批评，指责；厉声地说（rap out）； 闲聊，交谈**{n.}++a reproach for some lapse or misdeed																										        				&quot;it was a bum rap&quot;															   	同义词：								                                  				    blame**{vt.}++抢走；轻敲；敲击致使；使着迷**{vi.}++敲击；交谈**{n.}++轻敲**', '');
