INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('rapture', '[ˈræptʃər]', 'http://dict.youdao.com/dictvoice?audio=rapture', '{n.}++兴高采烈**{v.}++使……狂喜；使……着迷；（基督再临时）提送（信徒）升天**{n.}++a state of being carried away by overwhelming emotion																										        				&quot;listening to sweet music in a perfect rapture&quot;															   	同义词：								                                  				    ecstasy				    				    				      				    				      				    				                                      				    transport				    				    				      				    				      				    				                                      				    exaltation				    				    				      				    				      				    				                                      				    raptus**{n.}++兴高采烈**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('rascal', '[ˈræskl]', 'http://dict.youdao.com/dictvoice?audio=rascal', '{n.}++流氓，无赖；不诚实的人**{adj.}++下贱的，卑鄙的**{n.}++（Rascal）（美）瓦史撒乐（人名）**{n.}++a deceitful and unreliable scoundrel																					   	同义词：								                                  				    rogue				    				    				      				    				      				    				                                      				    knave				    				    				      				    				      				    				                                      				    rapscallion				    				    				      				    				      				    				                                      				    scalawag				    				    				      				    				      				    				                                      				    scallywag				    				    				      				    				      				    				                                      				    varlet**{n.}++流氓，无赖；淘气鬼，捣蛋鬼**{adj.}++不诚实的；下贱的，卑鄙的**', '');
