INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('rate', '[reɪt]', 'http://dict.youdao.com/dictvoice?audio=rate', '{n.}++速度，速率；比率，率；费用，价格；费率；（英国）地方税，房地产税（rates）；等级**{v.}++评价，评定；被认为，被列为； 看好； 对（影片、视频游戏等）分级；划分等级，分等；值得，应得；给（财产）核定应缴地方税款；（机器、发动机等的）额定功率（极限）为；受器重，受青睐（rate with）**{n.}++amount of a charge or payment relative to some basis																										        				&quot;a 10-minute phone call at that rate would cost $5&quot;															   	同义词：								                                  				    charge per unit**{n.}++[数]比率，率；[力]速度；价格；等级**{vt.}++认为；估价；责骂**{vi.}++责骂；被评价**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('rational', '[ˈræʃ(ə)nəl]', 'http://dict.youdao.com/dictvoice?audio=rational', '{adj.}++（想法、决定等）合理的，基于理性的；（人）理性的，理智的；富有理性的；（数）有理的，有理数的**{n.}++有理数**{n.}++an integer or a fraction																					   	同义词：								                                  				    rational number**{adj.}++consistent with or based on or using reason																										        													        													        				&quot;rational behavior&quot;; &quot;a process of rational inference&quot;; &quot;rational thought&quot;**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('rattle', '[ˈræt(ə)l]', 'http://dict.youdao.com/dictvoice?audio=rattle', '{v.}++（使）咯咯作响；（车辆） 嘎拉嘎拉地响，（移动时）隆隆作响；使慌张，使紧张；呆在......里，占用（大得不必要的房间或建筑）；喋喋不休地讲话（rattle on）**{n.}++咯咯声，咔嗒声；发连续短促尖利声的器具；拨浪鼓；（在观看足球比赛或举行部落仪式中使用的）急响器，响板；（响尾蛇尾部的）角质环，响环；（人垂死时喉间发出的）呼噜声，临终喉鸣； 喋喋不休的人**{n.}++a rapid series of short loud sounds (as might be heard with a stethoscope in some types of respiratory disorders)																										        				&quot;the death rattle&quot;															   	同义词：								                                  				    rattling				    				    				      				    				      				    				                                      				    rale**{vt.}++使发出咯咯声；喋喋不休；使慌乱，使惊慌**{n.}++喋喋不休的人；吓吱声，格格声**', '');
