INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('realistic', '[ˌriːəˈlɪstɪk]', 'http://dict.youdao.com/dictvoice?audio=realistic', '{adj.}++务实的，实事求是的；实际的，现实可行的；写实的，逼真的；实在论的**{adj.}++aware or expressing awareness of things as they really are																										        													        													        													        				&quot;a realistic description&quot;; &quot;a realistic view of the possibilities&quot;; &quot;a realistic appraisal of our chances&quot;; &quot;the actors tried to create a realistic portrayal of the Africans&quot;**{adj.}++现实的；现实主义的；逼真的；实在论的**', '');
