INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('rear', '[rɪr]', 'http://dict.youdao.com/dictvoice?audio=rear', '{n.}++（尤指建筑物或车辆等的）后部，背部（the rear）；（队列的）后方，后尾部队（或舰队）；臀部，屁股（=rear end）**{adj.}++后方的，背部的**{v.}++养育，饲养；栽种，培植；（动物）用后腿直立；（建筑、山等）高耸；（人）发火，暴跳（rear up）**{adv.}++向后，在后面**{n.}++the back of a military formation or procession																										        				&quot;infantrymen were in the rear&quot;**{vt.}++培养；树立；栽种**{vi.}++暴跳；高耸**{adv.}++向后；在后面**{adj.}++[军]后方的；后面的；背面的**{n.}++后面；屁股；后方部队**', '');
