INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('rebuke', '[rɪˈbjuːk]', 'http://dict.youdao.com/dictvoice?audio=rebuke', '{v.}++斥责，指责**{n.}++指责，叱责，训斥**{n.}++an act or expression of criticism and censure																										        				&quot;he had to take the rebuke with a smile on his face&quot;															   	同义词：								                                  				    reproof				    				    				      				    				      				    				                                      				    reproval				    				    				      				    				      				    				                                      				    reprehension				    				    				      				    				      				    				                                      				    reprimand**{v.}++censure severely or angrily																					   	同义词：								                                  				    call on the carpet				    				    				      				    				      				    				                                      				    take to task				    				    				      				    				      				    				                                      				    rag				    				    				      				    				      				    				                                      				    trounce				    				    				      				    				      				    				                                      				    reproof				    				    				      				    				      				    				                                      				    lecture				    				    				      				    				      				    				                                      				    reprimand				    				    				      				    				      				    				                                      				    jaw				    				    				      				    				      				    				                                      				    dress down				    				    				      				    				      				    				                                      				    call down				    				    				      				    				      				    				                                      				    scold				    				    				      