INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('reciprocal', '[rɪˈsɪprək(ə)l]', 'http://dict.youdao.com/dictvoice?audio=reciprocal', '{adj.}++相互的，互惠的，报答的；（路线，方向）反向的；（代词，动词）互相的；（量，函数）倒数的；互逆的，互反的**{n.}++反身代词，相互动词； 倒数，乘法逆元素；互相起作用的事物**{n.}++something (a term or expression or concept) that has a reciprocal relation to something else																										        				&quot;risk is the reciprocal of safety&quot;**{adj.}++[贸易]互惠的；相互的；[数]倒数的，彼此相反的**', '');
