INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('recognition', '[ˌrekəɡˈnɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=recognition', '{n.}++承认，接受；表彰，赞誉；认出，识别；（政府对他国的）外交认可**{n.}++the state or quality of being recognized or acknowledged																										        													        				&quot;the partners were delighted with the recognition of their work&quot;; &quot;she seems to avoid much in the way of recognition or acknowledgement of feminist work prior to her own&quot;															   	同义词：								                                  				    acknowledgment				    				    				      				    				      				    				                                      				    acknowledgement**{n.}++[计][免疫]识别；承认，认出；重视；赞誉；公认**', '');
