INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('reed', '[riːd]', 'http://dict.youdao.com/dictvoice?audio=reed', '{n.}++芦苇（秆）；（盖屋顶用）茅草；芦笛；与芦苇相似的人或物；箭，矢；小凸嵌线脚（reeds）；（吹奏乐器的）簧片，簧舌；簧乐器；（磁性继电器或磁力开关）接触器；筘，钢箍**{v.}++用芦苇盖，用芦苇装饰**{n.}++tall woody perennial grasses with hollow slender stems especially of the genera Arundo and Phragmites**{n.}++[作物]芦苇；簧片；牧笛；不可依靠的人**', '');
