INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('referee', '[ˌrefəˈriː]', 'http://dict.youdao.com/dictvoice?audio=referee', '{n.}++（比赛的）裁判员；仲裁员，调解人；（求职等时的）证明人，介绍人；（刊登前鉴定文章的）审阅人，（拨款前鉴定研究计划的）鉴定专家**{v.}++（给……）当裁判；（给……）做仲裁员，（给……）做调解人；审阅，鉴定（专业性强的文章）**{n.}++(sports) the chief official (as in boxing or American football) who is expected to ensure fair play																					   	同义词：								                                  				    ref**{n.}++裁判员；调解人；介绍人**{vt.}++为…当裁判；调停**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('reference', '[ˈrefrəns]', 'http://dict.youdao.com/dictvoice?audio=reference', '{n.}++提及，谈到；参考，查阅；（引自书或诗歌的）引言，引文；引文的作者，参考书目；（帮助或意见的）征求，征询； (为方便查询所用的）标记，编号；推荐信，介绍信；介绍人，推荐人**{adj.}++参考的，用于查阅的；文献索引的，参照的**{v.}++列出……的参考书目；提及，提到；引用，参照（某书或某作者）**{n.}++a remark that calls attention to something or someone																										        				&quot;the speaker made several references to his wife&quot;															   	同义词：								                                  				    mention**{n.}++参考，参照；涉及，提及；参考书目；介绍信；证明书**{vi.}++引用**{vt.}++引用**', '');
