INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('reign', '[reɪn]', 'http://dict.youdao.com/dictvoice?audio=reign', '{n.}++（君主）在位时期，统治时期；领导期，任期；支配期，极盛期；（运动员或运动队）持有指明荣誉头衔的时期**{v.}++为王，统治；支配，盛行；成为最佳，成为最重要的**{n.}++a period during which something or somebody is dominant or powerful																										        				&quot;he was helpless under the reign of his egotism&quot;**{vi.}++统治；支配；盛行；君临**{n.}++统治；统治时期；支配**', '');
