INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('replace', '[rɪˈpleɪs]', 'http://dict.youdao.com/dictvoice?audio=replace', '{v.}++取代；（用……）替换，（以……）接替；更换， 赔还；把......放回原处**{v.}++substitute a person or thing for (another that is broken or inefficient or lost or no longer working or yielding what is expected)																										        													        													        													        				&quot;He replaced the old razor blade&quot;; &quot;We need to replace the secretary that left a month ago&quot;; &quot;the insurance will replace the lost income&quot;; &quot;This antique vase can never be replaced&quot;**{vt.}++取代，代替；替换，更换；归还，偿还；把…放回原处**', '');
