INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('representative', '[ˌreprɪˈzentətɪv]', 'http://dict.youdao.com/dictvoice?audio=representative', '{adj.}++典型的，有代表性的；代表各类人（或事物）的；由代表组成的，代议制的；表现的，体现的；（艺术）具象派的；（哲） （与）表象（有关）的**{n.}++代表，代理人；代表他人者；销售代表，销售代理；典型人物，有代表性的事物；（美国）众议院议员；（类或群的）样本，代表物**{n.}++a person who represents others**{adj.}++典型的，[数]有代表性的；代议制的**{n.}++[数]代表；典型；众议员**', '');
