INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('reserve', '[rɪˈzɜːrv]', 'http://dict.youdao.com/dictvoice?audio=reserve', '{v.}++预订；保留，预留；拥有，保留（某种权利）；留作，用于（特定场合）；保留（意见），推迟作出（决定或判断）；贮存，贮藏；（教会用语）弥撒仪式后保留部分圣餐**{n.}++储备（量），储藏（量）；含蓄，寡言；保留意见，异议；（野生生物）保护区；替补队员，后备队员；后备队，替补队（the reserves）；预备役部队，后备部队；（尤指拍卖时的）底价，最低价；（美洲土著居民的）居留地；（陶瓷装饰或纺织品印染中保留原色的）防染本色区；（陶瓷装饰或纺织品印染中保留原色的）防染本色区**{n.}++formality and propriety of manner																					   	同义词：								                                  				    modesty**{n.}++[贸易][金融]储备，储存；自然保护区；[军][林]预备队；储备金**{vt.}++[贸易][金融]储备；保留；预约**{vi.}++预订**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('reside', '[rɪˈzaɪd]', 'http://dict.youdao.com/dictvoice?audio=reside', '{v.}++居住，定居；存在于；（权利、权力等）属于；位（于）**{v.}++make ones home in a particular place or community																										        				&quot;may parents reside in Florida&quot;															   	同义词：								                                  				    shack				    				    				      				    				      				    				                                      				    domicile				    				    				      				    				      				    				                                      				    domiciliate**{vt.}++住，居住；属于**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('resident', '[ˈrezɪdənt]', 'http://dict.youdao.com/dictvoice?audio=resident', '{n.}++居民，住户；（旅馆的）住宿者；住院医生； 寄宿制学校学生；（英国政府派驻半独立国家的） 特派代表；驻外特工；留鸟，无迁徙习性的蝴蝶（或其他动物）**{adj.}++（在某地）居住的，居留的；常驻的；属于（某个群体）的；（鸟、蝴蝶等）非迁徙性的；（计算机程序、文件等在存储器中）驻留的**{n.}++someone who lives at a particular place for a prolonged period or who was born there																					   	同义词：								                                  				    occupant				    				    				      				    				      				    				                                      				    occupier**{adj.}++居住的；住院医师；定居的**{n.}++居民**', '');
