INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('reverse', '[rɪˈvɜːrs]', 'http://dict.youdao.com/dictvoice?audio=reverse', '{v.}++逆转，彻底改变（决定、政策、趋势等）；撤销，推翻（法庭判决）；颠倒，反转；交换，互换（位置、功能）；承认错误，放弃（立场）；倒（车）；（发动机）反向运转；打对方付费的电话；使（铅字，图案）印成白或浅色**{n.}++相对，相反（the reverse）；逆向，逆转；倒车挡；失败，挫折；反面，背面；（翻开的书）左手页，（活页文件的）背面；（硬币或奖牌）反面图案（或刻字）；（美式橄榄球）反向传球，变位传球**{adj.}++相反的，反向的；背面的，反面的；（半导体结的外加电压）反向的；（地层）逆断的，冲断的；反身的**{n.}++a relation of direct opposition																										        				&quot;we thought Sue was older than Bill but just the reverse was true&quot;															   	同义词：								                                  				    contrary				    				    				      				    				      				    				                                      				    opposite**{n.}++相反；背面；倒退；失败**{vt.}++颠倒；倒转**{adj.}++反面的；颠倒的**{vi.}++倒退；逆叫**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('revive', '[rɪˈvaɪv]', 'http://dict.youdao.com/dictvoice?audio=revive', '{v.}++（使）复原，（使）复苏；重新唤起，重新记起；重新使用，使复兴；重新上演**{v.}++cause to regain consciousness																										        				&quot;The doctors revived the comatose man&quot;															   	同义词：								                                  				    resuscitate**{vi.}++复兴；复活；苏醒；恢复精神**{vt.}++使复兴；使苏醒；回想起；重演，重播**', '');
