INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('rigorous', '[ˈrɪɡərəs]', 'http://dict.youdao.com/dictvoice?audio=rigorous', '{adj.}++（测试、系统或程序）严密的，缜密的；（规则，制度等）严格的，苛刻的；一丝不苟的；严酷的，恶劣的**{adj.}++rigidly accurate; allowing no deviation from a standard																										        				&quot;rigorous application of the law&quot;															   	同义词：								                                  				    strict**{adj.}++严格的，严厉的；严密的；严酷的**', '');
