INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('rinse', '[rɪns]', 'http://dict.youdao.com/dictvoice?audio=rinse', '{v.}++（用清水）冲洗；（用其他液体）洗；把（肥皂、污垢等）洗掉（rinse sth. off/out）；漱（口）；染发**{n.}++冲洗；头发定型剂，染发剂；（清洗用的）液体**{n.}++a liquid preparation used on wet hair to give it a tint**{vt.}++漱；冲洗掉；漂净**{n.}++冲洗；漂洗；[轻]染发剂；染发**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('riot', '[ˈraɪət]', 'http://dict.youdao.com/dictvoice?audio=riot', '{n.}++暴乱，骚乱；纷呈，丰富多彩；非常有趣的人（或事物）；纵情欢闹，狂欢；骚动；（感情的）爆发，宣泄**{v.}++（人群）发生骚乱，聚众闹事；放纵，恣意；浪费，挥霍**{n.}++a public act of violence by an unruly mob																					   	同义词：								                                  				    public violence**{n.}++暴乱；放纵；蔓延**{vi.}++骚乱；放荡**{vt.}++浪费，挥霍**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('rip', '[rɪp]', 'http://dict.youdao.com/dictvoice?audio=rip', '{v.}++（使）撕裂，（使）划破；迅速扯开，猛力去除；（迅速）贯穿，穿过；划出（孔洞），击穿；抢掠，剥夺；严厉批评，训斥；利用程序将（光盘上的音序）复制到硬盘驱动器上**{n.}++裂口，裂缝；撕，撕破；欺诈，剽窃；（在电脑上制作的光碟）复制本；（由海、河中不同水流相遇造成的）裂流（激浪）水域，离岸流；生活放荡的人（尤指男人），浪子；调皮的人，淘气鬼（尤指小孩）；劣马，无用的马**{n.}++a dissolute man in fashionable society																					   	同义词：								                                  				    rake				    				    				      				    				      				    				                                      				    rakehell				    				    				      				    				      				    				                                      				    profligate				    				    				      				    				      				    				                                      				    blood				    				    				      				    				      				    				                                      				    roue**{vt.}++撕；锯**{vi.}++裂开，被撕裂**{n.}++裂口，裂缝**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('ripple', '[ˈrɪp(ə)l]', 'http://dict.youdao.com/dictvoice?audio=ripple', '{n.}++涟漪；（外观或运动）如波纹的东西；（声音的）传播起伏，（感情的）逐渐扩散；连锁反应；彩条冰淇淋；表面张力波；脉动**{v.}++（使）如波浪般起伏；（情绪）波动，（声音）荡漾；发出潺潺声**{n.}++a small wave on the surface of a liquid																					   	同义词：								                                  				    rippling				    				    				      				    				      				    				                                      				    riffle				    				    				      				    				      				    				                                      				    wavelet**{n.}++波纹；涟漪；[物]涟波**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('roam', '[roʊm]', 'http://dict.youdao.com/dictvoice?audio=roam', '{v.}++漫步，闲逛；（眼睛）扫视，（手）扫过；（思绪，想象力）遨游**{n.}++漫步**{v.}++move about aimlessly or without any destination, often in search of food or employment																										        													        				&quot;The gypsies roamed the woods&quot;; &quot;The cattle roam across the prairie&quot;															   	同义词：								                                  				    roll				    				    				      				    				      				    				                                      				    wander				    				    				      				    				      				    				                                      				    swan				    				    				      				    				      				    				                                      				    stray				    				    				      				    				      				    				                                      				    tramp				    				    				      				    				      				    				                                      				    cast				    				    				      				    				      				    				                                      				    ramble				    				    				      				    				      				    				                                      				    rove				    				    				      				    				      				    				                                      				    range				    				    				      				    				      				    				                                      				    drift				    				    				      				    				      				    				                                      				    vagabond**{vi.}++漫游，漫步；流浪**{vt.}++在…漫步，漫游；在…流浪**{n.}++漫步，漫游；流浪**', '');
