INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('scope', '[skoʊp]', 'http://dict.youdao.com/dictvoice?audio=scope', '{n.}++范围，领域；（发挥能力的）机会，施展余地；视野，眼界；观测仪器（如望远镜、显微镜等）；（船抛锚时的）缆绳长度；特定论点的数量**{v.}++评估，调查（scope sth. out）；确定（规划项目）的范围；仔细看，彻底检查**{n.}++an area in which something acts or operates or has power or control:																										        				&quot;within the scope of an investigation&quot;															   	同义词：								                                  				    range				    				    				      				    				      				    				                                      				    reach				    				    				      				    				      				    				                                      				    orbit				    				    				      				    				      				    				                                      				    compass				    				    				      				    				      				    				                                      				    ambit**{n.}++范围；余地；视野；眼界；导弹射程**', '');
