INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('scout', '[skaʊt]', 'http://dict.youdao.com/dictvoice?audio=scout', '{n.}++侦察兵，侦察机；侦查（尤指勘察地区）；童子军（the Scouts）；（英国大学里清扫学生房间的）校工；（演员、运动员等的）人才发掘者，星探；侦查蜂；童子军队员**{v.}++（在某个地区）寻找，搜寻；物色（尤指体育或娱乐）人才； 轻蔑地拒绝（建议，想法）；探查，侦查；跟踪，监视**{n.}++a person employed to watch for something to happen																					   	同义词：								                                  				    lookout				    				    				      				    				      				    				                                      				    lookout man				    				    				      				    				      				    				                                      				    sentinel				    				    				      				    				      				    				                                      				    sentry				    				    				      				    				      				    				                                      				    watch				    				    				      				    				      				    				                                      				    spotter				    				    				      				    				      				    				                                      				    picket**{n.}++搜索，[航][军]侦察；侦察员；侦察机**{vt.}++[航][军]侦察；跟踪，监视；发现**{vi.}++[航][军]侦察；巡视；嘲笑**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('scramble', '[ˈskræmb(ə)l]', 'http://dict.youdao.com/dictvoice?audio=scramble', '{v.}++（迅速而吃力地）爬，攀登；不规则地生长；匆忙地移动；仓促完成（困难的事）；匆忙穿（衣）（scramble into）；争夺，抢夺；变换……的无线电信号，倒换……的频率；扰乱（思维）；炒蛋；命令（飞机）紧急起飞，紧急起飞；（四分卫）持球跑进；打乱**{n.}++攀爬，爬行；（互相推撞的）争夺，争抢；（因赶任务出现的）忙乱，乱作一团； 摩托车越野赛；（四分卫的）持球跑进；战斗机紧急起飞**{n.}++an unceremonious and disorganized struggle																					   	同义词：								                                  				    scuffle**{vt.}++攀登；使混杂，仓促凑成；扰乱**{n.}++抢夺，争夺；混乱，混乱的一团；爬行，攀登**{vi.}++爬行，攀登；不规则地生长；仓促行动**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('scrap', '[skræp]', 'http://dict.youdao.com/dictvoice?audio=scrap', '{n.}++（纸、布等的）碎片，小块；丝毫，一丁点；废品，废弃材料（=scrap metal）；吃剩的东西，残羹剩饭（scraps）；小摩擦，小口角；极瘦小的人（常指小孩）**{v.}++（因不切实际而）放弃，抛弃（计划、体系）；把（旧机器、旧汽车等当）作废料处理，报废；打架，吵架；激烈竞争**{adj.}++（金属、纸张）废弃的，报废的；零碎的**{n.}++a small fragment of something broken off from the whole																					   	同义词：								                                  				    bit				    				    				      				    				      				    				                                      				    chip				    				    				      				    				      				    				                                      				    flake				    				    				      				    				      				    				                                      				    fleck**{n.}++[机]碎片；残余物；打架；少量**{vt.}++废弃；使解体；拆毁**{adj.}++废弃的；零碎的**{vi.}++吵架**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('scratch', '[skrætʃ]', 'http://dict.youdao.com/dictvoice?audio=scratch', '{v.}++（用指甲）挠，轻抓；（用指甲或利器）抓破，划破；划出，刮出（痕迹）；（用爪子）抓，刨；（鸟、哺乳动物，尤指鸡）用嘴（或爪子）扒地找食物；寻觅（难找的人或物）（scratch for）；艰难生活（scratch along）；勾掉，划去（写下的字）； 仓促写下；（用尖利物）刮擦出声音； 取消，撤销（想法或计划）；（使）退出比赛；（用刮擦技法）播放唱片**{n.}++（某人皮肤上的）划痕，划伤；刮痕，划痕；抓，挠；刮擦声；唱片的嚓嚓声（指唱片纹道与唱针的摩擦噪声）；刮擦（多用于快板乐中，用手制止唱片转动，使其来回移动发出有节奏的嚓嚓声的技巧）；（高尔夫）零让步（表明选手不弱，能在场上达到规定击球的次数）； 钱**{adj.}++（球队或一群人等）仓促拼凑的，匆匆组成的；（高尔夫球员）无让杆的，无让步优待的；碰巧的；打草稿用的**{n.}++an abraded area where the skin is torn or worn off																					   	同义词：								                                  				    abrasion				    				    				      				    				      				    				                                      				    scrape				    				    				      				    				      				    				                                      				    excoriation**{n.}++擦伤；抓痕；刮擦声；乱写**{adj.}++打草稿用的；凑合的；碰巧的**{vt.}++抓；刮；挖出；乱涂**{vi.}++抓；搔；发刮擦声；勉强糊口；退出比赛**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('scripture', '[ˈskrɪptʃər]', 'http://dict.youdao.com/dictvoice?audio=scripture', '{n.}++《圣经》（Scripture或the Scriptures）；（某一宗教的）经文，圣典；《圣经》研究；手稿**{n.}++the sacred writings of the Christian religions																					   	同义词：								                                  				    Bible				    				    				      				    				      				    				                                      				    Christian Bible				    				    				      				    				      				    				                                      				    Book				    				    				      				    				      				    				                                      				    Good Book				    				    				      				    				      				    				                                      				    Holy Scripture				    				    				      				    				      				    				                                      				    Holy Writ				    				    				      				    				      				    				                                      				    Word of God				    				    				      				    				      				    				                                      				    Word**{n.}++（大写）圣经；手稿；（大写）圣经的一句**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('scrub', '[skrʌb]', 'http://dict.youdao.com/dictvoice?audio=scrub', '{v.}++（尤指用硬刷子）擦洗，擦净；（医生在做手术前）仔细擦洗手和手臂（scrub up）；取消（计划等）；用水净化（汽油，蒸汽）；（骑手用手臂与腿紧迫地摩擦马的颈部和两侧）催马（快行）；（赛车）（司机）让轮胎滑行（或划擦路面）以减速**{n.}++矮树丛，灌木丛；灌木丛地带；刷洗，擦洗；磨砂膏；医院工作服（scrubs）；无足轻重的人，可鄙的人；二流球队（或队员）；（在公共场所举行的）儿童非正式团体比赛**{adj.}++（植物）矮小的；（动物）劣等的，发育不良的**{n.}++dense vegetation consisting of stunted trees or bushes																					   	同义词：								                                  				    chaparral				    				    				      				    				      				    				                                      				    bush**{n.}++矮树；洗擦；擦洗者；矮小的人（或物）**{vt.}++用力擦洗；使净化**{adj.}++矮小的；临时凑合的；次等的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('sculpture', '[ˈskʌlptʃər]', 'http://dict.youdao.com/dictvoice?audio=sculpture', '{n.}++雕像，雕塑作品；雕刻艺术，雕塑艺术；（动，植）（贝壳、花粉粒、角质层或其他生物体表面凸起或凹陷的）雕饰，雕纹**{v.}++雕刻，雕塑；从事雕刻**{n.}++a three-dimensional work of plastic art**{n.}++[建]雕塑；[轻]雕刻；刻蚀**{vt.}++[建]雕塑；[轻]雕刻；刻蚀**', '');
