INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('second', '[ˈsekənd]', 'http://dict.youdao.com/dictvoice?audio=second', '{num.}++第二（的），第二个（的）；（重要性、规模、质量等）居第二位的；另外的，外加的**{n.}++秒（时间单位）；片刻，瞬间；秒（角度单位）；次品，二等货；第二次上菜，添菜（seconds）；（车辆的）第二挡；（英国大学本科的）二等成绩学位；（学校或大学的）二年级；（棒球的）二垒；正式支持，附议；（体育俱乐部的）预备队（the seconds）；粗面粉，粗粉面包；（尤指拳击比赛或旧时决斗中的）助手；（乐）二度音程**{v.}++支持，附议；临时调派，短期调任**{adv.}++以第二位；第二，其次**{n.}++1/60 of a minute; the basic unit of time adopted under the Systeme International dUnites																					   	同义词：								                                  				    sec				    				    				      				    				      				    				                                      				    s**{n.}++[计量]秒；第二名；瞬间；二等品**{vt.}++支持**{adj.}++第二的；次要的；附加的**{adv.}++第二；其次；居第二位**', '');
