INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('set', '[set]', 'http://dict.youdao.com/dictvoice?audio=set', '{v.}++放，置；使开始；把故事情节安排在；设置；摆放餐具；镶嵌；安排；树立；布置；凝固；使现出坚定的表情；固定发型；把（断骨）复位；排版；为……谱曲；落（下）；布置（戏剧、电影或电视节目的布景）；（断骨）愈合**{n.}++一组（类似的东西）；一组（配套使用的东西）；一伙（或一帮、一群）人；电视机；布景 ；舞台；（网球、排球比赛等的）盘；集；一组歌曲（或乐曲）；（在某学科上能力相当的）一批学生 ；（尤指坚定的）姿势；头发的定型；凝固；兽穴；（供移植的）秧苗**{adj.}++位于（或处于）……的；安排好的；固定的；套（餐）；有可能的；不自然的**{n.}++a group of things of the same kind that belong together and are so used																										        													        													        				&quot;a set of books&quot;; &quot;a set of golf clubs&quot;; &quot;a set of teeth&quot;**{n.}++一套；[数]集合；[机]装置；趋势；布景**{vt.}++放；树立；点燃；使凝结；点缀**{vi.}++结果；定型；凝固**{adj.}++规定的；固定的；固执的**', '');
