INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('should', '[ʃʊd; ʃəd]', 'http://dict.youdao.com/dictvoice?audio=should', '{v.}++（用于纠正别人）应该；（用于建议）该，可以；（表示预期）应该会；（表示与预期相反）本应；（与 I 或 we 连用代替 would，表示虚拟结果）就将；（用于 that 从句，表示建议或安排）可以；（用于 that 从句，表示感情）竟然会；（表示拒绝、恼怒或惊奇）竟会；（表示可能）假如，万一；将（用作 shall 的过去式）；（与 I 和 we 连用，表示客气地请求）想；当然，真的（用于强调自己所相信或所期待的）；（表示强调有趣、惊讶或印象深刻）真该**{aux.}++应该；就；可能；将要**', '');
