INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('shove', '[ʃʌv]', 'http://dict.youdao.com/dictvoice?audio=shove', '{v.}++猛推，乱挤；连推带挤地走； 随便放置，乱放（某物）；移动身体，挪动身体（以腾出地方）；去他的，让……见鬼**{n.}++猛推**{n.}++the act of shoving (giving a push to someone or something)																										        				&quot;he gave the door a shove&quot;**{v.}++come into rough contact with while moving																					   	同义词：								                                  				    jostle**{vt.}++挤；强使；撞；猛推**{n.}++推；挤**', '');
