INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('shuttle', '[ˈʃʌt(ə)l]', 'http://dict.youdao.com/dictvoice?audio=shuttle', '{n.}++航天飞机（space shuttle 的简称）；往返于两地的交通工具，摆渡车；（英法之间英吉利海峡隧道的）穿梭火车（the Shuttle）；（织机的）梭子；羽毛球（shuttlecock 的简称）**{v.}++穿梭，往返；穿梭运送**{n.}++badminton equipment consisting of a ball of cork or rubber with a crown of feathers																					   	同义词：								                                  				    shuttlecock				    				    				      				    				      				    				                                      				    bird				    				    				      				    				      				    				                                      				    birdie**{n.}++[航]航天飞机；穿梭；[纺]梭子；穿梭班机、公共汽车等**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('sideways', '[ˈsaɪdweɪz]', 'http://dict.youdao.com/dictvoice?audio=sideways', '{adv.}++斜向一边地；侧面朝前地，侧着；（工作调动）平级地；间接地**{adj.}++向一边（或一侧）的，向旁边的；（工作，职位）平级变动的；间接的；（观点）非常规的，非正统的**{adj.}++(of movement) at an angle																					   	同义词：								                                  				    crabwise**{adv.}++with one side forward or to the front																										        				&quot;turned sideways to show the profile&quot;															   	同义词：								                                  				    sideway				    				    				      				    				      				    				                                      				    sidewise**{adv.}++向侧面地；向一旁**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('siege', '[siːdʒ]', 'http://dict.youdao.com/dictvoice?audio=siege', '{n.}++（军队或警察对某地的）围困，包围；不断的攻击**{v.}++围攻，包围**{n.}++the action of an armed force that surrounds a fortified place and isolates it while continuing to attack																					   	同义词：								                                  				    besieging				    				    				      				    				      				    				                                      				    beleaguering				    				    				      				    				      				    				                                      				    military blockade**{n.}++围攻；包围；围城；不断袭击；长期努力**{vt.}++围攻；包围**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('sift', '[sɪft]', 'http://dict.youdao.com/dictvoice?audio=sift', '{v.}++筛（面粉或颗粒较细的物质）；（使）通过筛具般撒下，落下；细查，详审；使分开，剔除（sift sth. out）；（雪、灰或光线等）轻轻撒落，轻轻飘落**{n.}++筛，筛选；筛过的原料**{v.}++move as if through a sieve																										        				&quot;The soldiers sifted through the woods&quot;**{vt.}++筛选；撒；过滤；详查**{vi.}++筛；详查；撒下；细究**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('sight', '[saɪt]', 'http://dict.youdao.com/dictvoice?audio=sight', '{n.}++视力，视觉；看见，见到；视野，视域；景物，景象；名胜，景点（sights）；志向，目标；（枪或炮上的）瞄准器，（光学仪器的）观测器； 奇怪的人，滑稽的人（或事物）； 许多，大量； 观点，见解**{v.}++（突然）看到，（远远）看见；把（枪）瞄准；（用观测器）观测；调整（火器）的瞄准器，调整（光学仪器）的观测器**{adj.}++见票即付的；即席的**{n.}++an instance of visual perception																										        													        				&quot;the sight of his wife brought him back to reality&quot;; &quot;the train was an unexpected sight&quot;**{n.}++视力；景象；眼界；见解**{vt.}++看见；瞄准**{vi.}++瞄准；观看**{adj.}++见票即付的；即席的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('sign', '[saɪn]', 'http://dict.youdao.com/dictvoice?audio=sign', '{n.}++指示牌，标志；迹象，征兆；示意动作，手势；手语动作；符号，记号；踪迹，踪影；（医）征，体征；神迹（主要用于《圣经》和文学作品中）；（野生动物的）足迹，臭迹；（占星）（黄道12宫中的）宫，星座；（数）正负号；暗号，信号；（表示某人状况或经历的）动作，反应**{v.}++签名，署名；（与机构、公司等）签约；示意，打手势；打手语；用标志杆（或其他记号）表示**{n.}++a perceptible indication of something not immediately apparent (as a visible clue that something has happened)																										        													        				&quot;he showed signs of strain&quot;; &quot;they welcomed the signs of spring&quot;															   	同义词：								                                  				    mark**{n.}++迹象；符号；记号；手势**{vi.}++签署；签名**{vt.}++签署；示意**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('significant', '[sɪɡˈnɪfɪkənt]', 'http://dict.youdao.com/dictvoice?audio=significant', '{adj.}++显著的，相当数量的；重要的，意义重大的； 别有含义的，意味深长的**{n.}++象征，有意义的事物**{adj.}++important in effect or meaning																										        													        													        													        													        				&quot;a significant change in tax laws&quot;; &quot;a significant change in the Constitution&quot;; &quot;a significant contribution&quot;; &quot;significant details&quot;; &quot;statistically significant&quot;															   	同义词：								                                  				    important**{too closely correlated to be attributed to chance and therefore indicating a systematic relation																										        													        				&quot;the interaction effect is significant at the .}++01 level&quot;; &quot;no significant difference was found&quot;**{adj.}++重大的；有效的；有意义的；值得注意的；意味深长的**{n.}++象征；有意义的事物**', '');
