INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('simple', '[ˈsɪmp(ə)l]', 'http://dict.youdao.com/dictvoice?audio=simple', '{adj.}++简单的，简明的；简朴的，朴素的；纯粹的，完全的；结构单一的，简易的；普通的，平凡的；愚笨的，迟钝的；（动词时态）简单的；（数）简单的；（叶、茎）没有分杈的；（镜头、显微镜等）单镜头的；（利息）单利的；（句子）无从句的**{n.}++草药，药草；出身低微者；笨蛋**{n.}++any herbaceous plant having medicinal properties**{adj.}++[生物]简单的；单纯的；天真的**{n.}++笨蛋；愚蠢的行为；出身低微者**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('simplicity', '[sɪmˈplɪsəti]', 'http://dict.youdao.com/dictvoice?audio=simplicity', '{n.}++简单（性)，容易（性）；简朴，朴素；简单（或质朴、朴素）之处；愚蠢，无知**{n.}++the quality of being simple or uncompounded																										        				&quot;the simplicity of a crystal&quot;															   	同义词：								                                  				    simpleness**{n.}++朴素；简易；天真；愚蠢**', '');
