INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('singular', '[ˈsɪŋɡjələr]', 'http://dict.youdao.com/dictvoice?audio=singular', '{adj.}++单数的，单数形式的；非凡的，突出的；奇怪的，异常的；独一无二的，独特的；（数）（方阵）零行列式的**{n.}++单数，单数形式（the singular）**{n.}++the form of a word that is used to denote a singleton																					   	同义词：								                                  				    singular form**{adj.}++unusual or striking																										        				&quot;such poise is singular in one so young&quot;															   	同义词：								                                  				    remarkable**{being a single and separate person or thing																										        													        				&quot;can the singular person be understood apart from his culture?&quot;; &quot;every fact in the world might be singular.}++..unlike any other fact and sole of its kind&quot;**{adj.}++单数的；单一的；非凡的；[数]异常的**', '');
