INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('siren', '[ˈsaɪrən]', 'http://dict.youdao.com/dictvoice?audio=siren', '{n.}++汽笛，警报器；塞壬（古希腊神话中的海妖）（Siren）；妖艳迷人而又危险的女人；危险的诱惑；鳗螈；歌声动人的女歌手**{adj.}++迷人的**{v.}++响着警报器行驶；引诱**{n.}++a sea nymph (part woman and part bird) supposed to lure sailors to destruction on the rocks where the nymphs lived**{n.}++[铁路][船]汽笛；迷人的女人；歌声动人的女歌手**{adj.}++迷人的**{vt.}++引诱**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('situated', '[ˈsɪtʃueɪtɪd]', 'http://dict.youdao.com/dictvoice?audio=situated', '{adj.}++坐落在……的，位于……的；处于……状况，处境……**{v.}++使（某物）位于，建于；置于环境中，描述（某物）周围状况；处于（某特定经济或婚姻）状况（situate 的过去式和过去分词）**{adj.}++situated in a particular spot or position																										        				&quot;nicely situated on a quiet riverbank&quot;															   	同义词：								                                  				    located				    				    				      				    				      				    				                                      				    placed				    				    				      				    				      				    				                                      				    set**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('situation', '[ˌsɪtʃuˈeɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=situation', '{n.}++情况，形势；重要问题，突发情况；（建筑物或城镇的）地理位置，环境特点；工作，职位**{n.}++the general state of things; the combination of circumstances at a given time																										        													        				&quot;the present international situation is dangerous&quot;; &quot;eternal truths will be neither true nor eternal unless they have fresh meaning for every new social situation&quot;															   	同义词：								                                  				    state of affairs**{n.}++情况；形势；处境；位置**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('skeleton', '[ˈskelɪt(ə)n]', 'http://dict.youdao.com/dictvoice?audio=skeleton', '{n.}++骨骼，骨架；梗概，提纲；骨瘦如柴的人（或动物）；（建筑物、桥梁等的）框架，骨架；（维持运转所需的）最少人员，基干人员；钢架雪车**{adj.}++（员工）最基本的，基干的**{n.}++something reduced to its minimal form																										        													        				&quot;the battalion was a mere skeleton of its former self&quot;; &quot;the bare skeleton of a novel&quot;**{n.}++[测][建]骨架，[解剖]骨骼；纲要；骨瘦如柴的人**{adj.}++[解剖]骨骼的；骨瘦如柴的；概略的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('skip', '[skɪp]', 'http://dict.youdao.com/dictvoice?audio=skip', '{v.}++蹦蹦跳跳地走；跳绳；不做（应做的事等），不参加；跳过，略过；快速转移，骤然转换（话题）；悄悄溜走，突然离开；打水漂；当（运动队的）领队**{n.}++蹦跳；（计算机）跳跃（进位），跳行；违约者，讨债者； 废料桶；罐笼，箕斗，吊斗；（草地滚木球或冰壶运动队的）领队，队长**{n.}++a gait in which steps and hops alternate**{vi.}++跳跃；跳绳；遗漏；跳读**{vt.}++跳过；遗漏**{n.}++跳跃；跳读**', '');
