INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('slack', '[slæk]', 'http://dict.youdao.com/dictvoice?audio=slack', '{adj.}++不紧的，松弛的；（生意）萧条的，清淡的；懈怠的，敷衍了事的；（潮水）迟缓的，平缓的；淫荡的，下流的**{n.}++（绳索的）松弛部分；富余部分，闲置部分；裤子（slacks）；煤屑；懈怠，懒散**{v.}++懈怠，偷懒；使（绳索等）松弛；减缓，放慢；熟化（石灰）；缓慢（或懒散地）工作**{n.}++dust consisting of a mixture of small coal fragments and coal dust and dirt that sifts out when coal is passed over a sieve**{adj.}++松弛的；疏忽的；不流畅的**{vi.}++松懈；减弱**{n.}++煤末；峡谷**{vt.}++放松；使缓慢**{adv.}++马虎地；缓慢地**', '');
