INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('slap', '[slæp]', 'http://dict.youdao.com/dictvoice?audio=slap', '{v.}++（用手掌）打，拍；拍打，拍击；（尤指生气地）啪的一声放下，随意扔放；（快速地、随意地或用力地）涂抹（某物）；甩击；侮辱**{n.}++拍，掌击；掌击声，拍打声；（厚厚地或随意涂抹的）化妆品；侮辱**{adv.}++直接地，猛然； 恰好，正好**{adj.}++精力不足的，效率不高的；（食物）松软的，过于柔软的**{n.}++a blow from a flat object (as an open hand)																					   	同义词：								                                  				    smack**{vt.}++拍击；侮辱；掌击；掴…的耳光**{n.}++掴；侮辱；掌击；拍打声**{vi.}++掴；拍击**{adv.}++直接地；猛然地；恰好**', '');
