INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('slide', '[slaɪd]', 'http://dict.youdao.com/dictvoice?audio=slide', '{v.}++（使）滑行，滑动；滑落；迅速熟练地进出；（使）快捷而悄声地移动；（价格等）下滑，下跌；逐渐败坏，开始出现问题；滑垒**{n.}++滑梯；滑道；滑行，滑动；（价格、数量等的）下降，跌落，减少；幻灯片；（情况）变糟，恶化，（人）出现问题；（显微镜的）载物玻璃片；（乐器或机器上的）滑动装置；（岩石，土等的）崩落；小发夹；（棒球）滑垒；（吉他）滑奏；无后帮凉鞋（或轻便鞋）**{n.}++a small flat rectangular piece of glass on which specimens can be mounted for microscopic study																					   	同义词：								                                  				    microscope slide**{n.}++滑动；[电影]幻灯片；滑梯；雪崩**{vi.}++滑动；滑落；不知不觉陷入**{vt.}++滑动；使滑动；悄悄地迅速放置**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('slim', '[slɪm]', 'http://dict.youdao.com/dictvoice?audio=slim', '{adj.}++苗条的，纤细的；单薄的；（物）狭长的；（衣服）修长的，紧身的；（数量或数字）微小的；（公司或其他组织）精简的；诡计多端的，狡猾的**{v.}++（靠节食等）变苗条，减肥；减少（产品），缩减（人员）**{n.}++（非洲）艾滋病；瘦身课程（或时期）**{v.}++take off weight																					   	同义词：								                                  				    reduce				    				    				      				    				      				    				                                      				    melt off				    				    				      				    				      				    				                                      				    lose weight				    				    				      				    				      				    				                                      				    slenderize				    				    				      				    				      				    				                                      				    thin				    				    				      				    				      				    				                                      				    slim down**{adj.}++being of delicate or slender build																										        				&quot;a slim girl with straight blonde hair&quot;															   	同义词：								                                  				    slender				    				    				      				    				      				    				                                      				    slight				    				    				      				    				      				    				                                      				    svelte**{adj.}++苗条的；修长的；无价值的**{vi.}++减轻体重；变细**', '');
