INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('smart', '[smɑːrt]', 'http://dict.youdao.com/dictvoice?audio=smart', '{adj.}++聪明的，明智的；（人）衣着得体的；整洁而漂亮的，光鲜的；耍小聪明的，不恭的；时髦的，高档的；迅速有力的，迅猛的；智能的**{v.}++（身体部位）感到刺痛；（因批评、失败等）难过，烦恼**{n.}++剧痛，刺痛；痛苦，苦恼；聪明，敏锐（smarts）**{adv.}++机敏地，整洁地，潇洒地**{n.}++a kind of pain such as that caused by a wound or a burn or a sore																					   	同义词：								                                  				    smarting				    				    				      				    				      				    				                                      				    smartness**{v.}++be the source of pain																					   	同义词：								                                  				    ache				    				    				      				    				      				    				                                      				    hurt**{adj.}++showing mental alertness and calculation and resourcefulness**{n.}++痛苦；刺痛**{adj.}++聪明的；漂亮的；厉害的；巧妙的；敏捷的；潇洒的；剧烈的**{vi.}++刺痛；懊恼**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('smash', '[smæʃ]', 'http://dict.youdao.com/dictvoice?audio=smash', '{v.}++打碎，（使）粉碎；（使）猛击，（使）猛撞；（用力）撞开，闯过；击溃，使结束；撞毁，撞坏（交通工具）；（网球等比赛中）扣球，打高压球；（轻松）打破（记录）**{n.}++猛烈撞击声，破碎时的哗啦声；猛击；撞车，车祸；（网球运动中的）高压球，扣球；大获成功的歌曲（或戏剧、电影）（=smash hit）；（由白兰地、果味水和冰混合调制的）斯马喜（混合烈酒）饮料；破产，投资失败**{adv.}++哗啦一声**{adj.}++非常轰动的，出色的**{n.}++a vigorous blow																					   	同义词：								                                  				    knock				    				    				      				    				      				    				                                      				    bash				    				    				      				    				      				    				                                      				    bang				    				    				      				    				      				    				                                      				    belt**{vt.}++粉碎；使破产；溃裂**{n.}++破碎；扣球；冲突；大败**{vi.}++粉碎；打碎**{adj.}++了不起的；非常轰动的；出色的**', '');
