INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('snap', '[snæp]', 'http://dict.youdao.com/dictvoice?audio=snap', '{v.}++（使咔嚓）断裂，绷断；（使啪地）打开，关上，移动；厉声说，怒气冲冲地说；突然失控，精神崩溃；（狗等动物）突然咬；拍照，摄影；使……终结；噼啪地响；打响指；快速后传（球）；用子母扣扣**{n.}++喀嚓声，啪嗒声；快照，照片；摁扣，搭扣；呼“同”牌游戏；容易的事；某种短时期的天气；迅速的动作；（裆下后传）发球；（风格或动作）充满活力；不耐烦的语调（或样子）；食物；薄脆饼干；突然折断**{adj.}++突然的，仓促的**{int.}++真巧啊，一模一样；（呼“同”牌游戏中的）“同！”**{n.}++the act of catching an object with the hands																										        				&quot;the infielders snap and throw was a single motion&quot;															   	同义词：								                                  				    catch				    				    				      				    				      				    				                                      				    grab				    				    				      				    				      				    				                                      				    snatch**{vt.}++突然折断，拉断；猛咬；啪地关上**{vi.}++咬；厉声说；咯嗒一声关上**{n.}++猛咬；劈啪声；突然折断**{adj.}++突然的**', '');
