INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('sniff', '[snɪf]', 'http://dict.youdao.com/dictvoice?audio=sniff', '{v.}++（出声地）以鼻吸气，抽鼻子（如因哭泣或感冒）；嗅，闻；嗤之以鼻地说，轻蔑地说；吸入（气体或毒品）；嗅到，察觉出**{n.}++抽鼻子，哼；吸入的空气（或其他物质）；气味；线索，迹象；轻蔑，厌恶**{n.}++sensing an odor by inhaling through the nose																					   	同义词：								                                  				    snuff**{v.}++perceive by inhaling through the nose																										        				&quot;sniff the perfume&quot;															   	同义词：								                                  				    whiff**{vi.}++嗅；嗤之以鼻**{vt.}++嗅；闻；用力吸；发觉**{n.}++吸，闻；嗤之以鼻；气味；以鼻吸气；吸气声**', '');
