INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('solo', '[ˈsoʊloʊ]', 'http://dict.youdao.com/dictvoice?audio=solo', '{adj.}++单独的，独自的；独奏的，单人表演的；（击球时）垒上无跑垒员的；（摩托车）没有跨斗的**{n.}++单人表演，单飞，独自完成的事情；单人纸牌戏，惠斯特纸牌戏；惠斯特纸牌戏中为赢五圈牌的叫牌；没有跨斗的摩托车**{v.}++独奏，独唱；单独飞行；单人攀登**{adv.}++单独地，独自地**{n.}++any activity that is performed alone without assistance**{adj.}++独奏的；独唱的；单独的**{adv.}++单独地**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('sophisticated', '[səˈfɪstɪkeɪtɪd]', 'http://dict.youdao.com/dictvoice?audio=sophisticated', '{adj.}++见多识广的，老练的，见过世面的；复杂巧妙的，先进的，精密的；水平高的，在行的；时尚的，精致的**{v.}++使老于世故；使（设备、技术等）更复杂先进；（老练地）讲话（或推理）（sophisticate 的过去式和过去分词形式）**{adj.}++having or appealing to those having worldly knowledge and refinement and savoir-faire																										        													        													        													        				&quot;sophisticated young socialites&quot;; &quot;a sophisticated audience&quot;; &quot;a sophisticated lifestyle&quot;; &quot;a sophisticated book&quot;**{adj.}++复杂的；精致的；久经世故的；富有经验的**{v.}++使变得世故；使迷惑；篡改（sophisticate的过去分词形式）**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('sorrowful', '[ˈsɑːroʊfl]', 'http://dict.youdao.com/dictvoice?audio=sorrowful', '{adj.}++悲伤的，悲痛的，悲哀的；使人悲伤的**{adj.}++experiencing or marked by or expressing sorrow especially that associated with irreparable loss																										        													        													        													        				&quot;sorrowful widows&quot;; &quot;a sorrowful tale of death and despair&quot;; &quot;sorrowful news&quot;; &quot;even in laughter the heart is sorrowful&quot;**{adj.}++悲伤的，伤心的**', '');
