INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('sovereign', '[ˈsɑːvrɪn]', 'http://dict.youdao.com/dictvoice?audio=sovereign', '{n.}++君主，元首；金镑（旧时英国金币，面值一英镑）；独立国**{adj.}++（国家）有主权的，完全独立的；掌握全部权力的，有至高无上的权力的；首要的；非常好的，非常有效的；不折不扣的**{n.}++a nations ruler or head of state usually by hereditary right																					   	同义词：								                                  				    crowned head				    				    				      				    				      				    				                                      				    monarch**{adj.}++(of political bodies) not controlled by outside forces																										        				&quot;a sovereign state&quot;															   	同义词：								                                  				    autonomous				    				    				      				    				      				    				                                      				    independent				    				    				      				    				      				    				                                      				    self-governing**{adj.}++至高无上的；有主权的；拥有最高统治权的；不折不扣的；极好的**{n.}++君主；独立国；最高统治者**', '');
