INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('span', '[spæn]', 'http://dict.youdao.com/dictvoice?audio=span', '{n.}++时间跨度，一段时间；（桥或拱的）墩距，跨距；宽度，翼展；范围，包括的种类；（航海）跨绳；一队人（或动物）；数值范围；一掌的长度**{v.}++持续，贯穿；包括（广大地区），涵盖（多项内容）；横跨，跨越；张开手覆盖（或环绕）；给（动物）套上轭**{adj.}++整洁干净的，照管得很好的（spick and span）**{n.}++the complete duration of something																										        				&quot;the job was finished in the span of an hour&quot;**{a structure that allows people or vehicles to cross an obstacle such as a river or canal or railway etc.}++同义词：								                                  				    bridge**{n.}++[建]跨度，跨距；范围**{vt.}++跨越；持续；以手指测量**', '');
