INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('spherical', '[ˈsfɪrɪk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=spherical', '{adj.}++球形的，球状的；（与）球体（有关）的；在球内（或球面上）形成的；天体的**{adj.}++of or relating to spheres or resembling a sphere																										        				&quot;spherical geometry&quot;**{adj.}++[数]球形的，球面的；[天]天体的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('spice', '[spaɪs]', 'http://dict.youdao.com/dictvoice?audio=spice', '{n.}++香料，调味品；情趣，趣味；赤褐色；糖果；少许**{v.}++给……增添趣味；在……中加香料**{n.}++aromatic substances of vegetable origin used as a preservative**{n.}++香料；情趣；[食品]调味品；少许**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('spill', '[spɪl]', 'http://dict.youdao.com/dictvoice?audio=spill', '{v.}++（使）洒出，泼出，溢出；（东西）倒出，洒落；涌出，蜂拥而出；（光线）透进，倾泻在……上；向（某人）说出秘密；使（某人）从马上（或自行车上）摔下来；（球赛中）掉球；（航海）减少（帆）的受风压力（多指把帆放松）**{n.}++洒出（量），溢出（量）；（从马、自行车上等的）摔下，跌下；职位空缺；（点火用的）纸捻，木片；小塞子**{n.}++liquid that is spilled																										        				&quot;clean up the spills&quot;**{vt.}++使溢出，使流出；使摔下**{vi.}++溢出，流出；摔下；涌流**{n.}++溢出，溅出；溢出量；摔下；小塞子**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('spiral', '[ˈspaɪrəl]', 'http://dict.youdao.com/dictvoice?audio=spiral', '{n.}++螺旋形，螺旋形之物；持续加剧的上升（或下降、恶化）；旋球**{v.}++螺旋式上升（或下降），盘旋上升（或下降）；持续下降，持续恶化；急剧上升**{adj.}++螺旋形的；（医）扭折（骨折的一种）；spiral-bound的简称**{n.}++a plane curve traced by a point circling about the center but at increasing distances from the center**{n.}++[机]螺旋；旋涡；螺旋形之物**{adj.}++螺旋形的；盘旋的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('spite', '[spaɪt]', 'http://dict.youdao.com/dictvoice?audio=spite', '{n.}++恶意，怨恨；不顾，尽管；不由自主地**{vt.}++刁难，使恼怒**{n.}++feeling a need to see others suffer																					   	同义词：								                                  				    malice				    				    				      				    				      				    				                                      				    maliciousness				    				    				      				    				      				    				                                      				    spitefulness				    				    				      				    				      				    				                                      				    venom**{n.}++不顾；恶意；怨恨**{vt.}++刁难；使恼怒**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('splash', '[splæʃ]', 'http://dict.youdao.com/dictvoice?audio=splash', '{v.}++（液体）稀里哗啦地溅落，飞溅；朝……泼洒，使……溅湿；泼溅着水行进，拍打着水游；以显著版面刊载，以大篇幅报道；使有色块，使有光斑； 在（某物）上花很多钱**{n.}++落水声，溅泼声；溅上的液体，溅洒后留下的污渍；掺入饮料的少量液体；色块，光斑；（报章等旨在招徕读者的）重点文章；拍水，戏水；引人注目的效果**{n.}++the sound like water splashing																					   	同义词：								                                  				    plash**{vt.}++溅，泼；用...使液体飞溅**{n.}++飞溅的水；污点；卖弄**', '');
