INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('squash', '[skwɑːʃ]', 'http://dict.youdao.com/dictvoice?audio=squash', '{v.}++压扁，压碎；（使）挤进，（把……）塞进；打断，制止，去除；控制，抑制（情绪）**{n.}++（软式）墙网球，壁球；果汁饮料；南瓜属植物（如南瓜）；拥挤的环境（或处所）；（生）（供显微镜观察用的）软化组织薄片，压片；咯吱声**{n.}++any of numerous annual trailing plants of the genus Cucurbita grown for their fleshy edible fruits																					   	同义词：								                                  				    squash vine**{vt.}++镇压；把…压扁；使沉默**{vi.}++受挤压；发出挤压声；挤入**{n.}++壁球；挤压；咯吱声；南瓜属植物；（英）果汁饮料**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('squat', '[skwɑːt]', 'http://dict.youdao.com/dictvoice?audio=squat', '{v.}++蹲坐；擅自占用（建筑物或土地）；占用王室土地来放牧牛羊；（举重）蹲举**{n.}++蹲坐；被非法占用的建筑物；非法占用空屋；几乎没有（常用于否定句中作强调）；（举重）蹲举训练；（体操）下蹲动作；俯撑腿屈伸（双手撑地下蹲后双腿同时前后跳动）**{adj.}++矮胖的，粗矮的**{n.}++exercising by repeatedly assuming a crouching position with the knees bent; strengthens the leg muscles																					   	同义词：								                                  				    knee bend				    				    				      				    				      				    				                                      				    squatting**{vi.}++蹲，蹲下；蹲坐；蹲伏**{adj.}++蹲着的；矮胖的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('squeeze', '[skwiːz]', 'http://dict.youdao.com/dictvoice?audio=squeeze', '{v.}++挤压，捏；挤出，榨出（液体等）；（使）挤入，塞入；为……挤出时间（squeeze someone/something in）；排挤出（squeeze someone/something out）；敲诈勒索，榨取；严格限制，紧缩（资金）；好不容易取得，勉强成功；紧紧闭上双眼；扣扳机射击，打一整发（子弹）；拍照；（桥牌）逼（对方）放弃一张赢墩牌，逼牌**{n.}++挤压，捏；拥挤，塞满；挤出来的少量事物；紧缩，拮据； 男朋友，女朋友； 勒索（或敲诈）的钱；拥抱；（桥牌）紧逼打法（逼对手扔掉一张重要的牌）；压模，拓印；（棒球）抢分战术；  拥挤的社交舞会**{n.}++the act of gripping and pressing firmly																										        				&quot;he gave her cheek a playful squeeze&quot;															   	同义词：								                                  				    squeezing**{vt.}++挤；紧握；勒索**{n.}++压榨；紧握；拥挤；佣金**', '');
