INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stagger', '[ˈstæɡər]', 'http://dict.youdao.com/dictvoice?audio=stagger', '{v.}++摇摇晃晃地走，蹒跚；使震惊，使大吃一惊；使交错，使错开**{n.}++踉跄，蹒跚；使（物体，物体的组成部分）交错排列；赛跑选手起跑时的梯形排列**{adj.}++交错的，错开的**{n.}++an unsteady uneven gait																					   	同义词：								                                  				    lurch				    				    				      				    				      				    				                                      				    stumble**{v.}++walk as if unable to control ones movements																										        				&quot;The drunken man staggered into the room&quot;															   	同义词：								                                  				    reel				    				    				      				    				      				    				                                      				    keel				    				    				      				    				      				    				                                      				    lurch				    				    				      				    				      				    				                                      				    swag				    				    				      				    				      				    				                                      				    careen**{vt.}++蹒跚；使交错；使犹豫**{vi.}++蹒跚；犹豫**{n.}++蹒跚；交错安排**{adj.}++交错的；错开的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stainless', '[ˈsteɪnləs]', 'http://dict.youdao.com/dictvoice?audio=stainless', '{adj.}++不锈的，防锈的；无污点的；（人，名声）纯洁的，无瑕的**{n.}++不锈钢**{n.}++steel containing chromium that makes it resistant to corrosion																					   	同义词：								                                  				    stainless steel				    				    				      				    				      				    				                                      				    chromium steel**{adj.}++of reputation																					   	同义词：								                                  				    unstained				    				    				      				    				      				    				                                      				    unsullied				    				    				      				    				      				    				                                      				    untainted				    				    				      				    				      				    				                                      				    untarnished**{adj.}++[材]不锈的；纯洁的，未被玷污的；无瑕疵的**', '');
