INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stalk', '[stɔːk]', 'http://dict.youdao.com/dictvoice?audio=stalk', '{n.}++（植物的）茎，秆；（动物的）肉柄，肉茎；柄；（车辆）（转向柱上控制指示仪、灯光等的）手柄；悄悄追踪；高视阔步**{v.}++偷偷接近，潜近；跟踪，盯梢；怒冲冲地走，趾高气扬地走；令人厌恶地穿过，威胁地通过；（不好的气氛）笼罩，蔓延**{n.}++material consisting of seed coverings and small pieces of stem or leaves that have been separated from the seeds																					   	同义词：								                                  				    chaff				    				    				      				    				      				    				                                      				    husk				    				    				      				    				      				    				                                      				    shuck				    				    				      				    				      				    				                                      				    straw				    				    				      				    				      				    				                                      				    stubble**{n.}++（植物的）茎，秆；（支持叶子、果实和花的）[植]梗，[生物]柄；追踪；高视阔步**{vt.}++追踪，潜近；高视阔步**{vi.}++高视阔步地走；潜近，偷偷接近**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stall', '[stɔːl]', 'http://dict.youdao.com/dictvoice?audio=stall', '{n.}++货摊，贩卖处，咨询台；牲畜棚，马厩，牛棚；（房间内的）小隔间，淋浴室，洗手间；（教堂内）唱诗班和牧师的座位；（剧场的）正厅前排座位（stalls）；（发动机的）熄火，（车辆的）抛锚，（飞机的）失速，（轮船的）停泊；（机动车停车场的）车位；（赛马开始前各马站位的）单间马房**{v.}++（使）熄火，抛锚；故意拖延（以赢得时间）；拖住（某人）；暂缓，搁置，停顿；（飞机）失速；（航海）（由于风力不够而）航行失控；把（牲畜）关在厩内（养肥）**{n.}++a compartment in a stable where a single animal is confined and fed**{n.}++[贸易]货摊；畜栏；托辞**{vi.}++停止，停转；拖延**{vt.}++拖延；使停转；使陷于泥中**', '');
