INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('standardize', '[ˈstændərdaɪz]', 'http://dict.youdao.com/dictvoice?audio=standardize', '{v.}++使标准化，使符合标准（或规格）；定出标准，立下标准；（对照标准）确定……的性能，确定……的特性**{v.}++cause to conform to standard or norm																										        				&quot;The weights and measures were standardized&quot;															   	同义词：								                                  				    standardise**{vt.}++使标准化；用标准检验**', '');
