INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('steady', '[ˈstedi]', 'http://dict.youdao.com/dictvoice?audio=steady', '{adj.}++平稳的，稳步的，持续的；稳定的，恒定的；稳固的，牢固的；沉着的，冷静的；（人）稳重的，可靠的**{v.}++使平稳，稳住；（使）稳定，（使）固定（一段时间）；（使）镇定，（使）冷静**{n.}++关系确定的情侣；（支撑大篷车或其他车辆的）支架，撑竿**{int.}++当心，冷静点**{adv.}++稳定地，持续地，稳固地**{n.}++a person loved by another person																					   	同义词：								                                  				    sweetheart				    				    				      				    				      				    				                                      				    sweetie				    				    				      				    				      				    				                                      				    truelove**{v.}++make steady																										        				&quot;steady yourself&quot;															   	同义词：								                                  				    calm				    				    				      				    				      				    				                                      				    becalm**{adj.}++稳定的；不变的；沉着的**{vt.}++使稳定；稳固；使坚定**{adv.}++稳定地；稳固地**{n.}++关系固定的情侣；固定支架**', '');
