INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('steal', '[stiːl]', 'http://dict.youdao.com/dictvoice?audio=steal', '{v.}++偷窃，盗窃；剽窃，窃取（观点）；悄悄地移动；（在棒球比赛中）偷（垒）；（在篮球或冰球比赛中）断（球），截（球）；偷偷做；偷拿，私自拿；抢（镜头、戏等）；（体育运动中）意外赢得；骗走**{n.}++极廉价的物品，低价；（尤指篮球比赛中的）断球；（棒球比赛中的）偷垒；偷窃，行窃；剽窃**{n.}++an advantageous purchase																					   	同义词：								                                  				    bargain				    				    				      				    				      				    				                                      				    buy**{vt.}++[法]偷窃；剽窃；偷偷地做**{n.}++[法]偷窃；便宜货；偷垒**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stem', '[stem]', 'http://dict.youdao.com/dictvoice?audio=stem', '{n.}++（植物、灌木的）茎，干；（高脚酒杯的）柄脚；（语法中的）词干；烟斗柄；主干；船头，艏柱；（机械装置的）阀杆，导杆，棒；血统；（手表的）发条转柄；（文字的）干线，（音符的）符干；鸦片烟枪**{v.}++阻止，遏制；止住（液体的流动）；起源于；去梗，去柄；（船）逆流而行；（滑雪）向外转动（滑雪屐）以便转弯（或减速）；给……装柄**{abbr.}++（STEM）理工科的统称（science, technology, engineering, and mathematics）**{n.}++(linguistics) the form of a word after all affixes are removed																										        				&quot;thematic vowels are part of the stem&quot;															   	同义词：								                                  				    root				    				    				      				    				      				    				                                      				    root word				    				    				      				    				      				    				                                      				    base				    				    				      				    				      				    				                                      				    theme				    				    				      				    				      				    				                                      				    radical**{n.}++干；[植]茎；船首；血统**{vt.}++阻止；除去…的茎；给…装柄**{vi.}++阻止；起源于某事物；逆行**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stereo', '[ˈsterioʊ]', 'http://dict.youdao.com/dictvoice?audio=stereo', '{n.}++立体声，立体声效果；立体声音响设备（器材）；（摄影）立体视镜；（印刷）铅版（stereotype 的简称）**{adj.}++立体声的（stereophonic 的简称）；立体的，体视镜的，有立体感觉的（stereoscopic 的简称）**{n.}++reproducer in which two microphones feed two or more loudspeakers to give a three-dimensional effect to the sound																					   	同义词：								                                  				    stereophony				    				    				      				    				      				    				                                      				    stereo system				    				    				      				    				      				    				                                      				    stereophonic system**{n.}++[声]立体声；立体声系统；[印刷]铅版；立体照片**{adj.}++[声]立体的；立体声的；立体感觉的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stern', '[stɜːrn]', 'http://dict.youdao.com/dictvoice?audio=stern', '{adj.}++（人或其态度）严厉的，认真的；（工作等）严峻的，棘手的；不屈从的，不动摇的**{n.}++船尾，艉部**{n.}++the rear part of a ship																					   	同义词：								                                  				    after part				    				    				      				    				      				    				                                      				    quarter				    				    				      				    				      				    				                                      				    poop				    				    				      				    				      				    				                                      				    tail**{n.}++[船]船尾；末端**{adj.}++严厉的；坚定的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stew', '[stuː]', 'http://dict.youdao.com/dictvoice?audio=stew', '{n.}++炖煮的菜肴；困惑的，焦虑的（in a stew）；鱼塘，大鱼桶；（客机的）乘务员；人工牡蛎养殖场；妓院；闷热**{v.}++炖，煨；自作自受（stew in ones own juice）；思考，担忧；生气，发火；消磨时间，无所事事；（茶）（因久泡）变浓变苦；处于炎热（或沉闷）的空气中；沉浸于**{n.}++agitation resulting from active worry																										        				&quot;dont get in a stew&quot;															   	同义词：								                                  				    fret				    				    				      				    				      				    				                                      				    sweat				    				    				      				    				      				    				                                      				    lather				    				    				      				    				      				    				                                      				    swither**{vt.}++炖，炖汤；焖；忧虑；受闷热**{n.}++炖，炖汤；烦恼；闷热；鱼塘**{vi.}++炖，炖汤；焖；受闷热；忧虑**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stiff', '[stɪf]', 'http://dict.youdao.com/dictvoice?audio=stiff', '{adj.}++（肌肉或关节）酸痛的，僵硬的；不易弯曲的，硬的；艰难的，严厉的；无礼的，生硬的；（酒）烈性的；稠的，难搅拌的；难移动的，不顺滑的；昂贵的；（风）强劲的，猛烈的；过于正式的**{n.}++死尸；……的人；无趣的人，令人讨厌的人；（体育俱乐部的）后备队，候补队 (the stiffs)**{v.}++诈骗，不还钱，（尤指）不给小费；（新产品、电影、节目等）不畅销，彻底失败；冷落，怠慢；杀害某人**{adv.}++非常，彻底地**{n.}++an ordinary man																										        													        				&quot;a lucky stiff&quot;; &quot;a working stiff&quot;**{adj.}++呆板的；坚硬的；严厉的；拘谨的；拘谨的**{adv.}++僵硬地；彻底地**{n.}++死尸；令人讨厌者；[金融]流通票据；劳动者**', '');
