INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('sting', '[stɪŋ]', 'http://dict.youdao.com/dictvoice?audio=sting', '{v.}++（昆虫、动植物）叮，刺，蜇；（使）刺痛，（使）产生剧痛；向……索要惊人高价，敲诈；（使）生气，（使）心烦；刺激**{n.}++刺伤处，蜇伤处；（植物、水母等的）刺毛； 刺痛，灼痛；（身体或心灵的）剧痛，痛苦；（警察为抓住罪犯而设计的）圈套，骗局；（罪犯诈骗钱财的）骗局，诡计**{n.}++a kind of pain; something as sudden and painful as being stung																										        													        				&quot;the sting of death&quot;; &quot;he felt the stinging of nettles&quot;															   	同义词：								                                  				    stinging**{n.}++刺痛；讽刺，刺激；刺毛**{vt.}++刺；驱使；使…苦恼；使…疼痛**{vi.}++刺痛；被刺痛；感到剧痛**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stitch', '[stɪtʃ]', 'http://dict.youdao.com/dictvoice?audio=stitch', '{n.}++（缝纫的）针脚，一针；（缝合伤口的）缝线；缝纫法，编结法；（肋部）突然剧痛；（最少的）一件衣服，一块布；（编织的）一针**{v.}++缝，缝补；缝合（伤口）；操纵局势使……处于劣势，陷害**{n.}++sewing consisting of a link or loop or knot made by drawing a threaded needle through a fabric**{n.}++针脚，[服装]线迹；一针**{vt.}++缝，缝合**{vi.}++缝，缝合**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stone', '[stoʊn]', 'http://dict.youdao.com/dictvoice?audio=stone', '{n.}++石头，石料；石块；宝石；果核；结石； 英石（英国重量单位,相当于6.35千克或14磅）；纪念碑，石碑；（指重量或缺少感情、表情或动作）像石头一样；（天文）陨石；CURLING STONE的简称；（桌游中的）棋子，筹码；排版用石台，石印台；（表示观念或规则固定而不可改变）板上钉钉；石头色，石青色**{v.}++向……扔石头；去核；用石头建（或铺）**{adj.}++石的，石制的**{adv.}++完全地，全部地**{n.}++a lump or mass of hard consolidated mineral matter																					   	同义词：								                                  				    rock**{United States jurist who was named chief justice of the United States Supreme Court in 1941 by Franklin D.}++Roosevelt (1872-1946)																					   	同义词：								                                  				    Harlan Stone				    				    				      				    				      				    				                                      				    Harlan F. Stone				    				    				      				    				      				    				                                      				    Harlan Fisk Stone**{United States journalist who advocated liberal causes (1907-1989)																					   	同义词：								                                  				    I.}++F. Stone				    				    				      				    				      				    				                                      				    Isidor Feinstein Stone**{n.}++[建]石头；结石；[宝]宝石**{adj.}++石的，石制的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('storage', '[ˈstɔːrɪdʒ]', 'http://dict.youdao.com/dictvoice?audio=storage', '{n.}++储存，贮藏；（信息的）存储，存储空间；（家具等的）存放，保管；储存空间，储藏场所；仓库费，仓租**{adj.}++储存的**{n.}++the act of storing something**{n.}++[计]存储；[建][经]仓库；[贸易]贮藏所**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('storm', '[stɔːrm]', 'http://dict.youdao.com/dictvoice?audio=storm', '{n.}++暴风雨，暴风雪，风暴；（感情或反应的）爆发，迸发；强低气压天气，旋风；暴雨般的飞弹（或打击）；（军队的）强击，猛攻；（防雨雪寒风的）外重窗**{v.}++猛烈攻击，突然袭击；气冲冲地走；非常生气地说，怒骂；暴风雨来临；迅速获得成功；（游戏或竞赛中）强有力并且胸有成竹地行动**{n.}++a violent weather condition with winds 64-72 knots (11 on the Beaufort scale) and precipitation and thunder and lightening																					   	同义词：								                                  				    violent storm**{n.}++[气象]暴风雨；大动荡**{vi.}++[气象]起风暴；横冲直撞；狂怒咆哮**{vt.}++猛攻；怒骂**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stout', '[staʊt]', 'http://dict.youdao.com/dictvoice?audio=stout', '{adj.}++（人）肥胖的，壮实的；厚而结实的；不屈不挠的，顽强的**{n.}++烈性黑啤酒；特大号衣服；胖子**{n.}++a strong very dark heavy-bodied ale made from pale malt and roasted unmalted barley and (often) caramel malt with hops**{adj.}++结实的；矮胖的；勇敢的；激烈的**{n.}++矮胖子；[食品]烈性啤酒**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('straighten', '[ˈstreɪtn]', 'http://dict.youdao.com/dictvoice?audio=straighten', '{v.}++（使）变直，（使）变正；挺直身子，直起身来；整理，清理；整顿，（使……）好转**{v.}++straighten up or out; make straight																					   	同义词：								                                  				    unbend**{vt.}++整顿；使…改正；使…挺直；使…好转**{vi.}++变直；好转**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('straightforward', '[ˌstreɪtˈfɔːrwərd]', 'http://dict.youdao.com/dictvoice?audio=straightforward', '{adj.}++简单的，易懂的；（人）诚实的，坦率的**{adv.}++直截了当地，坦率地**{adj.}++free from ambiguity																										        				&quot;a straightforward set of instructions&quot;**{adj.}++简单的；坦率的；明确的；径直的**{adv.}++直截了当地；坦率地**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('strait', '[streɪt]', 'http://dict.youdao.com/dictvoice?audio=strait', '{n.}++海峡，狭窄水道；（尤指财务问题导致的）窘境，困境（straits）**{adj.}++严格的，精确的；（地方）空间有限的，狭窄的；苦恼的**{adv.}++严格地，精确地**{n.}++a narrow channel of the sea joining two larger bodies of water																					   	同义词：								                                  				    sound**{adj.}++狭窄的；苦恼的**{n.}++[海洋]海峡；困境**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('strange', '[streɪndʒ]', 'http://dict.youdao.com/dictvoice?audio=strange', '{adj.}++奇怪的，不寻常的；陌生的，不熟悉的；令人局促不安的，令人不自在的，令人难受的；（亚原子粒子）有奇异性非零值的，奇异性的**{adv.}++奇怪地，不寻常地**{adj.}++being definitely out of the ordinary and unexpected; slightly odd or even a bit weird																										        													        													        				&quot;a strange exaltation that was indefinable&quot;; &quot;a strange fantastical mind&quot;; &quot;what a strange sense of humor she has&quot;															   	同义词：								                                  				    unusual**{adj.}++奇怪的；陌生的；外行的**{adv.}++奇怪地；陌生地，冷淡地**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('stray', '[streɪ]', 'http://dict.youdao.com/dictvoice?audio=stray', '{v.}++走失，迷路；走神，离题；（眼睛，手）悠闲 （或漫不经心）地移动；入歧途，犯错误；有外遇，在别处拈花惹草；游荡，徘徊**{adj.}++（动物）走失的，流浪的；离散的，零落的；（物理量）杂散的**{n.}++走失（流浪）的动物；离群者，走散者；天电干扰**{n.}++homeless cat																					   	同义词：								                                  				    alley cat**{v.}++move about aimlessly or without any destination, often in search of food or employment																					   	同义词：								                                  				    roll				    				    				      				    				      				    				                                      				    wander				    				    				      				    				      				    				                                      				    swan				    				    				      				    				      				    				                                      				    tramp				    				    				      				    				      				    				                                      				    roam				    				    				      				    				      				    				                                      				    cast				    				    				      				    				      				    				                                      				    ramble				    				    				      				    				      				    				                                      				    rove				    				    				      				    				      				    				                                      				    range				    				    				      				    				      				    				                                      				    drift				    				    				      				    				      				    				                                      				    vagabond**{vi.}++流浪；迷路；偏离**{adj.}++迷路的；[动]离群的；偶遇的**{n.}++走失的家畜；流浪者**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('streamline', '[ˈstriːmlaɪn]', 'http://dict.youdao.com/dictvoice?audio=streamline', '{v.}++精简（工商企业、组织、流程等）使效率更高；使……成为流线型**{n.}++（流动液体的）流线**{adj.}++（液体的流动）顺畅的，畅流的；流线型的**{v.}++contour economically or efficiently**{n.}++[流]流线；流线型**{adj.}++[流]流线型的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('strength', '[streŋθ]', 'http://dict.youdao.com/dictvoice?audio=strength', '{n.}++体力，力量；实力，影响力；长处，优势；意志力，毅力；（情感或意见的）强烈程度；（物体或物质的）强度；（食物、药等的）浓度，（酒的）烈度；（风等的）速度，力度；人数，人力；（货币的）价值，坚挺程度；球队的板凳深度，替补队员的水平；力量源泉；（手中所持好牌数目和花色的）牌力**{n.}++the property of being physically or mentally strong																										        				&quot;fatigue sapped his strength&quot;**{n.}++力量；力气；兵力；长处**', '');
