INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('striking', '[ˈstraɪkɪŋ]', 'http://dict.youdao.com/dictvoice?audio=striking', '{adj.}++惊人的，异常的；妩媚动人的，标致的；罢工的；打击的**{n.}++撞击，碰撞**{v.}++打，撞；（用手或武器等）打；罢工（strike 的现在分词形式）**{n.}++the physical coming together of two or more things																					   	同义词：								                                  				    contact				    				    				      				    				      				    				                                      				    impinging**{adj.}++显著的，突出的，惊人的；打击的；[劳经]罢工的**{v.}++打（strike的ing形式）**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('strip', '[strɪp]', 'http://dict.youdao.com/dictvoice?audio=strip', '{v.}++除去，撕掉（外皮或表层）；夺去，剥夺（地位，权力，财产）；脱衣服，脱光……的衣服；表演脱衣舞；为（奶牛）收奶；拆卸，拆开（机器、车辆或引擎 ）；拆散（汽车等）卖零件；使空无一物，搬光（家具、设备等）；（使）（螺丝或齿轮）受损；（为利润）出售（公司资产）；分离（债券的）息票使二者分开出售；（子弹出膛时因膛面磨损而）不旋转**{n.}++（纸、金属、织物等）条，带；带状地带；（比赛时穿的）队服，球衣；商业街；脱衣舞；连环漫画；（定时播出的）广播节目；飞机跑道**{n.}++a relatively long narrow piece of something																										        				&quot;he felt a flat strip of muscle&quot;**{vt.}++剥夺；剥去；脱去衣服**{n.}++带；条状；脱衣舞**', '');
