INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('subscription', '[səbˈskrɪpʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=subscription', '{n.}++（杂志等的）订阅费，（服务的）用户费；订阅，订购； （组织或俱乐部的）会费，捐赠款；集体资助，集体捐助；（对组织或项目的）捐赠协议，认捐书；（文件末尾的）签名，附注；季票（文化活动的季票）；（股票的）认购（协议）；通过预订来全部或部分支付出版费用的方法**{adj.}++（电视或电视频道）付费的，收费的**{n.}++a payment for consecutive issues of a newspaper or magazine for a given period of time**{n.}++捐献；订阅；订金；签署**', '');
