INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('suffice', '[səˈfaɪs]', 'http://dict.youdao.com/dictvoice?audio=suffice', '{v.}++足够，足以；满足……的需求；有能力**{v.}++be sufficient; be adequate, either in quality or quantity																										        				&quot;A B grade doesnt suffice to get me into medical school&quot;															   	同义词：								                                  				    do				    				    				      				    				      				    				                                      				    answer				    				    				      				    				      				    				                                      				    serve**{vt.}++使满足；足够…用；合格**{vi.}++足够；有能力**', '');
