INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('suit', '[suːt]', 'http://dict.youdao.com/dictvoice?audio=suit', '{n.}++套装，西装；（从事特定活动时穿的）成套服装；诉讼；同花色的一组纸牌；（企业或机构中的）高级管理人员；一套蓬帆；追求（常指求婚）；（向当权者提出的）请愿，请求**{v.}++（服装、风格、颜色）使显得漂亮，与……相配；对（某人）方便，满足（某人）需要，合（某人）心意；适合，适宜；随自己的意愿，随性子；（尤指为特定的活动）穿衣**{n.}++a comprehensive term for any proceeding in a court of law whereby an individual seeks a legal remedy																										        				&quot;the family brought suit against the landlord&quot;															   	同义词：								                                  				    lawsuit				    				    				      				    				      				    				                                      				    case				    				    				      				    				      				    				                                      				    cause				    				    				      				    				      				    				                                      				    causa**{vt.}++适合；使适应**{n.}++诉讼；组；套装；恳求**{vi.}++合适；相称**', '');
