INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('summary', '[ˈsʌməri]', 'http://dict.youdao.com/dictvoice?audio=summary', '{n.}++总结，概要**{adj.}++总结性的，概括的；（司法程序）即决的，简易的**{n.}++a brief statement that presents the main points in a concise form																										        				&quot;he gave a summary of the conclusions&quot;															   	同义词：								                                  				    sum-up**{adj.}++performed speedily and without formality																										        													        				&quot;a summary execution&quot;; &quot;summary justice&quot;															   	同义词：								                                  				    drumhead**{adj.}++简易的；扼要的**{n.}++概要，[图情]摘要**', '');
