INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('superb', '[suːˈpɜːrb]', 'http://dict.youdao.com/dictvoice?audio=superb', '{adj.}++极佳的，质量极高的；（信心、控制力、技巧）非同一般的，超凡的；壮丽的，辉煌的；羽毛鲜艳夺目的**{adj.}++of surpassing excellence																										        				&quot;a superb actor&quot;															   	同义词：								                                  				    brilliant**{adj.}++极好的；华丽的；宏伟的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('superficial', '[ˌsuːpərˈfɪʃ(ə)l]', 'http://dict.youdao.com/dictvoice?audio=superficial', '{adj.}++粗浅的，粗略的；（思想）浅薄的，缺乏深度的；表面的，乍看起来的（尤指实际并非如此）；（伤势或伤害）表皮的；（皮肤、土壤或岩石）表层的；不重要的，无关痛痒的；（建筑）面积的，平方的**{adj.}++being or affecting or concerned with a surface; not deep or penetrating emotionally or intellectually																										        													        													        													        													        													        				&quot;superficial similarities&quot;; &quot;a superficial mind&quot;; &quot;his thinking was superficial and fuzzy&quot;; &quot;superficial knowledge&quot;; &quot;the superficial report didnt give the true picture&quot;; &quot;only superficial differences&quot;**{adj.}++表面的；肤浅的**{n.}++表面文章；外表；浅薄的人**', '');
