INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('supersonic', '[ˌsuːpərˈsɑːnɪk]', 'http://dict.youdao.com/dictvoice?audio=supersonic', '{adj.}++超音速的**{n.}++超音速，超声波；超音速飞机**{adj.}++(of speed) greater than the speed of sound in a given medium (especially air)																										        				&quot;a supersonic bomber flies so fast that it must release its bombs while the target is still over the horizon&quot;**{adj.}++[流][力]超音速的；[声]超声波的**{n.}++[流]超音速；[声]超声波**', '');
