INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('supplement', '[ˈsʌplɪmənt]', 'http://dict.youdao.com/dictvoice?audio=supplement', '{n.}++补充物，增补物；营养片剂，补品；补助，补贴；额外服务费用；（报纸或杂志的）副刊，增刊；（书籍的）补编，附录；（几何）补角**{v.}++增加，增补**{n.}++textual matter that is added onto a publication; usually at the end																					   	同义词：								                                  				    addendum				    				    				      				    				      				    				                                      				    postscript**{a quantity added (e.}++g. to make up for a deficiency)																					   	同义词：								                                  				    supplementation**{n.}++补充，[图情]补遗；补充物；附录**{vt.}++补充，增补**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('support', '[səˈpɔːrt]', 'http://dict.youdao.com/dictvoice?audio=support', '{v.}++支持，拥护，鼓励；帮助，援助；支撑，承受（人或建筑物等的重量）；供养，赡养；资助，赞助；追随（或支持）（某个运动队）；证实，确认；（计算机，操作系统）支持（程序，语言，装置的）运行 ；支持……的生存；忍受，容忍；（在流行音乐会上）当助演，担任演出嘉宾；支付……费用，（尤指）用钱维持（不良嗜好，如毒品）；胜任**{n.}++支持，拥护；帮助，援助；赞助，资助；支撑物，支柱；（身体部位的）支持器，托；支撑，支承；（音乐会、演出的）助演演员，助演乐队；证实，证明；信息供应，信息支持；（战争中的）支援；抚养，供养；支持者，拥护者**{n.}++the activity of providing for or maintaining by supplying with money or necessities																										        													        				&quot;his support kept the family together&quot;; &quot;they gave him emotional support during difficult times&quot;**{vt.}++[医][机]支持，支撑，[计][军]支援；扶持，帮助；[法]赡养，供养**{n.}++[医][机]支持，维持；[计][军]支援，供养；支持者，支撑物**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('suppress', '[səˈpres]', 'http://dict.youdao.com/dictvoice?audio=suppress', '{v.}++（尤指用武力）镇压，压制；阻止（进程或活动）；封锁，隐瞒（消息）；抑制（生理过程）；克制（感情或反应），忍住；部分（或完全）消除（电干扰）；（心理分析）自觉抑制（不愉快的想法，记忆）**{v.}++to put down by force or authority																										        				&quot;suppress a nascent uprising&quot;															   	同义词：								                                  				    stamp down				    				    				      				    				      				    				                                      				    inhibit				    				    				      				    				      				    				                                      				    subdue				    				    				      				    				      				    				                                      				    conquer				    				    				      				    				      				    				                                      				    curb**{vt.}++抑制；镇压；废止**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('surpass', '[sərˈpæs]', 'http://dict.youdao.com/dictvoice?audio=surpass', '{v.}++超过，胜过，优于；比（预期的或希望的）更好；超越自我；超出（理解范围）**{v.}++distinguish oneself																					   	同义词：								                                  				    excel				    				    				      				    				      				    				                                      				    stand out**{vt.}++超越；胜过，优于；非…所能办到或理解**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('surplus', '[ˈsɜːrplʌs]', 'http://dict.youdao.com/dictvoice?audio=surplus', '{n.}++过剩，剩余，过剩量；盈余，顺差；超净资产**{adj.}++过剩的，剩余的，多余的；（商店）出售剩余（或过时的）军用品的**{v.}++甩卖，变卖**{n.}++a quantity much larger than is needed																					   	同义词：								                                  				    excess				    				    				      				    				      				    				                                      				    surplusage				    				    				      				    				      				    				                                      				    nimiety**{adj.}++more than is needed, desired, or required																										        				&quot;surplus cheese distributed to the needy&quot;															   	同义词：								                                  				    excess				    				    				      				    				      				    				                                      				    extra				    				    				      				    				      				    				                                      				    redundant				    				    				      				    				      				    				                                      				    spare				    				    				      				    				      				    				                                      				    supererogatory				    				    				      				    				      				    				                                      				    superfluous				    				    				      				    				      				    				                                      				    supernumerary**{n.}++[数]剩余；[贸易]顺差；[会计]盈余；[电子][经]过剩**{adj.}++[数][电子]剩余的；[经]过剩的**', '');
