INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('suspicious', '[səˈspɪʃəs]', 'http://dict.youdao.com/dictvoice?audio=suspicious', '{adj.}++感觉可疑的，怀疑的；不信任的，持怀疑态度的；令人怀疑的，引起怀疑的**{adj.}++openly distrustful and unwilling to confide																					   	同义词：								                                  				    leery				    				    				      				    				      				    				                                      				    mistrustful				    				    				      				    				      				    				                                      				    untrusting				    				    				      				    				      				    				                                      				    wary**{adj.}++可疑的；怀疑的；多疑的**', '');
