INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('swell', '[swel]', 'http://dict.youdao.com/dictvoice?audio=swell', '{v.}++（身体部位）肿胀，膨胀， 使（某物）膨胀，使肿胀；（使）鼓起，（使）隆起；（使）增长，增加，扩大；（声音）逐渐增强，变响亮；（情绪）高涨，充满；波涛汹涌**{n.}++海浪的涌动，涌浪；（音量的）增强；感情的高涨；（规模或数量的）增长，增加；（尤指身体部位）凸起的形状，鼓出处，隆起处； 重要人士，时髦人物；（管风琴、簧风琴的）音量调节器**{adj.}++第一流的，极好的； 漂亮的，时髦的**{adv.}++极好地，非常顺利地**{n.}++the undulating movement of the surface of the open sea																					   	同义词：								                                  				    crestless wave**{vi.}++膨胀；肿胀；隆起**{vt.}++使膨胀；使隆起**{n.}++肿胀；隆起**{adj.}++漂亮的；一流的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('switch', '[swɪtʃ]', 'http://dict.youdao.com/dictvoice?audio=switch', '{n.}++开关，电闸；骤变，突变；交换机；（计算机）切换； （铁路的）转辙器，道岔；（细软的）枝条，鞭子；假发；（在英国使用借记卡付账的一种）转换系统（Switch）**{v.}++（用开关）打开，关闭；（使）改变，转变；交换，调换；转移（注意力）；（与某人）交换工作，调班； 用枝条击打，轻拂**{n.}++control consisting of a mechanical or electrical or electronic device for making or breaking or changing the connections in a circuit																					   	同义词：								                                  				    electric switch				    				    				      				    				      				    				                                      				    electrical switch**', '');
