INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tack', '[tæk]', 'http://dict.youdao.com/dictvoice?audio=tack', '{n.}++大头钉，图钉；（为定样临时缝上的）粗缝针脚；马具，鞍辔；（航海）抢风调向，抢风航行路线，抢风航程；（系住帆角的）系帆索；（用系帆索）系住的帆角；行动方针，策略；廉价且难看的物品；黏着性，黏着力；（航海）（系住帆角的）系帆索**{v.}++（用平头钉）钉上，固定住；（为定样而）用粗缝针脚缝；戗风行驶，蜿蜒航行；（尤指画蛇添足地）增补，附加**{n.}++the heading or position of a vessel relative to the trim of its sails**{n.}++[五金]大头钉；粗缝；行动方针；食物**{vt.}++附加；以大头针钉住**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tackle', '[ˈtæk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=tackle', '{v.}++应付，解决（难题或局面）；与……交涉；（足球、曲棍球等比赛中）抢断；（橄榄球等比赛中）擒抱并摔倒（对方球员）；擒获；对付，打（尤指罪犯）；质问，责问；反对，反抗**{n.}++（足球等中的）抢断球；（橄榄球或美式足球）擒抱摔倒；（美式足球中的）阻截队员；体育器械，（尤指）渔具；（吊起重物用的）索具，滑轮；男性性器官**{n.}++the person who plays that position on a football team																										        				&quot;the right tackle is a straight A student&quot;**{gear consisting of ropes etc.}++supporting a ships masts and sails																					   	同义词：								                                  				    rigging**{n.}++[机]滑车；装备；用具；扭倒**{vt.}++处理；抓住；固定；与…交涉**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tact', '[tækt]', 'http://dict.youdao.com/dictvoice?audio=tact', '{n.}++得体，乖巧，机敏；鉴赏力**{n.}++consideration in dealing with others and avoiding giving offence																					   	同义词：								                                  				    tactfulness**{n.}++机智；老练；圆滑；鉴赏力**', '');
