INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tangle', '[ˈtæŋɡ(ə)l]', 'http://dict.youdao.com/dictvoice?audio=tangle', '{v.}++（使）纠结，（使）缠结； 和……发生冲突，和……发生纠纷；（思想、局势变得）纷乱，混乱**{n.}++（线、毛发等的）缠结的一团，乱团；混乱，纷乱；争吵，打架；大型棕色海藻（尤指昆布）**{n.}++a twisted and tangled mass that is highly interwoven																										        				&quot;they carved their way through the tangle of vines&quot;**{n.}++纠纷；混乱状态**{vt.}++使纠缠；处于混乱状态**{vi.}++缠结；乱作一团**', '');
