INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tape', '[teɪp]', 'http://dict.youdao.com/dictvoice?audio=tape', '{n.}++磁带，录音带；录了音的盒式磁带，录了像的盒式磁带；胶带，胶布；（用来绑东西或作界限标记的）布条，线带；（赛跑中的）终点线；卷尺**{v.}++（用磁带）录音，录像；用胶带粘贴；用带子系紧； 用（绷带）包扎（受伤部位）**{n.}++a long thin piece of cloth or paper as used for binding or fastening																										        													        				&quot;he used a piece of tape for a belt&quot;; &quot;he wrapped a tape around the package&quot;**{n.}++胶带；[计]磁带；带子；卷尺**{vt.}++录音；用带子捆扎；用胶布把…封住**', '');
