INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('through', '[θruː]', 'http://dict.youdao.com/dictvoice?audio=through', '{prep.}++穿过，从一端到另一端；透过（玻璃、窗户等）；越过（地区或空间），在……之间；断开，洞穿；（在应停处）径直通过；以，凭借；贯穿，遍及；自始至终，从头至尾；直至；彻底地（查看或检查）；经历，度过；胜利完成；（提议、观点）获得通过，得到批准**{adv.}++从一端到另一端；完全地，彻底地，十足地；接通电话；通过（障碍、阶段或测试）；直达，迳直；从头至尾；到（某个阶段或某种程度）；切断， 凿穿；胜利完成**{adj.}++完成的，结束的；直达的，直通的，中途不停的；断绝的；（公路）对穿的，双向的；（房间）与楼两对面通透的；（竞赛队，竞技者）进入下一轮（比赛）的**{adj.}++having finished or arrived at completion																										        													        				&quot;after the treatment, the patient is through except for follow-up&quot;; &quot;almost through with his studies&quot;															   	同义词：								                                  				    done				    				    				      				    				      				    				                                      				    through with(p)**{(of a route or journey etc.}++) continuing without requiring stops or changes																										        													        													        				&quot;a through street&quot;; &quot;a through bus&quot;; &quot;through traffic&quot;**{prep.}++通过；穿过；凭借**{adv.}++彻底；从头至尾**{adj.}++[交]直达的；过境的；完结的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('ticket', '[ˈtɪkɪt]', 'http://dict.youdao.com/dictvoice?audio=ticket', '{n.}++票，入场券；（交通违章）通知单，罚款单；（政党在选举中支持的）候选人名单；（竞选时所支持的）纲领，政见；（商店中标明货物价格、尺码等的）标签；彩票，奖券；途径；（货物）收条；（船员、飞行员等的）执照；工单；退役证书；……人，……家伙**{v.}++售票；给（违章停车、超速行驶的人）开罚单；（为显示价格、尺寸等）贴标签于；给定目标；注定**{n.}++a commercial document showing that the holder is entitled to something (as to ride on public transportation or to enter a public entertainment)**{n.}++票；[经]入场券，标签；（美）候选人名单；证明书；交通罚款单**{vt.}++加标签于；指派；对…开出交通违规罚单**', '');
