INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tile', '[taɪl]', 'http://dict.youdao.com/dictvoice?audio=tile', '{n.}++（贴墙或铺地用的）瓷砖，地砖；（铺屋顶的）瓦，瓦片；（拼字游戏、麻将等牌戏中的）（一张）牌；（棋盘游戏的）棋子；（数）平铺**{v.}++铺瓦，铺砖；（计算机）平铺（窗口）**{n.}++a flat thin rectangular slab (as of fired clay or rubber or linoleum) used to cover surfaces**{n.}++[建]瓷砖，瓦片**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tilt', '[tɪlt]', 'http://dict.youdao.com/dictvoice?audio=tilt', '{v.}++（使）倾斜，（使）倾侧；（使）倾向于，（使）偏向于；俯仰（摄影机）；（格斗中）持矛冲刺（或比武）；以言词或文字抨击**{n.}++倾斜，倾侧，倾斜度；（对某人、某信仰或某行为的）倾向，偏向；（意欲赢得某物或战胜某人的）企图，尝试；（口头或文字的）抨击，攻击；（摄影机的）俯仰转动，上下摇摄；（双人或两队间的）比赛，竞赛；林中小屋；骑马持矛冲刺，马上比枪，比武**{n.}++a combat between two mounted knights tilting against each other with blunted lances																					   	同义词：								                                  				    joust**{vi.}++[航][气象]倾斜；翘起；以言词或文字抨击**{vt.}++[航][气象]使倾斜；使翘起**{n.}++[航][气象]倾斜**', '');
