INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tiresome', '[ˈtaɪərsəm]', 'http://dict.youdao.com/dictvoice?audio=tiresome', '{adj.}++烦人的，令人厌烦的**{adj.}++so lacking in interest as to cause mental weariness																										        				&quot;the tiresome chirping of a cricket&quot;															   	同义词：								                                  				    boring				    				    				      				    				      				    				                                      				    deadening				    				    				      				    				      				    				                                      				    dull				    				    				      				    				      				    				                                      				    ho-hum				    				    				      				    				      				    				                                      				    irksome				    				    				      				    				      				    				                                      				    slow				    				    				      				    				      				    				                                      				    tedious				    				    				      				    				      				    				                                      				    wearisome**{adj.}++烦人的，无聊的；令人讨厌的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('toad', '[toʊd]', 'http://dict.youdao.com/dictvoice?audio=toad', '{n.}++蟾蜍，癞蛤蟆；（侮辱性用语）讨厌鬼**{n.}++any of various tailless stout-bodied amphibians with long hind limbs for leaping; semiaquatic and terrestrial species																					   	同义词：								                                  				    frog				    				    				      				    				      				    				                                      				    toad frog				    				    				      				    				      				    				                                      				    anuran				    				    				      				    				      				    				                                      				    batrachian				    				    				      				    				      				    				                                      				    salientian**{n.}++[脊椎]蟾蜍；癞蛤蟆；讨厌的家伙**', '');
