INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tone', '[toʊn]', 'http://dict.youdao.com/dictvoice?audio=tone', '{n.}++语气，腔调，口吻；气氛，基调，风格；（尤指乐器或电子音响设备的）音质，音色；色调，明暗；强健状况，（尤指肌肉的）紧实度；（电话或应答机等发出的）声音信号；（音乐）全音，音程；（说话的）声调，音调；（生理）神经纤维的正常活动状态**{v.}++使强健，使结实；与……协调，与……相配；（用化学溶液使黑白照片在润色时）变色；用某种调子说**{n.}++the quality of a persons voice																										        													        				&quot;he began in a conversational tone&quot;; &quot;he spoke in a nervous tone of voice&quot;															   	同义词：								                                  				    tone of voice**{the elastic tension of living muscles, arteries, etc.}++that facilitate response to stimuli																					   	同义词：								                                  				    tonicity				    				    				      				    				      				    				                                      				    tonus**', '');
