INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('torpedo', '[tɔːrˈpiːdoʊ]', 'http://dict.youdao.com/dictvoice?audio=torpedo', '{n.}++鱼雷，水雷；信号雷管；掼炮；油井爆破筒；电鳐**{v.}++用鱼雷袭击；彻底破坏，完全摧毁**{n.}++a professional killer who uses a gun																					   	同义词：								                                  				    gunman				    				    				      				    				      				    				                                      				    gunslinger				    				    				      				    				      				    				                                      				    hired gun				    				    				      				    				      				    				                                      				    gun				    				    				      				    				      				    				                                      				    gun for hire				    				    				      				    				      				    				                                      				    triggerman				    				    				      				    				      				    				                                      				    hit man				    				    				      				    				      				    				                                      				    hitman				    				    				      				    				      				    				                                      				    shooter**{n.}++鱼雷；[军]水雷；油井爆破筒；电鳐；职业杀手**{vt.}++破坏；用鱼雷袭击**', '');
