INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('toss', '[tɔːs]', 'http://dict.youdao.com/dictvoice?audio=toss', '{v.}++（轻轻地或随意地）扔，抛，掷；向后甩（头发或身体部位）；（使）摇摆，挥动，颠簸；（在液体中）搅拌（食物），拌匀；（为……）掷硬币决定，掷币猜边儿；把（煎饼）颠起翻面；除掉，抛弃；（马）摔下（骑手）；搜（某地）**{n.}++掷硬币决定；（轻轻的或随意的）扔，抛，掷；向上甩头，猛仰头；（尤指比赛或游戏中）投掷；根本不在乎**{n.}++the act of flipping a coin																					   	同义词：								                                  				    flip**{n.}++投掷；摇荡；投掷的距离；掷币赌胜负**{vt.}++投掷；使…不安；突然抬起；使…上下摇动；与…掷币打赌**{vi.}++辗转；被乱扔；颠簸；掷钱币决定某事**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tow', '[toʊ]', 'http://dict.youdao.com/dictvoice?audio=tow', '{v.}++拖，牵引（车、船等）；（人）牵引，拖带（某人，某物）**{n.}++（对车船等的）牵引，拖；牵引绳，拖链**{n.}++the act of hauling something (as a vehicle) by means of a hitch or rope																										        				&quot;the truck gave him a tow to the garage&quot;															   	同义词：								                                  				    towage**{v.}++drag behind																										        				&quot;Horses used to tow barges along the canal&quot;**{n.}++拖；[纺]麻的粗纤维；拖曳所用之绳**{vt.}++拖；牵引；曳**', '');
