INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('track', '[træk]', 'http://dict.youdao.com/dictvoice?audio=track', '{n.}++小道，小径；踪迹，足迹，车辙；（铁路的）轨道；（窗帘、推拉门等的）滑竿，滑轨；（火车站的）站台；赛道，跑道；（移动的）路径，方向；（唱片或光盘等上的）歌曲，曲子；音轨，声道；（推土机等的）履带；径赛运动，田径运动；（同龄学生依智力编排的）班，组；思路，行为方式；（分轨制教育的）课程；（机动车辆轮胎的横向）轮距**{v.}++追查，追踪；（尤指用特殊电子设备）跟踪；记录……的进展；跟踪摄影，移动摄影；（录制设备的移动部件）运转正常；把（学生）按能力分班（或组）；留下（脏）足迹；（以某方式或沿某方向）移动；跟随（利率，股价等）；（电子）统调；从岸上拉（独木舟）前进**{n.}++a line or route along which something travels or moves																										        				&quot;the track of an animal&quot;															   	同义词：								                                  				    path				    				    				      				    				      				    				                                      				    course**{n.}++[铁路]轨道；[古生]足迹，踪迹；小道**{vt.}++追踪；通过；循路而行；用纤拉**{vi.}++追踪；走；留下足迹**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('trade', '[treɪd]', 'http://dict.youdao.com/dictvoice?audio=trade', '{n.}++贸易，买卖；行业；同行业者，同仁（the trade）；营业额，交易量；（尤指需要特殊技术和手工劳动的）职业，行当；交换，交易； （体育界）转会，交换运动员； 执照酒商；信风，贸易风（trades）；股票交易**{v.}++做买卖，做生意；营运，营业；（在证券交易所）交易，买卖；用……进行交换，互相交换；（某物）替代（某物）；对打，对骂； 将（运动员）转会（或转队）；交换，对换（位置或处境）**{n.}++the commercial exchange (buying and selling on domestic or international markets) of goods and services																										        													        				&quot;Venice was an important center of trade with the East&quot;; &quot;they are accused of conspiring to constrain trade&quot;**{n.}++贸易，[贸易]交易；[劳经]行业；职业**{vi.}++[贸易]交易，买卖；以物易物**', '');
