INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tramp', '[træmp]', 'http://dict.youdao.com/dictvoice?audio=tramp', '{v.}++拖着沉重的脚步走，踩，踏；长途跋涉**{n.}++流浪汉，流浪乞丐；沉重的脚步声；长途步行，徒步旅行；（航线不定的）货船；（为挖地而穿的长统靴底）金属片；铲尖；不正经的女人**{n.}++a disreputable vagrant																										        				&quot;a homeless tramp&quot;															   	同义词：								                                  				    hobo				    				    				      				    				      				    				                                      				    bum**{vi.}++流浪；践踏，踩；脚步沉重地行走**{n.}++流浪者；沉重的脚步声；徒步旅行**{vt.}++践踏，踩；走过**', '');
