INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tranquil', '[ˈtræŋkwɪl]', 'http://dict.youdao.com/dictvoice?audio=tranquil', '{adj.}++平静的，宁静的**{adj.}++(of a body of water) free from disturbance by heavy waves																										        				&quot;a lake of tranquil blue water reflecting a tranquil blue sky&quot;															   	同义词：								                                  				    placid				    				    				      				    				      				    				                                      				    quiet				    				    				      				    				      				    				                                      				    still				    				    				      				    				      				    				                                      				    smooth				    				    				      				    				      				    				                                      				    unruffled**{adj.}++安静的，平静的；安宁的；稳定的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('transaction', '[trænˈzækʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=transaction', '{n.}++交易，买卖，业务；（学术团体会议的）议事录，公报；（人与人之间的）交流，相互影响；事务（元），事项**{n.}++the act of transacting within or between groups (as carrying on commercial activities)																										        				&quot;no transactions are possible without him&quot;															   	同义词：								                                  				    dealing				    				    				      				    				      				    				                                      				    dealings**{n.}++[贸易]交易；[计]事务；办理；会报，[图情]学报**', '');
