INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('transition', '[trænˈzɪʃ(ə)n]', 'http://dict.youdao.com/dictvoice?audio=transition', '{n.}++过渡，转变；（分子生物）转换；（乐）临时转调；（物理）跃迁，转变**{v.}++转变，过渡**{n.}++the act of passing from one state or place to the next																					   	同义词：								                                  				    passage**{n.}++过渡；转变；[分子生物]转换；变调**', '');
