INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('transplant', '[trænsˈplænt]', 'http://dict.youdao.com/dictvoice?audio=transplant', '{v.}++移植（器官、皮肤等）；（使）迁移，（使）移居；移栽，移植（植物）**{n.}++（器官、皮肤等的）移植（手术）；移植的器官，移植物；移居者，迁居者**{n.}++(surgery) tissue or organ transplanted from a donor to a recipient; in some cases the patient can be both donor and recipient																					   	同义词：								                                  				    graft**{vt.}++[林]移植；迁移；使移居**{n.}++[林]移植；移植器官；被移植物；移居者**{vi.}++[林]移植；迁移；移居**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('transverse', '[ˈtrænzvɜːrs]', 'http://dict.youdao.com/dictvoice?audio=transverse', '{adj.}++横向的；横断的；贯轴的**{n.}++横断面；贯轴；横肌**{adj.}++extending or lying across; in a crosswise direction; at right angles to the long axis																										        													        				&quot;from the transverse hall the stairway ascends gracefully&quot;; &quot;transverse colon&quot;															   	同义词：								                                  				    cross(a)				    				    				      				    				      				    				                                      				    transversal				    				    				      				    				      				    				                                      				    thwartwise**{adj.}++横向的；横断的；贯轴的**{n.}++横断面；贯轴；横肌**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('traverse', '[trəˈvɜːrs]', 'http://dict.youdao.com/dictvoice?audio=traverse', '{v.}++横穿，穿过；横越岩石面的攀爬；（滑雪时）横线下（坡）；整体考虑（问题），全面讨论；来回移动，斜向移动；转动（大炮等带轴设备）；否认（一项指控），反驳**{n.}++（爬陡坡时的）斜向攀上（下）；越过，穿过；滑雪横切运动；（逆风时轮船所作的）曲线航行，折航；横断物，横档；通廊，楼厢；（大炮等的）横转装置；机器部件的横转，横向运动；（测量用的）导线；（军）（壕沟的）土护墙，屏障**{adj.}++横贯的**{n.}++a horizontal beam that extends across something																					   	同义词：								                                  				    trave				    				    				      				    				      				    				                                      				    crossbeam				    				    				      				    				      				    				                                      				    crosspiece**{n.}++穿过；横贯；横木**{vt.}++穿过；反对；详细研究；在…来回移动**{vi.}++横越；[机]旋转；来回移动**{adj.}++横贯的**', '');
