INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('trench', '[trentʃ]', 'http://dict.youdao.com/dictvoice?audio=trench', '{n.}++壕沟，沟渠；海沟，海底沟；战壕，堑壕；堑壕阵地；一战时期法国北部和比利时的堑壕战（the trenches）；战壕雨衣**{v.}++在（地）上开沟，在……上挖战壕；翻（田地，花园）的地**{n.}++a ditch dug as a fortification having a parapet of the excavated earth**{n.}++沟，沟渠；战壕；堑壕**{vi.}++挖战壕；侵害**', '');
