INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tribute', '[ˈtrɪbjuːt]', 'http://dict.youdao.com/dictvoice?audio=tribute', '{n.}++（表示敬意的）礼物，颂辞，行为；（良好效果或影响的）体现，显示；（尤指旧时一国向他国交纳的）贡品，贡金；（用于支付矿工工资，或给矿厂主、出租人的）矿石份子**{adj.}++（尤指团体或音乐家）（通过模仿）表演著名乐曲的**{n.}++something given or done as an expression of esteem																					   	同义词：								                                  				    testimonial**{n.}++礼物；[税收]贡物；颂词**', '');
