INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('trivial', '[ˈtrɪviəl]', 'http://dict.youdao.com/dictvoice?audio=trivial', '{adj.}++琐碎的，不重要的；容易解决的，不费吹灰之力的；（人）务小的，浅薄的；（数学）平凡的**{adj.}++(informal) small and of little importance																					   	同义词：								                                  				    fiddling				    				    				      				    				      				    				                                      				    footling				    				    				      				    				      				    				                                      				    lilliputian				    				    				      				    				      				    				                                      				    little				    				    				      				    				      				    				                                      				    niggling				    				    				      				    				      				    				                                      				    piddling				    				    				      				    				      				    				                                      				    piffling				    				    				      				    				      				    				                                      				    petty				    				    				      				    				      				    				                                      				    picayune**{adj.}++不重要的，琐碎的；琐细的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('trolley', '[ˈtrɑːli]', 'http://dict.youdao.com/dictvoice?audio=trolley', '{n.}++手推车；（送食品饮料的）小车，台车；有轨电车；无轨电车；电车触轮（与架空电线接触以驱动电车）；有轨缆车，架空缆车；（医院用的）担架车**{v.}++乘电车；用手推车运**{n.}++a wheeled vehicle that runs on rails and is propelled by electricity																					   	同义词：								                                  				    streetcar				    				    				      				    				      				    				                                      				    tram				    				    				      				    				      				    				                                      				    tramcar				    				    				      				    				      				    				                                      				    trolley car**{n.}++手推车；（美）无轨电车（等于streetear）；（英）有轨电车（等于trolleybus）；空中吊运车**{vi.}++[车辆]乘电车**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('troop', '[truːp]', 'http://dict.youdao.com/dictvoice?audio=troop', '{n.}++军队，士兵；部队，（尤指）骑兵连，装甲连；童子军中队；一组，一群**{v.}++成群结队地走，列队行进；（孤身一人）缓步前行，稳步前行；（尤指被告知）成群前往**{adj.}++军队的，有关或涉及军队的**{n.}++a group of soldiers**{n.}++军队；组；群；多数**{vi.}++群集；成群而行；结队**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tropic', '[ˈtrɑːpɪk]', 'http://dict.youdao.com/dictvoice?audio=tropic', '{n.}++热带，热带地区（the tropics）；回归线；（天文）天球的回归线**{adj.}++热带的（同 tropical）；向性的，亲……的；（激素或其作用）向性的，刺激另一内分泌腺活动的（同 trophic）**{n.}++either of two parallels of latitude about 23.5 degrees north and south of the equator representing the points farthest north and south at which the sun can shine directly overhead and constituting the boundaries of the Torrid Zone or tropics**{adj.}++relating to or situated in or characteristic of the tropics (the region on either side of the equator)																										        													        				&quot;tropical islands&quot;; &quot;tropical fruit&quot;															   	同义词：								                                  				    tropical**{n.}++[地理]热带；[天]回归线**{adj.}++[地理]热带的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tropical', '[ˈtrɑːpɪk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=tropical', '{adj.}++热带的，热带地区的；（天气）湿热的**{adj.}++relating to or situated in or characteristic of the tropics (the region on either side of the equator)																										        													        				&quot;tropical islands&quot;; &quot;tropical fruit&quot;															   	同义词：								                                  				    tropic**{adj.}++[地理]热带的；热情的；酷热的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('trot', '[trɑːt]', 'http://dict.youdao.com/dictvoice?audio=trot', '{n.}++（马等动物的）小跑，慢跑；骑马小跑；人的小步跑；腹泻，拉稀（the trots）；走运时期，倒霉时期；快步马驾车赛（the trots）；（学生用来作弊的）笔记，答案；（侮辱性用语）左倾分子，托派分子；刚学步的小孩；老太婆**{v.}++（马等四足动物）快步，疾走；步行，走；小步快跑，疾行；骑马小跑；连珠炮似地说，急匆匆地做**{n.}++a slow pace of running																					   	同义词：								                                  				    jog				    				    				      				    				      				    				                                      				    lope**{n.}++（人）慢跑；马小跑的步态；小跑的马蹄声；刚学步的小孩；老太婆；腹泻；（学生作弊用的）译文对照本**{vi.}++（马）小跑；（人）慢跑；快步走**', '');
