INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tuberculosis', '[tuːˌbɜːrkjəˈloʊsɪs]', 'http://dict.youdao.com/dictvoice?audio=tuberculosis', '{n.}++结核病（尤指肺结核）**{n.}++infection transmitted by inhalation or ingestion of tubercle bacilli and manifested in fever and small lesions (usually in the lungs but in various other parts of the body in acute stages)																					   	同义词：								                                  				    TB				    				    				      				    				      				    				                                      				    T.B.**{n.}++[内科]肺结核；结核病**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tug', '[tʌɡ]', 'http://dict.youdao.com/dictvoice?audio=tug', '{v.}++（用力地）拉，拖，拽；（迅速地）穿（衣服）；用拖船拖（船）；努力做**{n.}++拖船；猛拉，拽；一股强烈的感情；强大的吸引力；（滑翔机的）拖航飞机；（系在马鞍上支承车杠或挽绳的）圆环；苦干；竞争，较量**{n.}++a sudden abrupt pull																					   	同义词：								                                  				    jerk**{n.}++拖船；拖曳；苦干**{vi.}++用力拉；竞争；努力做**{vt.}++用力拉；较量；用拖船拖**', '');
