INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('twist', '[twɪst]', 'http://dict.youdao.com/dictvoice?audio=twist', '{v.}++使弯曲；（使）扭曲变形；扭动身体；扭伤（脚踝等）；旋转，转动；编织，捻在一起；缠绕；歪曲，曲解；蜿蜒，曲折；欺诈；牌面朝上**{n.}++扭动，转动；弯曲处，拐弯处；转折，变化；螺旋形物体；扭摆舞（the twist）；扭歪，（性格）反常；（棉，丝） 合股线；混合酒；欺诈；（棍棒或其他物体） 扭转度；扭转力，转矩；绕轴旋转前进**{n.}++an unforeseen development																					   	同义词：								                                  				    turn				    				    				      				    				      				    				                                      				    turn of events**{vt.}++捻；拧；扭伤；编织；使苦恼**{n.}++[力]扭曲；拧；扭伤**{vi.}++扭动；弯曲**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('tyranny', '[ˈtɪrəni]', 'http://dict.youdao.com/dictvoice?audio=tyranny', '{n.}++暴虐，专横；暴君统治，暴君统治的国家；严酷的事物；（对人们生活和行为方式的）控制，左右； （不中意或令人不快的）必需品；（尤指古希腊）僭主统治，僭王统治**{n.}++a form of government in which the ruler is an absolute dictator (not restricted by a constitution or laws or opposition etc.)																					   	同义词：								                                  				    dictatorship				    				    				      				    				      				    				                                      				    absolutism				    				    				      				    				      				    				                                      				    authoritarianism				    				    				      				    				      				    				                                      				    Caesarism				    				    				      				    				      				    				                                      				    despotism				    				    				      				    				      				    				                                      				    monocracy				    				    				      				    				      				    				                                      				    one-man rule				    				    				      				    				      				    				                                      				    shogunate				    				    				      				    				      				    				                                      				    Stalinism				    				    				      				    				      				    				                                      				    totalitarianism**{n.}++暴政；专横；严酷；残暴的行为（需用复数）**', '');
