INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('ultimate', '[ˈʌltɪmət]', 'http://dict.youdao.com/dictvoice?audio=ultimate', '{adj.}++最终的，最后的；最根本的，最基础的；极限的，终极的；首要的，决定性的；（太空或时空中）最遥远的；（物理）极限的**{n.}++最好的事物，最终的事物；最终（或最根本）的事实（或原则）；极限飞盘（Ultimate Frisbee 的简称）**{v.}++结束**{n.}++the finest or most superior quality of its kind																										        				&quot;the ultimate in luxury&quot;**{adj.}++furthest or highest in degree or order; utmost or extreme																										        													        													        													        													        				&quot;the ultimate achievement&quot;; &quot;the ultimate question&quot;; &quot;mans ultimate destiny&quot;; &quot;the ultimate insult&quot;; &quot;ones ultimate goal in life&quot;**{adj.}++最终的；[物]极限的；根本的**{n.}++终极；根本；基本原则**', '');
