INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('unanimous', '[juˈnænɪməs]', 'http://dict.youdao.com/dictvoice?audio=unanimous', '{adj.}++（投票、决定、协议等）全体同意的，无异议的；（所有人）一致同意的，意见一致的**{adj.}++in complete agreement																										        				&quot;a unanimous decision&quot;															   	同义词：								                                  				    consentaneous				    				    				      				    				      				    				                                      				    consentient**{adj.}++全体一致的；意见一致的；无异议的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('uncertain', '[ʌnˈsɜːrt(ə)n]', 'http://dict.youdao.com/dictvoice?audio=uncertain', '{adj.}++犹豫的，无把握的；无法确知的，不确定的；多变的，难预料的；信心不足的；（脚步）蹒跚的，踉跄的**{adj.}++lacking or indicating lack of confidence or assurance																										        													        													        													        				&quot;uncertain of his convictions&quot;; &quot;moving with uncertain (or unsure) steps&quot;; &quot;an uncertain smile&quot;; &quot;touched the ornaments with uncertain fingers&quot;															   	同义词：								                                  				    unsure				    				    				      				    				      				    				                                      				    incertain**{adj.}++无常的；含糊的；靠不住的；迟疑不决的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('underestimate', '[ˌʌndərˈestɪmeɪt]', 'http://dict.youdao.com/dictvoice?audio=underestimate', '{v.}++低估，对……估计不足；轻视，小看（某人）**{n.}++低估，对……估计不足**{n.}++an estimation that is too low; an estimate that is less than the true or actual value																					   	同义词：								                                  				    underestimation				    				    				      				    				      				    				                                      				    underrating				    				    				      				    				      				    				                                      				    underreckoning**{v.}++assign too low a value to																										        				&quot;Dont underestimate the value of this heirloom-you may sell it at a good price&quot;															   	同义词：								                                  				    undervalue**{vt.}++低估；看轻**{n.}++低估**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('underline', '[ˌʌndərˈlaɪn]', 'http://dict.youdao.com/dictvoice?audio=underline', '{v.}++在……下面画线；强调，突出**{n.}++（尤指为强调）下划线；（动物）下体轮廓**{n.}++a line drawn underneath (especially under written matter)																					   	同义词：								                                  				    underscore**{v.}++give extra weight to (a communication)																					   	同义词：								                                  				    underscore				    				    				      				    				      				    				                                      				    emphasize				    				    				      				    				      				    				                                      				    emphasise**{vt.}++强调；在…下面划线；预告**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('undertake', '[ˌʌndərˈteɪk]', 'http://dict.youdao.com/dictvoice?audio=undertake', '{v.}++承担，从事；承诺，答应；在内侧行驶时赶上并超越（另一辆车）**{v.}++enter upon an activity or enterprise																					   	同义词：								                                  				    set about				    				    				      				    				      				    				                                      				    attempt**{vt.}++承担，保证；从事；同意；试图**', '');
