INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('uneasy', '[ʌnˈiːzi]', 'http://dict.youdao.com/dictvoice?audio=uneasy', '{adj.}++担忧的，不安的；令人不舒服的，不安稳的；（情况）不稳定的；（书或音乐）难懂的，晦涩的；不和谐的，矛盾的**{adj.}++lacking a sense of security or affording no ease or reassurance																										        													        													        													        													        													        													        				&quot;farmers were uneasy until rain finally came&quot;; &quot;uneasy about his health&quot;; &quot;gave an uneasy laugh&quot;; &quot;uneasy lies the head that wears the crown&quot;; &quot;an uneasy coalition government&quot;; &quot;an uneasy calm&quot;; &quot;an uneasy silence fell on the group&quot;**{adj.}++不舒服的；心神不安的；不稳定的**', '');
