INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('value', '[ˈvæljuː]', 'http://dict.youdao.com/dictvoice?audio=value', '{n.}++价值；等值，等价，物有所值；重要性，有用性；重要特点，显著特点；价值观（values）；（数学中的）值；（音乐中的）时值（指音符的时间长度）；（词或其他语言单位）确切意义；（色彩）明暗度**{v.}++尊重，重视；给……估价，给……定价**{n.}++a numerical quantity measured or assigned or computed																										        				&quot;the value assigned was 16 milliseconds&quot;**{relative darkness or lightness of a color																										        				&quot;I establish the colors and principal values by organizing the painting into three values--dark, medium.}++..and light&quot;**{n.}++[数]值；[经]价值；价格；重要性；确切涵义**{vt.}++评价；重视；估价**', '');
