INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('web', '[web]', 'http://dict.youdao.com/dictvoice?audio=web', '{n.}++（蜘蛛）网；网状物，错综复杂的事物；网络；（鸟兽的）蹼；连接板，金属薄条（片）；（连续印刷用）一卷纸；（制造卷筒纸的造纸机上的）无端金属丝网；织物**{v.}++用网（或网状物）覆盖；使中圈套；形成网**{n.}++an intricate network suggesting something that was formed by weaving or interweaving																										        				&quot;the trees cast a delicate web of shadows over the lawn&quot;**{n.}++网；卷筒纸；蹼；织物；圈套**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('wedge', '[wedʒ]', 'http://dict.youdao.com/dictvoice?audio=wedge', '{n.}++楔子，三角木；楔形物，三角形物（尤指食物）；不和；（高尔夫）楔形铁头球棒；（高尔夫）楔形铁头球棒击出的球；有鞋跟的女鞋；坡跟鞋鞋跟；（人或动物组成的）楔形队形；钱，收入**{v.}++（将……）楔入，插入，挤入；把……楔住，把……楔牢；（制作陶瓷时）揉（陶土）**{n.}++any shape that is triangular in cross section																					   	同义词：								                                  				    wedge shape				    				    				      				    				      				    				                                      				    cuneus**{vt.}++楔入；挤进；楔住**{vi.}++楔入；挤进**{n.}++楔子；楔形物；导致分裂的东西**', '');
