INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('what', '[wʌt]', 'http://dict.youdao.com/dictvoice?audio=what', '{det.}++什么；（指数量的全部）所……的；多么的，何等的**{pron.}++什么；多么；无论什么；……的事物**{adj.}++什么，什么样的；多么（好或坏）的；全部的，所有的**{adv.}++到什么程度，在哪一方面；哦（用于暂停下来思考）；是吧**{int.}++（表示惊讶、气愤、怀疑、喜欢、厌恶等）什么，真的吗**{conj.}++（用于动词和形容词后引导关系从句）什么；（用于强调句型句首）所……的（是……）；……那样的（事物）；（指全部的量）所有的**', '');
