INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('white', '[waɪt]', 'http://dict.youdao.com/dictvoice?audio=white', '{adj.}++白色的；白种人的，白肤色的；苍白的；加牛奶（或奶油）的；（葡萄酒）白的，淡黄色的；（面粉）精白的；空白的；树皮淡色的；（玻璃）透明的，无色的；完全公正的，非常诚实的；（魔法）善意的；（血细胞）白的；（政治）反动的；纯洁的**{n.}++白色，白颜料；白种人，白人；白葡萄酒；眼白；蛋清，蛋白；白色运动服（whites）；要洗涤的白色织物（whites）；白衣服；执白棋者，白方；白色的东西，白球；白粉蝶**{v.}++把……漆成白色，使变白**{n.}++a member of the Caucasoid race																					   	同义词：								                                  				    white person				    				    				      				    				      				    				                                      				    Caucasian**{United States jurist appointed chief justice of the United States Supreme Court in 1910 by President Taft; noted for his work on antitrust legislation (1845-1921)																					   	同义词：								                                  				    Edward White				    				    				      				    				      				    				                                      				    Edward D.}++White				    				    				      				    				      				    				                                      				    Edward Douglas White Jr.**{United States political journalist (1915-1986)																					   	同义词：								                                  				    T.}++H. White				    				    				      				    				      				    				                                      				    Theodore Harold White**{United States writer noted for his humorous essays (1899-1985)																					   	同义词：								                                  				    E.}++B. White				    				    				      				    				      				    				                                      				    Elwyn Brooks White**{United States educator who in 1865 (with Ezra Cornell) founded Cornell University and served as its first president (1832-1918)																					   	同义词：								                                  				    Andrew D.}++White				    				    				      				    				      				    				                                      				    Andrew Dickson White**{adj.}++白色的；白种的；纯洁的**{n.}++白色；洁白；白种人**', '');
