INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('wind', '[wɪnd]', 'http://dict.youdao.com/dictvoice?audio=wind', '{n.}++风，气流；风向，逼近的形势；呼吸，呼吸能力；肠胃气胀；管乐器，吹奏乐器；大话，空谈；放屁；弯，弯曲处；一圈，一转；（给钟表）上发条；（由风带来，表明附近有动物、人存在的）气味**{v.}++弯曲前进，蜿蜒而行；卷缠，缠绕，绕成团；卷绕（磁带等）；给（钟、表）上发条；转动（把手）；（用辘轳、绞车等）吊起（某物）；使喘不过气来，使喘大气；给（婴儿）拍嗝儿； 嗅出（人，动物）的气味；吹（号角，哨子）**{adj.}++管乐的**{n.}++air moving (sometimes with considerable force) from an area of high pressure to an area of low pressure																										        													        				&quot;trees bent under the fierce winds&quot;; &quot;when there is no wind, row&quot;															   	同义词：								                                  				    air current				    				    				      				    				      				    				                                      				    current of air**{vt.}++缠绕；上发条；使弯曲；吹号角；绕住或缠住某人**{vi.}++缠绕；上发条；吹响号角**{n.}++[气象]风；呼吸；气味；卷绕**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('winding', '[ˈwaɪndɪŋ]', 'http://dict.youdao.com/dictvoice?audio=winding', '{n.}++卷绕物，卷绕材料；线圈，绕组；蜿蜒曲折的路径**{adj.}++曲折的，弯曲的，蜿蜒的**{v.}++蜿蜒而行；缠绕，卷绕；被弯曲（wind 的现在分词）**{n.}++the act of winding or twisting																					   	同义词：								                                  				    wind				    				    				      				    				      				    				                                      				    twist**{adj.}++marked by repeated turns and bends																										        				&quot;winding roads are full of surprises&quot;															   	同义词：								                                  				    tortuous				    				    				      				    				      				    				                                      				    twisting				    				    				      				    				      				    				                                      				    twisty				    				    				      				    				      				    				                                      				    voluminous**{of a path e.}++g.																										        				&quot;a winding country road&quot;															   	同义词：								                                  				    meandering(a)				    				    				      				    				      				    				                                      				    rambling				    				    				      				    				      				    				                                      				    wandering(a)**{n.}++绕，缠；线圈；弯曲**{adj.}++弯曲的，蜿蜒的；[纺]卷绕的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('windmill', '[ˈwɪndmɪl]', 'http://dict.youdao.com/dictvoice?audio=windmill', '{n.}++风车房，风力磨坊；玩具风车；（用于发电、汲水的）风车；（尤指旧时用于旋翼机上的）风力旋轮，空气旋轮**{v.}++使（手臂）作风车般转动；（飞机螺旋桨、旋翼或飞机自身）借风力旋转**{n.}++a mill that is powered by the wind**{n.}++[动力]风车；风车房；旋转玩具；直升飞机**{vt.}++使旋转**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('windy', '[ˈwɪndi]', 'http://dict.youdao.com/dictvoice?audio=windy', '{adj.}++多风的，风大的；夸夸其谈的，空话连篇的；胃内气胀的；（道路，河流）蜿蜒的，弯弯曲曲的；（人）紧张的，忧虑的**{adj.}++abounding in or exposed to the wind or breezes																										        				&quot;a windy bluff&quot;															   	同义词：								                                  				    blowy				    				    				      				    				      				    				                                      				    breezy**{adj.}++多风的，有风的；腹胀的；吹牛的**', '');
