INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('wrench', '[rentʃ]', 'http://dict.youdao.com/dictvoice?audio=wrench', '{v.}++猛拉，猛扭，挣脱；扭伤；夺走（某人），拆散；使痛苦，使十分难过（尤指以致哭喊出声）；用扳钳拧**{n.}++扳手，扳钳；（离别的）痛苦，难受；猛扭，猛拉；（机械）偶单力组；扭伤；歪曲**{n.}++a sharp strain on muscles or ligaments																										        				&quot;the wrench to his knee occurred as he fell&quot;															   	同义词：								                                  				    twist				    				    				      				    				      				    				                                      				    pull**{n.}++扳手，[机]扳钳；扭伤；痛苦；歪曲；猛扭**{vt.}++扭伤；猛扭；曲解；折磨**{vi.}++扭伤；猛扭；猛绞**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('wrestle', '[ˈres(ə)l]', 'http://dict.youdao.com/dictvoice?audio=wrestle', '{v.}++（与某人）摔跤，扭打；使劲搬动，用力操作；努力解决，艰难对付**{n.}++摔跤，角力；艰苦的斗争，搏斗**{n.}++the act of engaging in close hand-to-hand combat																										        				&quot;they had a fierce wrestle&quot;															   	同义词：								                                  				    wrestling				    				    				      				    				      				    				                                      				    grapple				    				    				      				    				      				    				                                      				    grappling				    				    				      				    				      				    				                                      				    hand-to-hand struggle**{v.}++combat to overcome an opposing tendency or force																										        				&quot;He wrestled all his life with his feeling of inferiority&quot;**{n.}++摔跤；搏斗；斗争**{vi.}++摔跤；斗争；斟酌**{vt.}++与摔跤；与…搏斗；使劲搬动**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('wretched', '[ˈretʃɪd]', 'http://dict.youdao.com/dictvoice?audio=wretched', '{adj.}++可怜的，悲惨的；（表示憎恶）讨厌的，该死的；感到不适的，不愉快的；极坏的，恶劣的**{adj.}++of very poor quality or condition																					   	同义词：								                                  				    deplorable				    				    				      				    				      				    				                                      				    execrable				    				    				      				    				      				    				                                      				    miserable				    				    				      				    				      				    				                                      				    woeful**{adj.}++可怜的；卑鄙的；令人苦恼或难受的**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('wring', '[rɪŋ]', 'http://dict.youdao.com/dictvoice?audio=wring', '{vt.}++拧；绞；紧握；使痛苦；折磨**{vi.}++蠕动；扭动；感到痛苦；感到苦恼**{n.}++拧；绞；挤；扭动**{n.}++a twisting squeeze																										        				&quot;gave the wet cloth a wring&quot;															   	同义词：								                                  				    squeeze**{v.}++twist and press out of shape																					   	同义词：								                                  				    contort				    				    				      				    				      				    				                                      				    deform				    				    				      				    				      				    				                                      				    distort**{vt.}++拧；绞；紧握；使痛苦；折磨**{vi.}++蠕动；扭动；感到痛苦；感到苦恼**{n.}++拧；绞；挤；扭动**', '');
INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('wrinkle', '[ˈrɪŋk(ə)l]', 'http://dict.youdao.com/dictvoice?audio=wrinkle', '{n.}++（皮肤上的）皱纹；（布或纸上的）皱褶； 小困难，小难题；令人吃惊的情节，出人意料的事情；妙计，好主意**{v.}++（使脸上）起皱纹，皱起；（布料等）起皱，起褶**{n.}++a slight depression in the smoothness of a surface																										        				&quot;ironing gets rid of most wrinkles&quot;															   	同义词：								                                  				    furrow				    				    				      				    				      				    				                                      				    crease				    				    				      				    				      				    				                                      				    crinkle				    				    				      				    				      				    				                                      				    seam				    				    				      				    				      				    				                                      				    line**{n.}++皱纹**{vi.}++起皱**{vt.}++使起皱纹**', '');
