INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('yoke', '[joʊk]', 'http://dict.youdao.com/dictvoice?audio=yoke', '{n.}++轭，牛轭；羁绊，枷锁；（女服的）上衣抵肩，裙腰；（挑东西用的）轭状扁担；轭门；同轭的一对动物；（飞机的）操纵杆；磁轭，轭铁；想不起名字的事物**{v.}++（强行）使结合，使联合；给……套上轭**{n.}++fabric comprising a fitted part at the top of a garment**{n.}++轭；束缚；牛轭**{vt.}++结合；给…上轭**{vi.}++结合；匹配**', '');
