INSERT IGNORE INTO CET6WordBook (word, phonetic, pron, poses, sentences) VALUES ('zinc', '[zɪŋk]', 'http://dict.youdao.com/dictvoice?audio=zinc', '{n.}++锌；（非洲某些地方用于搭建屋顶、棚子等的）波纹铁板，瓦楞铁板**{v.}++（为防锈而）镀锌于（铁）**{n.}++a bluish-white lustrous metallic element; brittle at ordinary temperatures but malleable when heated; used in a wide variety of alloys and in galvanizing iron; it occurs as zinc sulphide in zinc blende																					   	同义词：								                                  				    Zn				    				    				      				    				      				    				                                      				    atomic number 30**{v.}++coat or cover with zinc**', '');
